class dom_tag:
  def render(self, indent='  ', pretty=True, xhtml=False):
    """
    Render the DOM tag and return the rendered output as a string. It recursively renders the tag and its children.
    Input-Output Arguments
    :param self: dom_tag. An instance of the dom_tag class.
    :param indent: String. The string used for indentation. Defaults to two spaces.
    :param pretty: Bool. Whether to add line breaks and indentation for a prettier output. Defaults to True.
    :param xhtml: Bool. Whether to use XHTML syntax. Defaults to False.
    :return: String. The rendered output of the DOM tag.
    """
    def render_attrs(attrs):
      if not attrs:
        return ''
      parts = []
      for k, v in attrs.items():
        if v is None:
          parts.append(k)
        else:
          parts.append(f'{k}="{v}"')
      return ' ' + ' '.join(parts)

    def render_node(node, level=0):
      # Text node
      if isinstance(node, str):
        return (indent * level + node) if pretty else node

      # Assume DOM-like object with tag, attrs, children
      tag = getattr(node, 'tag', '')
      attrs = getattr(node, 'attrs', {}) or {}
      children = getattr(node, 'children', []) or []

      # Self-closing / void tag
      void_tags = {
        'area', 'base', 'br', 'col', 'embed', 'hr', 'img',
        'input', 'link', 'meta', 'param', 'source', 'track', 'wbr'
      }

      attr_str = render_attrs(attrs)

      if not children:
        if xhtml or tag not in void_tags:
          return f"{indent * level}<{tag}{attr_str}></{tag}>" if pretty else f"<{tag}{attr_str}></{tag}>"
        else:
          return f"{indent * level}<{tag}{attr_str} />" if pretty else f"<{tag}{attr_str} />"

      # Render children
      if pretty:
        rendered_children = []
        for child in children:
          rendered_children.append(render_node(child, level + 1))
        inner = "\n".join(rendered_children)
        return f"{indent * level}<{tag}{attr_str}>\n{inner}\n{indent * level}</{tag}>"
      else:
        inner = "".join(render_node(child, level + 1) if not isinstance(child, str) else child for child in children)
        return f"<{tag}{attr_str}>{inner}</{tag}>"

    return render_node(self)

