def _walk(item, parent=None):
    if item is None:
        return

    # If middleware is a tuple/list of middleware objects, recurse into it.
    if isinstance(item, (list, tuple)):
        for sub_item in item:
            _walk(sub_item, parent=parent)
        return

    cls = item.__class__
    middleware_classes.append(cls)

    node = {
        "middleware": item,
        "class": cls,
        "name": f"{cls.__module__}.{cls.__qualname__}",
        "parent": parent,
    }
    middleware_tree.append(node)

    # Some middleware wrappers may expose nested middleware via common attrs.
    for attr in ("middleware", "middlewares", "_middleware"):
        nested = getattr(item, attr, None)
        if nested is not None and nested is not item:
            _walk(nested, parent=node)

