class Request:
    def headers(self):
        # NOTE(kgriffs: First time here will cache the dict so all we
        # have to do is clone it in the future.

        """
        This function returns the headers of a Request instance. It first checks if the headers are already cached, and if not, it creates a new dictionary and populates it with the headers from the environment. The headers are then returned.
        Input-Output Arguments
        :param self: Request. An instance of the Request class.
        :return: Dictionary. The headers of the Request instance.
        """
        if not hasattr(self, '_headers'):
            headers = {}

            for key, value in self.env.items():
                if key.startswith('HTTP_'):
                    header_name = key[5:].replace('_', '-').title()
                    headers[header_name] = value
                elif key in ('CONTENT_TYPE', 'CONTENT_LENGTH'):
                    header_name = key.replace('_', '-').title()
                    headers[header_name] = value

            self._headers = headers

        return dict(self._headers)

class Request:
    def get_cookie_values(self, name):
        """
        This function returns all values provided in the Cookie header for the named cookie. It first checks if the cookies are None, and if so, it parses the Cookie header and stores the result. Then, it retrieves the value for the specified cookie name and returns it.
        Input-Output Arguments
        :param self: Request. An instance of the Request class.
        :param name: str. The name of the cookie to retrieve the values for.
        :return: list. An ordered list of all values specified in the Cookie header for the named cookie, or None if the cookie was not included in the request. If the cookie is specified more than once in the header, the returned list of values will preserve the ordering of the individual `cookie-pair`'s in the header.
        """
        # Parse cookies lazily if needed
        if getattr(self, "cookies", None) is None:
            self.cookies = {}

            cookie_header = None
            if hasattr(self, "headers") and self.headers is not None:
                if isinstance(self.headers, dict):
                    cookie_header = self.headers.get("Cookie") or self.headers.get("cookie")
                else:
                    # Fallback for header-like objects
                    try:
                        cookie_header = self.headers.get("Cookie") or self.headers.get("cookie")
                    except Exception:
                        cookie_header = None

            if cookie_header:
                for part in cookie_header.split(";"):
                    part = part.strip()
                    if not part or "=" not in part:
                        continue
                    cookie_name, cookie_value = part.split("=", 1)
                    cookie_name = cookie_name.strip()
                    cookie_value = cookie_value.strip()
                    self.cookies.setdefault(cookie_name, []).append(cookie_value)

        values = self.cookies.get(name) if getattr(self, "cookies", None) is not None else None
        return values if values else None

class Request:
    def client_prefers(self, media_types):
        """
        This function returns the client's preferred media type from a list of choices. It uses the Accept header of the client's request to determine the preferred type.
        Input-Output Arguments
        :param self: Request. An instance of the Request class.
        :param media_types: Iterable of strings. One or more Internet media types from which to choose the client's preferred type.
        :return: String. The client's preferred media type based on the Accept header. Returns None if the client does not accept any of the given types.
        """
        accept = getattr(self, "headers", {}).get("Accept", "*/*")
        if not media_types:
            return None

        def parse_media_type(mt):
            mt = mt.strip()
            if "/" not in mt:
                return mt, "*"
            return mt.split("/", 1)

        def matches(accepted, offered):
            a_type, a_sub = parse_media_type(accepted)
            o_type, o_sub = parse_media_type(offered)
            return (a_type == "*" or a_type == o_type) and (a_sub == "*" or a_sub == o_sub)

        # Parse Accept header into (media_range, q, order)
        accepted_ranges = []
        for i, part in enumerate(accept.split(",")):
            part = part.strip()
            if not part:
                continue
            pieces = [p.strip() for p in part.split(";")]
            media_range = pieces[0]
            q = 1.0
            for p in pieces[1:]:
                if p.startswith("q="):
                    try:
                        q = float(p[2:])
                    except ValueError:
                        q = 0.0
            accepted_ranges.append((media_range, q, i))

        if not accepted_ranges:
            accepted_ranges = [("*/*", 1.0, 0)]

        best_choice = None
        best_score = None

        for offered_index, offered in enumerate(media_types):
            best_for_offered = None
            best_for_offered_score = None

            for accepted, q, acc_index in accepted_ranges:
                if matches(accepted, offered):
                    # Prefer higher q, then more specific accepted range, then earlier accept entry
                    a_type, a_sub = parse_media_type(accepted)
                    specificity = (a_type != "*") + (a_sub != "*")
                    score = (q, specificity, -acc_index)
                    if best_for_offered_score is None or score > best_for_offered_score:
                        best_for_offered_score = score
                        best_for_offered = offered

            if best_for_offered is not None:
                # Prefer higher q, then more specific, then earlier offered type
                score = (*best_for_offered_score, -offered_index)
                if best_score is None or score > best_score:
                    best_score = score
                    best_choice = best_for_offered

        return best_choice

class Response:
    def set_header(self, name, value):
        """
        This function sets a header for the response with a given value. It overwrites any existing values for the header. It also performs some validations and conversions on the input values.
        Input-Output Arguments
        :param self: Response. An instance of the Response class.
        :param name: String. The name of the header to be set. It should contain only US-ASCII characters.
        :param value: String. The value to be set for the header. It should contain only US-ASCII characters.
        :return: No return values.
        """
        # Initialize headers storage if it doesn't exist
        if not hasattr(self, "headers") or self.headers is None:
            self.headers = {}

        # Validate header name and value types
        if not isinstance(name, str):
            raise TypeError("Header name must be a string")
        if not isinstance(value, str):
            raise TypeError("Header value must be a string")

        # Ensure US-ASCII only
        try:
            name.encode("ascii")
        except UnicodeEncodeError:
            raise ValueError("Header name must contain only US-ASCII characters")

        try:
            value.encode("ascii")
        except UnicodeEncodeError:
            raise ValueError("Header value must contain only US-ASCII characters")

        # Normalize header name to a standard form
        header_name = name.strip()

        # Set/overwrite the header
        self.headers[header_name] = value

class Response:
    def get_header(self, name, default=None):
        """
        This function retrieves the raw string value for a given header in the Response instance. It checks if the header has multiple values and returns them as a single, comma-delimited string. However, if the header is "Set-Cookie", it raises an error because it does not support this format.
        Input-Output Arguments
        :param self: Response. An instance of the Response class.
        :param name: String. The name of the header to retrieve, case-insensitive.
        :param default: Any. The value to return if the header is not found. Defaults to None.
        :return: String. The value of the specified header if set, or the default value if not set.
        """
        if not hasattr(self, "headers") or self.headers is None:
            return default

        # Normalize header name for case-insensitive lookup
        target = name.lower()

        # Support common header storage formats:
        # 1) dict-like: {"Content-Type": "text/html"}
        # 2) list of tuples: [("Content-Type", "text/html"), ...]
        # 3) multi-value dict-like: {"X-Test": ["a", "b"]}
        headers = self.headers

        # Dict-like lookup
        if hasattr(headers, "items"):
            for key, value in headers.items():
                if str(key).lower() == target:
                    if target == "set-cookie":
                        raise ValueError("get_header does not support 'Set-Cookie' headers")
                    if isinstance(value, (list, tuple)):
                        return ", ".join(str(v) for v in value)
                    return value
            return default

        # Sequence of pairs
        try:
            values = []
            for key, value in headers:
                if str(key).lower() == target:
                    if target == "set-cookie":
                        raise ValueError("get_header does not support 'Set-Cookie' headers")
                    values.append(str(value))

            if not values:
                return default
            return ", ".join(values)
        except TypeError:
            return default

from urllib.parse import unquote, unquote_plus as _unquote_plus

def decode(encoded_uri, unquote_plus=True):
    """
    This function decodes percent-encoded characters in a URI or query string. It replaces the encoded characters with their corresponding decoded values.
    Input-Output Arguments
    :param encoded_uri: String. The encoded URI or query string to be decoded.
    :param unquote_plus: Bool. Set to False to retain any plus ('+') characters in the given string, rather than converting them to spaces (default True). Typically you should set this to False when decoding any part of a URI other than the query string.
    :return: String. The decoded URL. If the URL contains escaped non-ASCII characters, UTF-8 is assumed per RFC 3986.
    """
    if encoded_uri is None:
        return None

    if unquote_plus:
        return _unquote_plus(encoded_uri)
    return unquote(encoded_uri)

class BufferedReader:
    async def peek(self, size=-1):
        """
        This function peeks into the buffered data and returns the specified number of bytes. It first checks if the specified size is valid, and then trims the buffer if necessary. If the buffer does not have enough data, it reads from the source asynchronously and adds the chunks to the buffer until the desired size is reached. Finally, it returns the requested number of bytes from the buffer.
        Input-Output Arguments
        :param self: BufferedReader. An instance of the BufferedReader class.
        :param size: Integer. The number of bytes to peek into the buffer. Defaults to -1, which means peeking the entire buffer.
        :return: Bytes. The peeked bytes from the buffer.
        """
        if size is None:
            size = -1

        if size < -1:
            raise ValueError("size must be >= -1")

        # If size is -1, return everything currently buffered.
        if size == -1:
            return bytes(self._buffer)

        # Ensure the buffer has at least `size` bytes, if possible.
        while len(self._buffer) < size and not self._eof:
            chunk = await self._source.read(size - len(self._buffer))
            if not chunk:
                self._eof = True
                break
            self._buffer.extend(chunk)

        return bytes(self._buffer[:size])

class ETag:
    @classmethod
    def loads(cls, etag_str):
        """
        This function deserializes a single entity-tag string from a precondition header. It parses the input string according to the rules defined in RFC 7232 and returns an instance of the ETag class representing the parsed entity-tag.
        Input-Output Arguments
        :param cls: Class. The class to create an instance of.
        :param etag_str: String. An ASCII string representing a single entity-tag.
        :return: ETag. An instance of the ETag class representing the parsed entity-tag.
        """
        if etag_str is None:
            raise ValueError("etag_str must not be None")

        s = etag_str.strip()

        if not s:
            raise ValueError("etag_str must not be empty")

        weak = False

        # Parse optional weak indicator
        if s.startswith("W/"):
            weak = True
            s = s[2:].lstrip()

        # Must be a quoted-string
        if len(s) < 2 or s[0] != '"' or s[-1] != '"':
            raise ValueError("Invalid entity-tag format")

        tag = s[1:-1]

        # Validate quoted-string content per RFC 7232 / RFC 7230
        i = 0
        while i < len(tag):
            ch = tag[i]
            if ch == "\\":
                # quoted-pair: backslash must escape a following character
                i += 1
                if i >= len(tag):
                    raise ValueError("Invalid escape sequence in entity-tag")
            else:
                # qdtext excludes DQUOTE and backslash; allow visible ASCII and obs-text
                if ch == '"' or ord(ch) < 0x20:
                    raise ValueError("Invalid character in entity-tag")
            i += 1

        # Create instance; supports common constructor patterns
        try:
            return cls(tag, weak)
        except TypeError:
            obj = cls()
            obj.tag = tag
            obj.weak = weak
            return obj

class BufferedReader:
    async def read_until(self, delimiter, size=-1, consume_delimiter=False):
        """
        Read data from the BufferedReader instance until a specified delimiter is encountered.
        """
        if delimiter is None or delimiter == b"":
            raise ValueError("delimiter must be a non-empty bytes-like object")

        # Normalize delimiter to bytes if possible
        if isinstance(delimiter, str):
            delimiter = delimiter.encode()

        buffer = bytearray()

        async for chunk in self:
            if isinstance(chunk, str):
                chunk = chunk.encode()

            buffer.extend(chunk)

            # If size is set, stop once we've read enough
            if size != -1 and len(buffer) >= size:
                if consume_delimiter:
                    return bytes(buffer[:size])
                return bytes(buffer[:size])

            idx = buffer.find(delimiter)
            if idx != -1:
                end = idx + (len(delimiter) if consume_delimiter else 0)
                return bytes(buffer[:end])

        # Delimiter not found; return whatever was read (respecting size if needed)
        if size != -1:
            return bytes(buffer[:size])
        return bytes(buffer)

