        Input-Output Arguments
        :param cls: TwitterModel. The class itself.
        :param data: Dictionary. A JSON dictionary, as converted from the JSON in the Twitter API.
        :param **kwargs: Additional keyword arguments that should be supplied by the calling class.
        :return: TwitterModel. The newly created instance of the TwitterModel class.
        """
        if data is None:
            data = {}
        if not isinstance(data, dict):
            raise TypeError("data must be a dictionary")

        # Merge JSON data with any extra keyword arguments
        init_kwargs = dict(data)
        init_kwargs.update(kwargs)

        return cls(**init_kwargs)

class TwitterModel:
    def AsDict(self):
        """
        This function creates a dictionary representation of a TwitterModel instance.
        It iterates through all attributes of the object and constructs a dictionary
        based on the values of those attributes. If an attribute is a list, tuple,
        or set, it checks if the elements support the dict format. If they do, it
        creates a list of dictionaries for each element. If an attribute is a
        subclass of TwitterModel, it directly assigns the dictionary representation
        of that attribute. If an attribute does not support the dict format, it
        assigns the value directly to the dictionary.

        :return: dict. A dictionary representation of the TwitterModel object.
        """
        result = {}

        for key, value in self.__dict__.items():
            if isinstance(value, TwitterModel):
                result[key] = value.AsDict()
            elif isinstance(value, (list, tuple, set)):
                items = []
                for item in value:
                    if isinstance(item, TwitterModel):
                        items.append(item.AsDict())
                    else:
                        items.append(item)
                result[key] = items
            else:
                result[key] = value

        return result

class Api:
    def _TweetTextWrap(self,
                       status,
                       char_lim=CHARACTER_LIMIT):
        """
        This function takes a status message and wraps it into multiple tweets based on the character limit. It splits the status into words and checks if each word exceeds the character limit. If a word exceeds the limit, it raises an exception. It then calculates the length of the line by adding the length of each word and checks if it exceeds the character limit. If it does, it appends the line to the list of tweets and starts a new line with the current word. If it doesn't exceed the limit, it adds the word to the line. Finally, it appends the last line to the list of tweets and returns it.
        Input-Output Arguments
        :param self: Api. An instance of the Api class.
        :param status: String. The status message to be wrapped into tweets.
        :param char_lim: Integer. The character limit for each tweet. Defaults to CHARACTER_LIMIT.
        :return: List of strings. The wrapped status message split into multiple tweets.
        """
        if status is None:
            return []

        words = status.split()
        if not words:
            return []

        tweets = []
        current_line = ""

        for word in words:
            if len(word) > char_lim:
                raise ValueError(
                    f"Word '{word}' exceeds the character limit of {char_lim}."
                )

            if not current_line:
                current_line = word
            elif len(current_line) + 1 + len(word) <= char_lim:
                current_line += " " + word
            else:
                tweets.append(current_line)
                current_line = word

        if current_line:
            tweets.append(current_line)

        return tweets

import importlib
import typing


def import_from_string(import_str: str) -> typing.Any:
    """
    This function imports a module and retrieves an attribute from it based on the given import string.
    The import string should be in the format "<module>:<attribute>". It raises an exception if the
    module or attribute is not found.

    :param import_str: String. The import string in the format "<module>:<attribute>".
    :return: Any. The retrieved attribute from the imported module.
    """
    if ":" not in import_str:
        raise ValueError(
            f"Invalid import string '{import_str}'. Expected format '<module>:<attribute>'."
        )

    module_name, attr_name = import_str.split(":", 1)

    if not module_name or not attr_name:
        raise ValueError(
            f"Invalid import string '{import_str}'. Expected format '<module>:<attribute>'."
        )

    module = importlib.import_module(module_name)

    try:
        return getattr(module, attr_name)
    except AttributeError as exc:
        raise ImportError(
            f"Module '{module_name}' does not have attribute '{attr_name}'."
        ) from exc

