class _MediaType:
    def match(self, other):
        """
        This function checks if a given MediaType object satisfies another MediaType object.
        It compares the parameters, subtypes, and main types of the two objects and returns
        True if they match.

        :param self: _MediaType. An instance of the _MediaType class.
        :param other: _MediaType. The MediaType object to compare with.
        :return: bool. True if the self MediaType satisfies the other MediaType, False otherwise.
        """
        if other is None:
            return False

        # Compare main type
        if getattr(self, "type", None) != getattr(other, "type", None):
            return False

        # Compare subtype, allowing wildcards
        self_subtype = getattr(self, "subtype", None)
        other_subtype = getattr(other, "subtype", None)
        if self_subtype != "*" and other_subtype != "*" and self_subtype != other_subtype:
            return False

        # Compare parameters: all parameters in other must be present in self
        self_params = getattr(self, "params", {}) or {}
        other_params = getattr(other, "params", {}) or {}

        for key, value in other_params.items():
            if key not in self_params or self_params[key] != value:
                return False

        return True

