class Job:
    def download_to_fileobj(self, output_file, chunk_size=DefaultPartSize,
                            verify_hashes=True,
                            retry_exceptions=(socket.error,)):

        """
        This function downloads an archive and saves its contents to a file object. It divides the download into chunks and verifies the tree hashes for each downloaded chunk.
        Input-Output Arguments
        :param self: Job. An instance of the Job class.
        :param output_file: file. The file object where the archive contents will be saved.
        :param chunk_size: int. The chunk size to use when downloading the archive.
        :param verify_hashes: bool. Indicates whether or not to verify the tree hashes for each downloaded chunk. It defaults to True.
        :param retry_exceptions: tuple. A tuple of exceptions that should be retried if they occur during the download. It defaults to (socket.error,).
        :return: No return values.
        """
        import hashlib
        import time

        # Ensure we have a valid chunk size
        if chunk_size is None or chunk_size <= 0:
            chunk_size = DefaultPartSize

        # Determine total size if available
        total_size = None
        if hasattr(self, "archive_size"):
            total_size = self.archive_size
        elif hasattr(self, "size"):
            total_size = self.size

        # Helper to compute tree hash for a chunk
        def _tree_hash(data):
            return hashlib.sha256(data).hexdigest()

        offset = 0
        while True:
            # Stop if we know the total size and have downloaded everything
            if total_size is not None and offset >= total_size:
                break

            # Determine current chunk length
            current_chunk_size = chunk_size
            if total_size is not None:
                current_chunk_size = min(chunk_size, total_size - offset)

            # Retry loop for transient errors
            last_exc = None
            for attempt in range(3):
                try:
                    # Prefer a ranged download method if available
                    if hasattr(self, "get_range"):
                        chunk = self.get_range(offset, current_chunk_size)
                    elif hasattr(self, "download_range"):
                        chunk = self.download_range(offset, current_chunk_size)
                    elif hasattr(self, "read"):
                        # Fallback: read sequentially from a stream-like object
                        chunk = self.read(current_chunk_size)
                    else:
                        raise AttributeError(
                            "Job object does not provide a supported download method"
                        )

                    if not chunk:
                        # No more data available
                        return

                    # Verify hash if requested and hash metadata is available
                    if verify_hashes and hasattr(self, "get_chunk_hash"):
                        expected_hash = self.get_chunk_hash(offset, len(chunk))
                        actual_hash = _tree_hash(chunk)
                        if expected_hash != actual_hash:
                            raise ValueError(
                                "Hash verification failed for chunk at offset {}".format(offset)
                            )

                    # Write chunk to output file
                    output_file.write(chunk)
                    offset += len(chunk)
                    break

                except retry_exceptions as exc:
                    last_exc = exc
                    if attempt == 2:
                        raise
                    time.sleep(0.5 * (attempt + 1))
            else:
                if last_exc is not None:
                    raise last_exc

class Address:
    def release(self, dry_run=False):
        """
        Free up this Elastic IP address. If the address has an allocation ID, it releases the address using the allocation ID. Otherwise, it releases the address using the public IP.
        Input-Output Arguments
        :param self: Address. An instance of the Address class.
        :param dry_run: Bool. Whether to perform a dry run (no changes are made). Defaults to False.
        :return: The result of the release operation.
        """
        # Determine whether to release by allocation ID or public IP
        params = {"DryRun": dry_run}

        allocation_id = getattr(self, "allocation_id", None)
        public_ip = getattr(self, "public_ip", None)

        if allocation_id:
            params["AllocationId"] = allocation_id
        elif public_ip:
            params["PublicIp"] = public_ip
        else:
            raise ValueError("Cannot release address: missing allocation_id and public_ip.")

        # Use the underlying EC2 client/resource if available
        if hasattr(self, "connection") and self.connection is not None:
            return self.connection.release_address(**params)
        if hasattr(self, "ec2") and self.ec2 is not None:
            return self.ec2.release_address(**params)
        if hasattr(self, "client") and self.client is not None:
            return self.client.release_address(**params)

        raise AttributeError("No EC2 connection/client available to release the address.")

class Address:
    def disassociate(self, dry_run=False):
        """
        Disassociate this Elastic IP address from a currently running instance. If the address has an allocation ID, it disassociates the address using the allocation ID. Otherwise, it disassociates the address using the public IP.
        Input-Output Arguments
        :param self: Address. An instance of the Address class.
        :param dry_run: Bool. Whether to perform a dry run of the disassociation. Defaults to False.
        :return: The result of the disassociation operation.
        """
        params = {'DryRun': dry_run}

        allocation_id = getattr(self, 'allocation_id', None)
        public_ip = getattr(self, 'public_ip', None)

        if allocation_id:
            params['AssociationId'] = allocation_id
        elif public_ip:
            params['PublicIp'] = public_ip
        else:
            raise ValueError("Address must have either an allocation_id or public_ip to disassociate.")

        # Assumes the instance has a boto3 EC2 resource/client available as `self.ec2`
        return self.ec2.meta.client.disassociate_address(**params)

class NetworkInterface:
    def detach(self, force=False, dry_run=False):
        """
        This function detaches a network interface (ENI) from an EC2 instance.
        Input-Output Arguments
        :param self: NetworkInterface. An instance of the NetworkInterface class.
        :param force: Bool. Specifies whether to force detachment if the previous detachment attempt did not occur cleanly.
        :param dry_run: Bool. Specifies whether this is a dry run, meaning no actual detachment will occur.
        :return: Bool. Returns True if the detachment is successful.
        """
        try:
            # If the interface is already detached, nothing to do.
            if getattr(self, "attachment", None) is None:
                return True

            # Dry run: validate that detachment would be possible, but do not perform it.
            if dry_run:
                return True

            # Prefer boto3-style EC2 resource/client if available.
            attachment = self.attachment
            attachment_id = getattr(attachment, "attachment_id", None) or getattr(attachment, "id", None)

            # If we have an EC2 resource object with detach() on the attachment, use it.
            if hasattr(attachment, "detach"):
                if force:
                    attachment.detach(Force=True, DryRun=False)
                else:
                    attachment.detach(DryRun=False)
            else:
                # Fall back to a client-based detach if the object exposes a client.
                client = getattr(self, "client", None) or getattr(self, "ec2_client", None)
                if client is None:
                    raise AttributeError("No detach method or EC2 client available for this network interface.")

                kwargs = {
                    "NetworkInterfaceId": getattr(self, "network_interface_id", None)
                    or getattr(self, "id", None)
                    or getattr(self, "eni_id", None),
                    "DryRun": False,
                }
                if force:
                    kwargs["Force"] = True

                # If attachment id is known, include it when supported.
                if attachment_id is not None:
                    kwargs["AttachmentId"] = attachment_id

                client.detach_network_interface(**kwargs)

            # Mark as detached locally if possible.
            try:
                self.attachment = None
            except Exception:
                pass

            return True

        except Exception:
            return False

class Address:
    def associate(self, instance_id=None, network_interface_id=None, private_ip_address=None, allow_reassociation=False, dry_run=False):
        """
        Associate this Elastic IP address with a currently running instance. If the address has an allocation ID, it uses the allocation ID. Otherwise, it does not use the allocation ID.
        Input-Output Arguments
        :param self: Address. An instance of the Address class.
        :param instance_id: String. The ID of the instance to associate the Elastic IP address with.
        :param network_interface_id: String. The ID of the network interface to associate the Elastic IP address with.
        :param private_ip_address: String. The private IP address to associate with the Elastic IP address.
        :param allow_reassociation: Bool. Whether to allow reassociation of the Elastic IP address.
        :param dry_run: Bool. Whether to perform a dry run of the association.
        :return: The result of the association operation.
        """
        params = {
            "AllowReassociation": allow_reassociation,
            "DryRun": dry_run,
        }

        if instance_id is not None:
            params["InstanceId"] = instance_id
        if network_interface_id is not None:
            params["NetworkInterfaceId"] = network_interface_id
        if private_ip_address is not None:
            params["PrivateIpAddress"] = private_ip_address

        # Prefer allocation ID when available, otherwise use public IP association.
        if hasattr(self, "allocation_id") and self.allocation_id:
            params["AllocationId"] = self.allocation_id
        elif hasattr(self, "public_ip") and self.public_ip:
            params["PublicIp"] = self.public_ip
        else:
            raise ValueError("Address must have either an allocation_id or public_ip to associate.")

        # Call the underlying EC2 client/resource API.
        if hasattr(self, "connection") and self.connection:
            return self.connection.associate_address(**params)
        elif hasattr(self, "ec2") and self.ec2:
            return self.ec2.associate_address(**params)
        else:
            raise AttributeError("No EC2 connection/client available for association.")

