class Dynamizer:
    def encode(self, attr):
        """
        This function encodes a Python type to the format expected by DynamoDB. It determines the DynamoDB type of the input attribute and uses the corresponding encoder method to encode the attribute.
        Input-Output Arguments
        :param self: Dynamizer. An instance of the Dynamizer class.
        :param attr: The attribute to be encoded.
        :return: Dictionary. The encoded attribute in the format expected by DynamoDB.
        """
        # None -> NULL
        if attr is None:
            return {"NULL": True}

        # bool must be checked before int, since bool is a subclass of int
        if isinstance(attr, bool):
            return {"BOOL": attr}

        # Strings
        if isinstance(attr, str):
            return {"S": attr}

        # Numbers
        if isinstance(attr, (int, float)):
            return {"N": str(attr)}

        # Binary
        if isinstance(attr, (bytes, bytearray)):
            return {"B": bytes(attr)}

        # Sets
        if isinstance(attr, set):
            if not attr:
                return {"SS": []}

            first = next(iter(attr))
            if isinstance(first, str):
                return {"SS": list(attr)}
            elif isinstance(first, (int, float)):
                return {"NS": [str(x) for x in attr]}
            elif isinstance(first, (bytes, bytearray)):
                return {"BS": [bytes(x) for x in attr]}
            else:
                raise TypeError(f"Unsupported set element type: {type(first)}")

        # Lists / tuples -> DynamoDB list
        if isinstance(attr, (list, tuple)):
            return {"L": [self.encode(item) for item in attr]}

        # Dictionaries -> DynamoDB map
        if isinstance(attr, dict):
            return {"M": {str(k): self.encode(v) for k, v in attr.items()}}

        raise TypeError(f"Unsupported type for DynamoDB encoding: {type(attr)}")

class Dynamizer:
    def decode(self, attr):
        """
        This function decodes the format returned by DynamoDB and constructs the appropriate Python type. It checks the length of the attribute and if it is a string, it returns the attribute as is. Otherwise, it determines the DynamoDB type and calls the corresponding decoder method to convert the attribute to the appropriate Python type.
        Input-Output Arguments
        :param self: Dynamizer. An instance of the Dynamizer class.
        :param attr: The attribute to decode, in the format returned by DynamoDB.
        :return: The decoded attribute in the appropriate Python type.
        """
        if attr is None:
            return None

        # If it's already a plain string, return it unchanged
        if isinstance(attr, str):
            return attr

        # DynamoDB attribute values are typically dicts like {"S": "..."} or {"N": "..."}
        if not isinstance(attr, dict) or len(attr) != 1:
            return attr

        dtype, value = next(iter(attr.items()))

        if dtype == "S":
            return value
        elif dtype == "N":
            # Convert numeric strings to int when possible, otherwise float
            try:
                if "." in value or "e" in value.lower():
                    return float(value)
                return int(value)
            except (ValueError, TypeError):
                return value
        elif dtype == "BOOL":
            return bool(value)
        elif dtype == "NULL":
            return None
        elif dtype == "SS":
            return set(value)
        elif dtype == "NS":
            return {self.decode({"N": v}) for v in value}
        elif dtype == "L":
            return [self.decode(v) for v in value]
        elif dtype == "M":
            return {k: self.decode(v) for k, v in value.items()}
        elif dtype == "B":
            return value
        elif dtype == "BS":
            return set(value)
        else:
            # Unknown/unsupported type: return as-is
            return attr

