class VPCConnection:
    def get_all_vpc_peering_connections(self, vpc_peering_connection_ids=None, 
                                        filters=None, dry_run=False):

        """
        This function retrieves information about VPC peering connections. It allows you to filter the results based on specific search parameters. If no filters are specified, it returns information about all VPC peering connections associated with your account.
        Input-Output Arguments
        :param self: VPCConnection. An instance of the VPCConnection class.
        :param vpc_peering_connection_ids: List of strings. A list of VPC peering connection IDs to retrieve information for.
        :param filters: List of tuples. A list of filters to apply to the results. Each filter consists of a key and a value.
        :param dry_run: Bool. Set to True if the operation should not actually run.
        :return: List of VPC. A list of VPC peering connections that match the search parameters.
        """
        try:
            params = {}

            if vpc_peering_connection_ids:
                params["VpcPeeringConnectionIds"] = vpc_peering_connection_ids

            if filters:
                # Convert list of tuples into AWS-compatible filter format
                params["Filters"] = [
                    {"Name": key, "Values": value if isinstance(value, list) else [value]}
                    for key, value in filters
                ]

            if dry_run:
                params["DryRun"] = True

            response = self.ec2_client.describe_vpc_peering_connections(**params)
            return response.get("VpcPeeringConnections", [])

        except Exception as e:
            raise Exception(f"Error retrieving VPC peering connections: {e}")

class Table:
    def delete(self):
        """
        This function deletes a table in DynamoDB. It uses the connection object to delete the table with the specified table name.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :return: Bool. Returns True on success.
        """
        try:
            self.connection.delete_table(TableName=self.name)
            return True
        except Exception:
            return False

class Table:
    def update_global_secondary_index(self, global_indexes):
        """
        This function updates the global index(es) in DynamoDB after the table has been created. It takes a dictionary of global indexes as input and updates the read and write capacity units for each index. It then updates the table with the new global index information.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param global_indexes: Dictionary. A dictionary specifying the global indexes to be updated. Each key in the dictionary represents the index name, and the corresponding value is another dictionary containing the read and write capacity units for the index.
        :return: Bool. Returns True if the global indexes are successfully updated, False otherwise.
        """
        try:
            # Validate input
            if not isinstance(global_indexes, dict):
                return False

            # Build the list of global secondary index updates
            gsi_updates = []
            for index_name, capacity in global_indexes.items():
                if not isinstance(capacity, dict):
                    return False

                read_units = capacity.get("ReadCapacityUnits")
                write_units = capacity.get("WriteCapacityUnits")

                if read_units is None or write_units is None:
                    return False

                gsi_updates.append({
                    "Update": {
                        "IndexName": index_name,
                        "ProvisionedThroughput": {
                            "ReadCapacityUnits": int(read_units),
                            "WriteCapacityUnits": int(write_units)
                        }
                    }
                })

            # Update the table with the new global secondary index settings
            if not hasattr(self, "table") or self.table is None:
                return False

            self.table.update(
                AttributeDefinitions=getattr(self, "attribute_definitions", []),
                GlobalSecondaryIndexUpdates=gsi_updates
            )

            return True

        except Exception:
            return False

class Table:
    def update(self, throughput=None, global_indexes=None):
        """
        This function updates the attributes and global indexes of a table in DynamoDB. It accepts optional parameters for throughput and global indexes. If provided, the throughput parameter should be a dictionary with 'read' and 'write' keys, each associated with an integer value. The global_indexes parameter should also be a dictionary, where each key is the index name and the value is a dictionary with 'read' and 'write' keys, each associated with an integer value. The function returns True on success.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param throughput: Dictionary. Optional. Specifies the read and write capacity units for the table. Defaults to None.
        :param global_indexes: Dictionary. Optional. Specifies the read and write capacity units for the global indexes of the table. Defaults to None.
        :return: bool. True if the update is successful, False otherwise.
        """
        try:
            update_kwargs = {}

            # Update table throughput if provided
            if throughput is not None:
                if not isinstance(throughput, dict):
                    raise ValueError("throughput must be a dictionary with 'read' and 'write' keys")
                if "read" not in throughput or "write" not in throughput:
                    raise ValueError("throughput must contain 'read' and 'write' keys")

                update_kwargs["ProvisionedThroughput"] = {
                    "ReadCapacityUnits": int(throughput["read"]),
                    "WriteCapacityUnits": int(throughput["write"]),
                }

            # Update global secondary indexes if provided
            if global_indexes is not None:
                if not isinstance(global_indexes, dict):
                    raise ValueError("global_indexes must be a dictionary")

                gsi_updates = []
                for index_name, capacity in global_indexes.items():
                    if not isinstance(capacity, dict):
                        raise ValueError(
                            f"Capacity for index '{index_name}' must be a dictionary with 'read' and 'write' keys"
                        )
                    if "read" not in capacity or "write" not in capacity:
                        raise ValueError(
                            f"Capacity for index '{index_name}' must contain 'read' and 'write' keys"
                        )

                    gsi_updates.append({
                        "Update": {
                            "IndexName": index_name,
                            "ProvisionedThroughput": {
                                "ReadCapacityUnits": int(capacity["read"]),
                                "WriteCapacityUnits": int(capacity["write"]),
                            },
                        }
                    })

                if gsi_updates:
                    update_kwargs["GlobalSecondaryIndexUpdates"] = gsi_updates

            # If there is nothing to update, consider it a success
            if not update_kwargs:
                return True

            # Perform the update using boto3 Table resource if available
            if hasattr(self, "meta") and hasattr(self.meta, "client"):
                # If this is a boto3 Table resource, use update_table via client
                table_name = getattr(self, "name", None)
                if table_name is None:
                    raise AttributeError("Table name is not available")

                params = {"TableName": table_name, **update_kwargs}
                self.meta.client.update_table(**params)
                return True

            # Fallback: if the object has an update_table method, use it
            if hasattr(self, "update_table") and callable(getattr(self, "update_table")):
                self.update_table(**update_kwargs)
                return True

            raise AttributeError("No supported update mechanism found for Table object")

        except Exception:
            return False

class Table:
    def create_global_secondary_index(self, global_index):
        """
        This function creates a global secondary index in DynamoDB after the table has been created. It takes a `global_index` parameter, which should be a subclass of `GlobalBaseIndexField` representing the desired index. It updates the `global_indexes` information on the `Table` by calling `Table.describe`. It returns `True` on success.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param global_index: GlobalBaseIndexField subclass. The desired global index to be created.
        :return: Bool. Returns `True` if the global index is created successfully, otherwise `False`.
        """
        try:
            # Validate input
            if global_index is None:
                return False

            # Build the GSI definition from the provided index object
            index_name = getattr(global_index, "index_name", None)
            partition_key = getattr(global_index, "partition_key", None)
            sort_key = getattr(global_index, "sort_key", None)
            projection_type = getattr(global_index, "projection_type", "ALL")
            read_capacity = getattr(global_index, "read_capacity", None)
            write_capacity = getattr(global_index, "write_capacity", None)

            if not index_name or not partition_key:
                return False

            # Ensure table metadata is up to date
            try:
                self.describe()
            except Exception:
                pass

            # Avoid duplicate index creation
            existing_indexes = getattr(self, "global_indexes", []) or []
            for idx in existing_indexes:
                if isinstance(idx, dict) and idx.get("IndexName") == index_name:
                    return False

            # Prepare index schema
            key_schema = [
                {"AttributeName": partition_key, "KeyType": "HASH"}
            ]
            if sort_key:
                key_schema.append({"AttributeName": sort_key, "KeyType": "RANGE"})

            # Prepare projection
            projection = {"ProjectionType": projection_type}
            non_key_attrs = getattr(global_index, "non_key_attributes", None)
            if projection_type == "INCLUDE" and non_key_attrs:
                projection["NonKeyAttributes"] = list(non_key_attrs)

            # Build request parameters
            params = {
                "IndexName": index_name,
                "KeySchema": key_schema,
                "Projection": projection,
            }

            # Capacity settings are only needed for provisioned billing mode
            if read_capacity is not None:
                params["ProvisionedThroughput"] = {
                    "ReadCapacityUnits": read_capacity,
                    "WriteCapacityUnits": write_capacity if write_capacity is not None else read_capacity,
                }

            # Create the index using the underlying DynamoDB table resource/client
            if hasattr(self, "table") and hasattr(self.table, "update"):
                # boto3 Table resource path
                self.table.update(
                    AttributeDefinitions=[
                        {"AttributeName": partition_key, "AttributeType": getattr(global_index, "partition_key_type", "S")},
                        *(
                            [{"AttributeName": sort_key, "AttributeType": getattr(global_index, "sort_key_type", "S")}]
                            if sort_key else []
                        ),
                    ],
                    GlobalSecondaryIndexUpdates=[{"Create": params}],
                )
            elif hasattr(self, "client") and hasattr(self.client, "update_table"):
                # boto3 client path
                self.client.update_table(
                    TableName=getattr(self, "table_name", None),
                    AttributeDefinitions=[
                        {"AttributeName": partition_key, "AttributeType": getattr(global_index, "partition_key_type", "S")},
                        *(
                            [{"AttributeName": sort_key, "AttributeType": getattr(global_index, "sort_key_type", "S")}]
                            if sort_key else []
                        ),
                    ],
                    GlobalSecondaryIndexUpdates=[{"Create": params}],
                )
            else:
                return False

            # Refresh table metadata after creation
            try:
                self.describe()
            except Exception:
                pass

            return True

        except Exception:
            return False

class Table:
    def _put_item(self, item_data, expects=None):
        """
        This function is used by the Item instances to save themselves to a Table instance.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param item_data: Item. Several Item instances to be saved.
        :param expects: Optional. The expected conditions for the save operation.
        :return: Bool. Returns True after saving the item to the table.
        """
        # Basic validation
        if item_data is None:
            raise ValueError("item_data cannot be None")

        # If the table has a backend/client with a put_item method, delegate to it.
        # This keeps the method generic and usable with different storage implementations.
        if hasattr(self, "client") and hasattr(self.client, "put_item"):
            kwargs = {"Item": item_data}
            if expects is not None:
                kwargs["Expected"] = expects
            self.client.put_item(**kwargs)
            return True

        # Fallback: store in an in-memory dictionary if available.
        if hasattr(self, "_items"):
            # Try to derive a key from common primary key names.
            key = None
            if isinstance(item_data, dict):
                for candidate in ("id", "pk", "key"):
                    if candidate in item_data:
                        key = item_data[candidate]
                        break

            if key is None:
                # If no obvious key exists, use the whole item as a tuple of sorted items.
                key = tuple(sorted(item_data.items())) if isinstance(item_data, dict) else item_data

            self._items[key] = item_data
            return True

        # If no storage mechanism is available, fail clearly.
        raise NotImplementedError(
            "No supported storage backend found for _put_item."
        )

class Table:
    def count(self):
        """
        This function returns an approximate count of the number of items in a table. The count may not be accurate due to lag time.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :return: Integer. The approximate count of the number of items in the table.
        """
        return len(self)

class Table:
    def _build_filters(self, filter_kwargs, using=QUERY_OPERATORS):
        """
        This function is an internal method used to convert query/scan-style keyword arguments into the raw structure that DynamoDB expects for filtering. It creates a dictionary of filters based on the input filter_kwargs.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param filter_kwargs: Dictionary. The query/scan-style keyword arguments to be converted into filters.
        :param using: Dictionary. The dictionary of query operators to be used for comparison. It defaults to QUERY_OPERATORS if not specified.
        :return: None.
        """
        filters = {}

        for key, value in filter_kwargs.items():
            # Support Django-style lookups like:
            #   age__gte=18
            #   name__contains="abc"
            #   status="active"  -> equality
            if "__" in key:
                field, op = key.rsplit("__", 1)
                operator = using.get(op)
                if operator is None:
                    raise ValueError(f"Unsupported filter operator: {op}")
            else:
                field = key
                operator = using.get("eq", "=")

            filters[field] = {
                "operator": operator,
                "value": value,
            }

        return filters

class Table:
    def batch_get(self, keys, consistent=False, attributes=None):
        """
        This function fetches multiple specific items in batch from a table. It takes a list of dictionaries as the keys parameter, where each dictionary consists of the key values to specify. It also accepts optional parameters such as consistent (boolean) for specifying whether to use strongly consistent read or not, and attributes (tuple) for specifying the attributes to fetch from DynamoDB. It returns a ResultSet object that handles the pagination of results.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param keys: List of dictionaries. The keys values to specify for fetching items.
        :param consistent: Bool. Whether to use strongly consistent read or not. Defaults to False.
        :param attributes: Tuple. The attributes to fetch from DynamoDB.
        :return: ResultSet. The ResultSet object that handles the pagination of results.
        """
        if not keys:
            return ResultSet(self, [], consistent=consistent, attributes=attributes)

        # Normalize keys to a list of dictionaries
        if not isinstance(keys, (list, tuple)):
            raise TypeError("keys must be a list or tuple of key dictionaries")

        # Build the request payload for batch_get_item
        request_keys = []
        for key in keys:
            if not isinstance(key, dict):
                raise TypeError("each key must be a dictionary")
            request_keys.append(key)

        # Return a ResultSet that will handle fetching/pagination
        return ResultSet(
            self,
            request_keys,
            consistent=consistent,
            attributes=attributes
        )

class BatchTable:
    def put_item(self, data, overwrite=False):
        """
        This function adds an item to the BatchTable instance. It appends the input data to the list of items to be put in the BatchTable. It also can flush the items.
        Input-Output Arguments
        :param self: BatchTable. An instance of the BatchTable class.
        :param data: The data to be added to the BatchTable.
        :param overwrite: Bool. Whether to overwrite existing data with the same key. Defaults to False.
        :return: No return values.
        """
        if data is None:
            return

        # Ensure the batch storage exists
        if not hasattr(self, "items"):
            self.items = []

        # If overwrite is enabled, replace any existing item with the same key
        if overwrite and isinstance(data, dict) and "key" in data:
            self.items = [
                item for item in self.items
                if not (isinstance(item, dict) and item.get("key") == data["key"])
            ]

        # Add the new item
        self.items.append(data)

        # Flush if batch size limit is reached
        batch_size = getattr(self, "batch_size", None)
        if batch_size is not None and len(self.items) >= batch_size:
            if hasattr(self, "flush") and callable(self.flush):
                self.flush()

class Table:
    def get_key_fields(self):
        """
        This function returns the fields necessary to make a key for a table. If the table does not already have a populated schema, it requests it. It returns a list of field names.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :return: List of field names (strings) that are necessary to make a key for the table.
        """
        # Ensure schema is available
        if not hasattr(self, "schema") or self.schema is None:
            if hasattr(self, "request_schema") and callable(self.request_schema):
                self.request_schema()
            else:
                raise AttributeError("Table schema is not populated and no request_schema() method is available.")

        # If schema is still missing, fail clearly
        if not hasattr(self, "schema") or self.schema is None:
            raise ValueError("Table schema could not be populated.")

        # Common schema shapes supported:
        # 1) dict with a 'key_fields' entry
        # 2) dict with a 'primary_key' entry
        # 3) object with key_fields / primary_key attributes
        # 4) list/tuple of field descriptors containing key/primary_key flags
        schema = self.schema

        # Direct attribute / dict lookups
        if isinstance(schema, dict):
            if "key_fields" in schema and schema["key_fields"] is not None:
                return list(schema["key_fields"])
            if "primary_key" in schema and schema["primary_key"] is not None:
                pk = schema["primary_key"]
                return list(pk) if isinstance(pk, (list, tuple)) else [pk]

        else:
            if hasattr(schema, "key_fields") and getattr(schema, "key_fields") is not None:
                return list(getattr(schema, "key_fields"))
            if hasattr(schema, "primary_key") and getattr(schema, "primary_key") is not None:
                pk = getattr(schema, "primary_key")
                return list(pk) if isinstance(pk, (list, tuple)) else [pk]

        # Infer from field descriptors if schema is iterable
        key_fields = []
        try:
            for field in schema:
                if isinstance(field, dict):
                    name = field.get("name")
                    is_key = field.get("key") or field.get("primary_key") or field.get("is_key")
                else:
                    name = getattr(field, "name", None)
                    is_key = (
                        getattr(field, "key", False)
                        or getattr(field, "primary_key", False)
                        or getattr(field, "is_key", False)
                    )

                if name is not None and is_key:
                    key_fields.append(name)
        except TypeError:
            pass

        if key_fields:
            return key_fields

        # Fallback: if the table has a single key field name stored elsewhere
        for attr in ("key_field", "pk_field", "primary_key_field"):
            if hasattr(self, attr):
                value = getattr(self, attr)
                if value is not None:
                    return [value] if isinstance(value, str) else list(value)

        return []

class BaseSchemaField:
    def definition(self):
        """
        This function returns the attribute definition structure that DynamoDB expects for a schema field. It includes the attribute name and attribute type.
        Input-Output Arguments
        :param self: BaseSchemaField. An instance of the BaseSchemaField class.
        :return: Dictionary. The attribute definition structure that DynamoDB expects.
        """
        return {
            "AttributeName": self.name,
            "AttributeType": self.type
        }

class BatchTable:
    def flush(self):
        """
        This function flushes the batch data by preparing the data to be inserted or deleted.
        It also handles any unprocessed items.

        Input-Output Arguments
        :param self: BatchTable. An instance of the BatchTable class.
        :return: bool. Returns True after flushing the batch data.
        """
        # If there is nothing to flush, return True.
        if not hasattr(self, "batch_data") or not self.batch_data:
            return True

        # Prepare containers for items to insert/delete and any unprocessed items.
        items_to_insert = []
        items_to_delete = []
        unprocessed_items = []

        # Split batch data into insert/delete operations.
        for item in self.batch_data:
            if isinstance(item, dict) and item.get("operation") == "delete":
                items_to_delete.append(item)
            elif isinstance(item, dict) and item.get("operation") == "insert":
                items_to_insert.append(item)
            else:
                unprocessed_items.append(item)

        # Store prepared data back on the instance if those attributes exist.
        if hasattr(self, "items_to_insert"):
            self.items_to_insert.extend(items_to_insert)
        else:
            self.items_to_insert = items_to_insert

        if hasattr(self, "items_to_delete"):
            self.items_to_delete.extend(items_to_delete)
        else:
            self.items_to_delete = items_to_delete

        if hasattr(self, "unprocessed_items"):
            self.unprocessed_items.extend(unprocessed_items)
        else:
            self.unprocessed_items = unprocessed_items

        # Clear the batch after flushing.
        self.batch_data = []

        return True

class BatchTable:
    def resend_unprocessed(self):
        # If there are unprocessed records (for instance, the user was over
        # their throughput limitations), iterate over them & send until they're
        # all there.

        """
        Resend unprocessed items in the BatchTable instance. It iterates over the unprocessed items and sends them in batches until all items are processed.
        Input-Output Arguments
        :param self: BatchTable. An instance of the BatchTable class.
        :return: No return values.
        """
        # Nothing to resend if there are no unprocessed items
        if not hasattr(self, "unprocessed") or not self.unprocessed:
            return

        # Keep retrying until all unprocessed items are successfully sent
        while self.unprocessed:
            # Copy current unprocessed items and clear the queue before retrying
            items_to_retry = self.unprocessed
            self.unprocessed = []

            # Send items in batches
            for item in items_to_retry:
                try:
                    # Prefer a batch send method if available
                    if hasattr(self, "send"):
                        self.send(item)
                    elif hasattr(self, "put_item"):
                        self.put_item(item)
                    else:
                        raise AttributeError(
                            "BatchTable must define a send() or put_item() method."
                        )
                except Exception:
                    # If sending fails, keep the item for another retry
                    self.unprocessed.append(item)

            # If nothing changed, avoid an infinite loop
            if len(self.unprocessed) == len(items_to_retry):
                break

class BaseIndexField:
    def definition(self):
        """
        This function returns the attribute definition structure that DynamoDB expects for the index field. It iterates over the parts of the index field and creates a list of dictionaries, where each dictionary represents an attribute with its name and data type.
        Input-Output Arguments
        :param self: BaseIndexField. An instance of the BaseIndexField class.
        :return: List of dictionaries. The attribute definition structure that DynamoDB expects. Each dictionary contains the name and data type of an attribute.
        """
        return [
            {"AttributeName": part.name, "AttributeType": part.data_type}
            for part in getattr(self, "parts", [])
        ]

class BaseIndexField:
    def schema(self):
        """
        This function returns the schema structure that DynamoDB expects for the given index field. It constructs the schema by iterating over the parts of the index field and appending their schemas to the key schema.
        Input-Output Arguments
        :param self: BaseIndexField. An instance of the BaseIndexField class.
        :return: Dict. The schema structure that DynamoDB expects for the index field. The structure includes the index name, key schema, and projection type.
        """
        key_schema = []

        # If the index field is composed of multiple parts, build the key schema from them.
        if hasattr(self, "parts") and self.parts:
            for part in self.parts:
                if hasattr(part, "schema") and callable(part.schema):
                    key_schema.append(part.schema())
                else:
                    key_schema.append(part)
        else:
            # Fallback for a simple index field representation
            if hasattr(self, "name") and hasattr(self, "key_type"):
                key_schema.append({
                    "AttributeName": self.name,
                    "KeyType": self.key_type
                })

        schema = {
            "KeySchema": key_schema,
            "Projection": {
                "ProjectionType": "ALL"
            }
        }

        # Include index name if available
        if hasattr(self, "index_name"):
            schema["IndexName"] = self.index_name
        elif hasattr(self, "name"):
            schema["IndexName"] = self.name

        return schema

class Item:
    def get_raw_keys(self):
        """
        This function returns a dictionary of the keys and their corresponding values in DynamoDB-style format. It iterates over the keys and values and encodes the values before adding them to the dictionary.
        Input-Output Arguments
        :param self: Item. An instance of the Item class.
        :return: Dict. A dictionary containing the keys and their corresponding encoded values in DynamoDB-style format.
        """
        raw_keys = {}

        # Expecting the item to expose its key attributes in a dict-like form.
        # Commonly, these may be stored in `self.keys` or accessible via `self._keys`.
        keys = getattr(self, "keys", None)
        if keys is None:
            keys = getattr(self, "_keys", {})

        for key, value in keys.items():
            # Encode each value into DynamoDB-style format if an encoder exists.
            if hasattr(self, "encode"):
                raw_keys[key] = self.encode(value)
            else:
                raw_keys[key] = value

        return raw_keys

class Item:
    def prepare_full(self):
        """
        This function prepares the data of an Item object to be saved in DynamoDB. It encodes each field of the Item object and returns the encoded data as a dictionary.
        Input-Output Arguments
        :param self: Item. An instance of the Item class.
        :return: Dict. The encoded data of the Item object as a dictionary.
        """
        data = {}

        for key, value in self.__dict__.items():
            if value is None:
                continue

            # Encode nested Item objects
            if isinstance(value, Item):
                data[key] = value.prepare_full()
            # Encode lists/tuples recursively
            elif isinstance(value, (list, tuple)):
                encoded_list = []
                for item in value:
                    if isinstance(item, Item):
                        encoded_list.append(item.prepare_full())
                    else:
                        encoded_list.append(item)
                data[key] = encoded_list
            # Encode dictionaries recursively for nested Item objects
            elif isinstance(value, dict):
                encoded_dict = {}
                for k, v in value.items():
                    if isinstance(v, Item):
                        encoded_dict[k] = v.prepare_full()
                    else:
                        encoded_dict[k] = v
                data[key] = encoded_dict
            else:
                data[key] = value

        return data

class Item:
    def prepare_partial(self):
        """
        This function prepares the changed or deleted fields of an Item instance to be encoded and handed off to DynamoDB for an update operation. It determines the alterations made to the fields, encodes the values, and creates a data structure with the necessary actions and values for each field.
        Input-Output Arguments
        :param self: Item. An instance of the Item class.
        :return: Tuple. A tuple containing the final data structure with actions and values for each field, and a set of fields that were altered.
        """
        # These attributes are expected to exist on the instance:
        # - _data: current field values
        # - _original_data: values as last loaded/saved
        # - _deleted_fields: fields explicitly marked for deletion
        # - _encode_value(value): encodes a Python value for DynamoDB
        # - _is_key_field(field): returns True if field is a key field
        # - _is_ignored_field(field): returns True if field should not be persisted

        partial = {}
        altered_fields = set()

        current_data = getattr(self, "_data", {})
        original_data = getattr(self, "_original_data", {})
        deleted_fields = set(getattr(self, "_deleted_fields", set()))

        all_fields = set(current_data.keys()) | set(original_data.keys()) | deleted_fields

        for field in all_fields:
            if hasattr(self, "_is_ignored_field") and self._is_ignored_field(field):
                continue

            # Skip key fields for update payloads
            if hasattr(self, "_is_key_field") and self._is_key_field(field):
                continue

            if field in deleted_fields:
                partial[field] = {"Action": "DELETE"}
                altered_fields.add(field)
                continue

            current_value = current_data.get(field, None)
            original_value = original_data.get(field, None)

            # Only include changed fields
            if current_value != original_value:
                altered_fields.add(field)

                if current_value is None:
                    partial[field] = {"Action": "DELETE"}
                else:
                    encoded_value = (
                        self._encode_value(current_value)
                        if hasattr(self, "_encode_value")
                        else current_value
                    )
                    partial[field] = {"Action": "PUT", "Value": encoded_value}

        return partial, altered_fields

class Item:
    def build_expects(self, fields=None):
        """
        This function builds up a dictionary of expectations to be passed to DynamoDB when saving an item. It iterates through the fields provided (or all fields if none are specified), checks their state (new, unchanged, modified, or deleted), and adds the corresponding expectation to the dictionary. It also encodes the value if necessary.
        Input-Output Arguments
        :param self: Item. An instance of the Item class.
        :param fields: List of strings. The fields to include in the expectations. If None, all fields are included. Defaults to None.
        :return: Dictionary. A dictionary of expectations to be passed to DynamoDB.
        """
        expects = {}

        # Determine which fields to process
        if fields is None:
            fields = list(getattr(self, "_data", {}).keys())

        for field in fields:
            # Skip internal/private attributes
            if field.startswith("_"):
                continue

            # Get current and original values/state
            current_value = getattr(self, field, None)
            original_data = getattr(self, "_original_data", {})
            original_value = original_data.get(field, None)

            # Determine field state
            is_new = field not in original_data
            is_deleted = current_value is None and field in original_data
            is_modified = (not is_new and not is_deleted and current_value != original_value)

            # Build expectation based on state
            if is_new:
                # Expect field not to exist yet
                expects[field] = {"Exists": False}
            elif is_deleted:
                # Expect field to exist before deletion
                expects[field] = {"Exists": True}
            elif is_modified:
                # Expect old value to match before update
                expects[field] = {
                    "Value": self.encode(original_value) if hasattr(self, "encode") else original_value
                }
            else:
                # Unchanged field: still expect current/original value
                expects[field] = {
                    "Value": self.encode(current_value) if hasattr(self, "encode") else current_value
                }

        return expects

class Item:
    def partial_save(self):
        """
        This function saves only the changed data of an Item instance to DynamoDB. It updates only the fields that have been modified, rather than pushing the entire item. This helps prevent accidental overwrites and reduces the amount of data transferred over the network.
        Input-Output Arguments
        :param self: Item. An instance of the Item class.
        :return: bool. Returns True if the save operation is successful, False if no save was performed or if the write failed.
        """
        try:
            # If the object does not track changes, fall back to a full save if available.
            if not hasattr(self, "_changed_fields") or not self._changed_fields:
                return False

            # Determine the DynamoDB table name.
            table_name = getattr(self, "_table_name", None)
            if not table_name:
                return False

            # Determine the primary key field(s).
            key_fields = getattr(self, "_key_fields", None)
            if not key_fields:
                key_fields = ["id"] if hasattr(self, "id") else []

            if not key_fields:
                return False

            # Build the key for the update operation.
            key = {}
            for field in key_fields:
                if not hasattr(self, field):
                    return False
                key[field] = getattr(self, field)

            # Build the update expression for changed fields.
            update_parts = []
            expression_values = {}
            expression_names = {}

            for field in self._changed_fields:
                if field in key_fields:
                    continue
                if not hasattr(self, field):
                    continue

                placeholder_name = f"#{field}"
                placeholder_value = f":{field}"

                expression_names[placeholder_name] = field
                expression_values[placeholder_value] = getattr(self, field)
                update_parts.append(f"{placeholder_name} = {placeholder_value}")

            # Nothing to update.
            if not update_parts:
                return False

            update_expression = "SET " + ", ".join(update_parts)

            # Use boto3 if available on the instance.
            dynamodb = getattr(self, "_dynamodb_resource", None)
            if dynamodb is None:
                import boto3
                dynamodb = boto3.resource("dynamodb")

            table = dynamodb.Table(table_name)
            table.update_item(
                Key=key,
                UpdateExpression=update_expression,
                ExpressionAttributeNames=expression_names if expression_names else None,
                ExpressionAttributeValues=expression_values,
            )

            # Clear changed fields after successful save.
            self._changed_fields.clear()
            return True

        except Exception:
            return False

