import sqlparse
from sqlparse.sql import Identifier, IdentifierList, Parenthesis, TokenList
from sqlparse.tokens import Keyword, DML

def _is_subselect(parsed):
    if not parsed.is_group:
        return False
    for token in parsed.tokens:
        if token.ttype is DML and token.value.upper() == "SELECT":
            return True
    return False

def _extract_from_token(token):
    tables = []

    if isinstance(token, IdentifierList):
        for identifier in token.get_identifiers():
            tables.extend(_extract_from_identifier(identifier))
    elif isinstance(token, Identifier):
        tables.extend(_extract_from_identifier(token))
    elif isinstance(token, Parenthesis):
        # Handle subqueries
        for subtoken in token.tokens:
            if isinstance(subtoken, TokenList):
                tables.extend(_extract_tables_from_tokenlist(subtoken))
    elif isinstance(token, TokenList):
        tables.extend(_extract_tables_from_tokenlist(token))

    return tables

def _extract_from_identifier(identifier):
    # Skip function calls like COUNT(...)
    if "(" in str(identifier) and ")" in str(identifier):
        return []

    schema = None
    table = None
    alias = identifier.get_alias()

    real_name = identifier.get_real_name()
    parent_name = identifier.get_parent_name()

    if real_name:
        table = real_name
    if parent_name:
        schema = parent_name

    # If identifier is a dotted name without alias, sqlparse may return full name in real_name
    if table is None:
        parts = [p.strip() for p in str(identifier).split(".")]
        if len(parts) == 2:
            schema, table = parts
        elif len(parts) == 3:
            schema, table = parts[-2], parts[-1]

    if table:
        tables.append((schema, table, alias))
    return tables

def _extract_tables_from_tokenlist(tokenlist):
    tables = []
    from_seen = False
    join_seen = False

    for token in tokenlist.tokens:
        if token.is_whitespace or token.ttype is sqlparse.tokens.Punctuation:
            continue

        value = token.value.upper() if hasattr(token, "value") else ""

        if token.ttype is Keyword:
            if value in ("FROM", "JOIN", "INNER JOIN", "LEFT JOIN", "RIGHT JOIN",
                         "FULL JOIN", "LEFT OUTER JOIN", "RIGHT OUTER JOIN",
                         "FULL OUTER JOIN", "CROSS JOIN"):
                from_seen = True
                join_seen = True
                continue
            elif value in ("WHERE", "GROUP BY", "ORDER BY", "HAVING", "LIMIT",
                           "UNION", "EXCEPT", "INTERSECT"):
                from_seen = False
                join_seen = False
                continue

        if from_seen or join_seen:
            if isinstance(token, IdentifierList):
                for identifier in token.get_identifiers():
                    tables.extend(_extract_from_identifier(identifier))
                from_seen = False
                join_seen = False
            elif isinstance(token, Identifier):
                tables.extend(_extract_from_identifier(token))
                from_seen = False
                join_seen = False
            elif isinstance(token, Parenthesis) and _is_subselect(token):
                tables.extend(_extract_tables_from_tokenlist(token))
                from_seen = False
                join_seen = False
            elif token.ttype is Keyword and token.value.upper() == "ON":
                # Skip join conditions
                from_seen = False
                join_seen = False

        # Recurse into nested token lists (e.g., subqueries)
        if isinstance(token, TokenList) and not isinstance(token, (Identifier, IdentifierList, Parenthesis)):
            tables.extend(_extract_tables_from_tokenlist(token))

    return tables

parsed = sqlparse.parse(sql)
results = []
seen = set()

for statement in parsed:
    for table in _extract_tables_from_tokenlist(statement):
        if table not in seen:
            seen.add(table)
            results.append(table)

return results

class ArrayFacet:
    async def suggest(self):
        """
        This function suggests array facets based on the given SQL query and parameters. It retrieves the columns from the query, checks if each column is already enabled as a facet, and then checks if every value in the column is either null or a JSON array. If these conditions are met, it further checks that the first 100 arrays in the column contain only strings. If all these conditions are satisfied, it adds the column as a suggested array facet to the list of suggested facets.
        Input-Output Arguments
        :param self: ArrayFacet. An instance of the ArrayFacet class.
        :return: List of dictionaries. A list of suggested array facets, where each dictionary contains the name of the facet, its type, and a toggle URL.
        """
        suggested = []

        # Get columns from the query result / metadata
        columns = getattr(self, "columns", None)
        if columns is None:
            columns = getattr(self, "query_columns", [])
        if not columns:
            return suggested

        # Existing enabled facets, if available
        enabled_facets = set(getattr(self, "enabled_facets", []) or [])
        enabled_facets.update(set(getattr(self, "facets", []) or []))

        # Helper to safely fetch column values
        async def _get_column_values(col):
            if hasattr(self, "get_column_values") and callable(self.get_column_values):
                return await self.get_column_values(col)
            if hasattr(self, "fetch_column_values") and callable(self.fetch_column_values):
                return await self.fetch_column_values(col)
            return []

        # Helper to validate JSON array of strings
        def _is_array_of_strings(value):
            if not isinstance(value, list):
                return False
            return all(isinstance(item, str) for item in value)

        for col in columns:
            col_name = col.get("name") if isinstance(col, dict) else str(col)

            # Skip if already enabled
            if col_name in enabled_facets:
                continue

            values = await _get_column_values(col_name)
            if not values:
                continue

            # Every value must be either null or a JSON array
            valid = True
            arrays_seen = 0
            for v in values:
                if v is None:
                    continue
                if not isinstance(v, list):
                    valid = False
                    break
                arrays_seen += 1

            if not valid or arrays_seen == 0:
                continue

            # First 100 arrays must contain only strings
            array_values = [v for v in values if isinstance(v, list)][:100]
            if not array_values:
                continue

            if not all(_is_array_of_strings(arr) for arr in array_values):
                continue

            # Build toggle URL if possible
            toggle_url = None
            if hasattr(self, "toggle_url") and callable(self.toggle_url):
                toggle_url = self.toggle_url(col_name, "array")
            elif hasattr(self, "base_url"):
                toggle_url = f"{self.base_url}?facet={col_name}&type=array"

            suggested.append(
                {
                    "name": col_name,
                    "type": "array",
                    "toggle_url": toggle_url,
                }
            )

        return suggested

class Datasette:
    def get_database(self, name=None, route=None):
        """
        This function retrieves a database from the Datasette instance based on the given conditions. It first checks if a specific route is provided, and if so, it returns the database that matches the route. If no route is provided, it returns the first database that is not named "_internal".
        Input-Output Arguments
        :param self: Datasette. An instance of the Datasette class.
        :param name: String [optional]. The name of the database to retrieve. If not provided, the first database that isn't '_internal' is returned.
        :param route: String [optional]. The route of the database to retrieve. If provided, the database with the matching route is returned.
        :return: Database. The retrieved database instance.
        """
        # If a route is provided, try to find the matching database
        if route is not None:
            for database in self.databases.values():
                if getattr(database, "route", None) == route:
                    return database
            raise KeyError(f"No database found for route: {route}")

        # If a name is provided, return that database if it exists
        if name is not None:
            if name in self.databases:
                return self.databases[name]
            raise KeyError(f"No database found with name: {name}")

        # Otherwise return the first database that is not "_internal"
        for db_name, database in self.databases.items():
            if db_name != "_internal":
                return database

        raise KeyError("No suitable database found")

class Datasette:
    async def render_template(
        self, templates, context=None, request=None, view_name=None
    ):

        """
        This function renders a template using the Datasette instance. It first checks if the startup has been invoked, and if not, raises an exception. Then, it prepares the context for the template by adding various variables and values. It also calls hooks to get any extra body scripts and template variables. Finally, it renders the template with the prepared context and returns the result.
        Input-Output Arguments
        :param self: Datasette. An instance of the Datasette class.
        :param templates: Template or str. The template(s) to render. It can be a Template instance or a string representing the template name.
        :param context: dict. The context variables to be passed to the template. Defaults to None.
        :param request: Request. The request object associated with the rendering. Defaults to None.
        :param view_name: str. The name of the view being rendered. Defaults to None.
        :return: str. The rendered template as a string.
        """
        if not getattr(self, "_startup_complete", False):
            raise RuntimeError("Datasette startup has not completed")

        context = dict(context or {})

        # Basic request-related context
        context.setdefault("request", request)
        context.setdefault("view_name", view_name)
        context.setdefault("datasette", self)

        # Add extra body scripts from hooks if available
        extra_body_script = []
        if hasattr(self, "plugin_manager") and self.plugin_manager is not None:
            try:
                extra_body_script = await self.plugin_manager.hook.extra_body_script(
                    datasette=self, request=request
                )
            except Exception:
                extra_body_script = []
        context["extra_body_script"] = extra_body_script

        # Add template variables from hooks if available
        if hasattr(self, "plugin_manager") and self.plugin_manager is not None:
            try:
                extra_template_vars = await self.plugin_manager.hook.extra_template_vars(
                    datasette=self, request=request
                )
                if extra_template_vars:
                    for item in extra_template_vars:
                        if isinstance(item, dict):
                            context.update(item)
            except Exception:
                pass

        # Render using the underlying template engine
        if hasattr(self, "jinja_env"):
            template = self.jinja_env.get_template(templates) if isinstance(templates, str) else templates
            return template.render(**context)

        raise RuntimeError("No template environment available")

class Response:
    def html(cls, body, status=200, headers=None):
        """
        Create a Response instance with HTML content. It sets the body, status, headers, and content type of the response.
        Input-Output Arguments
        :param cls: Class. The class of the Response instance.
        :param body: Any. The body of the response.
        :param status: int. The status code of the response. It defaults to 200 if not specified.
        :param headers: dict. The headers of the response. It defaults to None if not specified.
        :return: Response. The created Response instance.
        """
        if headers is None:
            headers = {}
        headers = dict(headers)
        headers.setdefault("Content-Type", "text/html")
        return cls(body=body, status=status, headers=headers)

class Response:
    def redirect(cls, path, status=302, headers=None):
        """
        This function creates a redirect response. It sets the "Location" header to the specified path and returns a Response instance with the given status code and headers.
        Input-Output Arguments
        :param cls: Class. The class of the Response instance.
        :param path: String. The path to redirect to.
        :param status: Integer. The status code for the response. It defaults to 302 if not specified.
        :param headers: Dictionary. Additional headers to include in the response. It defaults to an empty dictionary if not specified.
        :return: Response. The created redirect response instance.
        """
        if headers is None:
            headers = {}

        headers = dict(headers)
        headers["Location"] = path

        return cls(status=status, headers=headers)

