import inspect

def call_with_supported_arguments(fn, **kwargs):
    """
    This function calls the given function with the supported arguments. It gathers the arguments that are supported by the function and then calls the function with those arguments.
    Input-Output Arguments
    :param fn: Function. The function to be called.
    :param kwargs: Keyword arguments. The arguments to be passed to the function.
    :return: The return value of the function call.
    """
    sig = inspect.signature(fn)
    params = sig.parameters

    # If the function accepts **kwargs, pass everything through.
    if any(p.kind == inspect.Parameter.VAR_KEYWORD for p in params.values()):
        return fn(**kwargs)

    # Otherwise, only pass supported keyword arguments.
    supported_kwargs = {
        name: value
        for name, value in kwargs.items()
        if name in params and params[name].kind in (
            inspect.Parameter.POSITIONAL_OR_KEYWORD,
            inspect.Parameter.KEYWORD_ONLY,
        )
    }

    return fn(**supported_kwargs)

class Resolver:
    def get_package_name(self):
        """
        This function returns the name of the package based on the package in a Resolver instance. If the package value is set to CALLER_PACKAGE, it retrieves the name of the caller package. Otherwise, it retrieves the name of the package specified in the package of the Resolver instance.
        Input-Output Arguments
        :param self: Resolver. An instance of the Resolver class.
        :return: String. The name of the package.
        """
        if getattr(self, "package", None) == "CALLER_PACKAGE":
            # Try to infer the caller's package name from the call stack
            import inspect

            frame = inspect.currentframe()
            try:
                # current frame -> get_package_name, caller -> whoever called get_package_name
                caller_frame = frame.f_back if frame else None
                module = inspect.getmodule(caller_frame) if caller_frame else None
                return module.__package__ if module and module.__package__ else module.__name__ if module else None
            finally:
                del frame
        else:
            package = getattr(self, "package", None)
            if package is None:
                return None
            return package.__package__ if hasattr(package, "__package__") else str(package)

