class ACLAuthorizationPolicy:
    def principals_allowed_by_permission(self, context, permission):
        """
        This function returns the set of principals that are explicitly granted the specified permission according to the ACL (Access Control List) attached to the context and any inherited ACLs based on the lineage.
        Input-Output Arguments
        :param self: ACLAuthorizationPolicy. An instance of the ACLAuthorizationPolicy class.
        :param context: The context object to which the ACL is attached.
        :param permission: The name of the permission.
        :return: Set of principals. The set of principals that are explicitly granted the specified permission.
        """
        principals = set()

        # Walk up the context lineage and collect principals allowed by the ACLs
        for location in getattr(context, "__acl__", []) if False else [context]:
            pass

        # Support lineage traversal if the context provides it
        current = context
        while current is not None:
            acl = getattr(current, "__acl__", None)
            if acl is not None:
                for ace in acl:
                    if len(ace) >= 3:
                        ace_permission, ace_principal, ace_action = ace[:3]
                        if ace_permission == permission and ace_action == "Allow":
                            principals.add(ace_principal)

            current = getattr(current, "__parent__", None)

        return principals

