class Introspector:
    def relate(self, *pairs):
        """
        This function establishes relationships among introspectables based on the given category name and discriminator pairs. It creates relationships between each pair of introspectables by adding a reference from one introspectable to another.
        Input-Output Arguments
        :param self: Introspector. An instance of the Introspector class.
        :param pairs: Variable number of arguments. Each argument is a pair of category name and discriminator to identify one introspectable.
        :return: No return values.
        """
        if len(pairs) < 2:
            return

        # Resolve each (category, discriminator) pair to an introspectable object
        resolved = []
        for pair in pairs:
            if not isinstance(pair, (tuple, list)) or len(pair) != 2:
                raise ValueError("Each argument must be a (category, discriminator) pair.")
            category, discriminator = pair

            # Try common lookup patterns on the introspector
            obj = None
            if hasattr(self, "get"):
                obj = self.get(category, discriminator)
            elif hasattr(self, "lookup"):
                obj = self.lookup(category, discriminator)
            elif hasattr(self, "find"):
                obj = self.find(category, discriminator)
            else:
                # Fallback: try a nested mapping stored on the instance
                store = getattr(self, "store", None) or getattr(self, "introspectables", None)
                if store is not None:
                    obj = store.get(category, {}).get(discriminator)

            if obj is None:
                raise KeyError(f"Could not resolve introspectable for ({category!r}, {discriminator!r}).")

            resolved.append(obj)

        # Create relationships between consecutive introspectables
        for left, right in zip(resolved, resolved[1:]):
            # Prefer a dedicated relationship API if present
            if hasattr(left, "relate"):
                left.relate(right)
            elif hasattr(left, "add_reference"):
                left.add_reference(right)
            elif hasattr(left, "references"):
                left.references.append(right)
            else:
                # Generic fallback: store related objects in a list attribute
                if not hasattr(left, "_related"):
                    left._related = []
                left._related.append(right)

class PackageOverrides:
    def insert(self, path, source):
        """
        Insert a new override into the PackageOverrides instance. It creates a new override object based on the given path and source, and inserts it at the beginning of the overrides list in the PackageOverrides instance.
        Input-Output Arguments
        :param self: PackageOverrides. An instance of the PackageOverrides class.
        :param path: str. The path of the override. If it is empty or it ends with a slash, it is treated as a directory override. Otherwise, it is treated as a file override.
        :param source: Object. The source of the override.
        :return: The created override object.
        """
        # Create the appropriate override object
        if not path or path.endswith("/"):
            override = {
                "type": "directory",
                "path": path,
                "source": source,
            }
        else:
            override = {
                "type": "file",
                "path": path,
                "source": source,
            }

        # Ensure the overrides list exists
        if not hasattr(self, "overrides") or self.overrides is None:
            self.overrides = []

        # Insert at the beginning
        self.overrides.insert(0, override)

        return override

class PackageOverrides:
    def filtered_sources(self, resource_name):
        """
        This function iterates over the overrides in the PackageOverrides instance and yields the filtered sources based on the given resource name. It will yield all possible resources based on different overrides.
        Input-Output Arguments
        :param self: PackageOverrides. An instance of the PackageOverrides class.
        :param resource_name: str. The name of the resource to filter the sources.
        :return: Generator. Yields the filtered sources based on the given resource name.
        """
        # If there are no overrides, yield nothing
        overrides = getattr(self, "overrides", None)
        if not overrides:
            return

        # Iterate through overrides and yield matching sources
        for override in overrides:
            # Support common override shapes:
            # - dict with "resource_name" / "sources"
            # - object with attributes resource_name / sources
            override_resource_name = (
                override.get("resource_name") if isinstance(override, dict)
                else getattr(override, "resource_name", None)
            )

            if override_resource_name != resource_name:
                continue

            sources = (
                override.get("sources") if isinstance(override, dict)
                else getattr(override, "sources", None)
            )

            if sources is None:
                continue

            for source in sources:
                yield source

class PShellCommand:
    def make_shell(self):
        """
        This function is used to determine which shell to use for the PShellCommand instance. If the user has specified a shell, it will use that shell if it is available, otherwise it will raise a ValueError with 'could not find a shell named "%s"' as the message. If the user has not specified a shell, it will use the first available preferred shell if that is specified, otherwise it will use the first available shell, with python as the least preferred shell. If no shell is available at all, it will use the default runner.
        Input-Output Arguments
        :param self: PShellCommand. An instance of the PShellCommand class.
        :return: The selected shell to be used.
        """
        # If a shell was explicitly requested, use it if available.
        if getattr(self, "shell", None):
            shell_name = self.shell
            if shell_name in self.available_shells:
                return self.available_shells[shell_name]
            raise ValueError('could not find a shell named "%s"' % shell_name)

        # If preferred shells are specified, use the first available one.
        preferred_shells = getattr(self, "preferred_shells", None) or []
        for shell_name in preferred_shells:
            if shell_name in self.available_shells:
                return self.available_shells[shell_name]

        # Otherwise, use the first available shell, preferring non-python shells.
        if getattr(self, "available_shells", None):
            for shell_name, shell in self.available_shells.items():
                if shell_name != "python":
                    return shell
            if "python" in self.available_shells:
                return self.available_shells["python"]

        # If nothing is available, fall back to the default runner.
        return self.default_runner

class MultiView:
    def get_views(self, request):
        """
        This function returns a list of views based on the given request. It checks if both the request and this instance have accept. If both conditions are met, it iterates over the acceptable offers from the request's accept and appends the corresponding media views to a 'views' list. It then appends the regular views to the 'views' list. Finally, it returns the 'views' list. If the conditions are not met, it simply returns the regular views.
        Input-Output Arguments
        :param self: MultiView. An instance of the MultiView class.
        :param request: The request object.
        :return: List. The list of views based on the given request.
        """
        views = []

        # If both request and self support accept-based negotiation
        if hasattr(request, "accept") and hasattr(self, "accept") and request.accept and self.accept:
            for offer in request.accept:
                media_view = self.accept.get(offer)
                if media_view is not None:
                    views.append(media_view)

        # Append regular views if available
        if hasattr(self, "views") and self.views:
            views.extend(self.views)
        elif hasattr(self, "view") and self.view:
            views.append(self.view)

        return views

class MultiView:
    def __call_permissive__(self, context, request):
        """
        This function is a method of the MultiView class. It is used to call the matched view with the given context and request. If the matched view is call permissive, this custom method is called instead.
        Input-Output Arguments
        :param self: MultiView. An instance of the MultiView class.
        :param context: The context object to be passed to the view.
        :param request: The request object to be passed to the view.
        :return: The result of calling the matched view with the given context and request.
        """
        view = getattr(self, "matched_view", None)
        if view is None:
            raise AttributeError("No matched view is available to call.")

        # Prefer a permissive call hook if the matched view provides one.
        permissive = getattr(view, "__call_permissive__", None)
        if callable(permissive):
            return permissive(context, request)

        # Fall back to calling the view directly.
        if callable(view):
            return view(context, request)

        raise TypeError("Matched view is not callable.")

class MultiView:
    def add(self, view, order, phash=None, accept=None, accept_order=None):
        """
        This function adds a view to the MultiView instance based on the given conditions. If a view with the same phash value already exists, it updates the existing view. If accept is not specified, it adds the view to the main views list and sorts it based on the order. If accept is specified, it updates the existing view or adds the view to the subset of views for that accept value and sorts it based on the order. It also updates the accept values and sorts them based on the custom order.
        Input-Output Arguments
        :param self: MultiView. An instance of the MultiView class.
        :param view: The view to be added.
        :param order: The order of the view.
        :param phash: The phash value of the view. Defaults to None.
        :param accept: The accept value for the view. Defaults to None.
        :param accept_order: The order of the accept values. Defaults to None.
        :return: No return values.
        """
        # Ensure required containers exist
        if not hasattr(self, "views"):
            self.views = []
        if not hasattr(self, "accept_views"):
            self.accept_views = {}
        if not hasattr(self, "accept_orders"):
            self.accept_orders = {}

        # Helper to update or insert a view in a list by phash
        def upsert_view(container, item):
            if phash is not None:
                for i, existing in enumerate(container):
                    if existing.get("phash") == phash:
                        container[i] = item
                        return
            container.append(item)

        item = {
            "view": view,
            "order": order,
            "phash": phash,
            "accept": accept,
        }

        if accept is None:
            upsert_view(self.views, item)
            self.views.sort(key=lambda x: x["order"])
        else:
            if accept not in self.accept_views:
                self.accept_views[accept] = []
            upsert_view(self.accept_views[accept], item)
            self.accept_views[accept].sort(key=lambda x: x["order"])

            if accept_order is not None:
                self.accept_orders[accept] = accept_order

            # Keep accept keys sorted by accept_order if provided, otherwise by accept value
            self.accept_views = dict(
                sorted(
                    self.accept_views.items(),
                    key=lambda kv: (
                        self.accept_orders.get(kv[0], float("inf")),
                        kv[0],
                    ),
                )
            )

