class OpenAPI:
    def generate(self):
        """
        This function generates an OpenAPI specification based on the given conditions. It creates a base specification dictionary with the host, schemes, and "securityDefinitions". Then, it calls the generate method of the parent class, passing the base specification as the "swagger" parameter.
        Input-Output Arguments
        :param self: OpenAPI. An instance of the OpenAPI class.
        :return: CorniceSwagger. The generated OpenAPI specification.
        """
        base_spec = {
            "host": getattr(self, "host", None),
            "schemes": getattr(self, "schemes", ["http"]),
            "securityDefinitions": getattr(self, "securityDefinitions", {}),
        }

        # Merge any existing swagger/spec data if present
        swagger = getattr(self, "swagger", {})
        if isinstance(swagger, dict):
            base_spec.update(swagger)

        # Call parent generate if available, otherwise return the spec
        parent_generate = getattr(super(), "generate", None)
        if callable(parent_generate):
            return parent_generate(swagger=base_spec)

        return base_spec

class OpenAPI:
    def expose_authentication_method(cls, method_name, definition):
        """
        This function allows security extensions to expose authentication methods on the OpenAPI documentation. It adds the provided method name and definition to the security definitions dictionary of the OpenAPI class. It also adds the scopes from the definition to the security roles dictionary.
        Input-Output Arguments
        :param cls: OpenAPI. The OpenAPI class.
        :param method_name: String. The name of the authentication method.
        :param definition: Dictionary. The definition of the authentication method, following the OpenAPI 2.0 specification.
        :return: No return values.
        """
        # Ensure the class has the required containers
        if not hasattr(cls, "security_definitions") or cls.security_definitions is None:
            cls.security_definitions = {}
        if not hasattr(cls, "security_roles") or cls.security_roles is None:
            cls.security_roles = {}

        # Add/overwrite the security definition
        cls.security_definitions[method_name] = definition

        # Extract scopes from the definition and add them to security_roles
        scopes = definition.get("scopes", {})
        if isinstance(scopes, dict):
            for scope_name, scope_description in scopes.items():
                cls.security_roles[scope_name] = scope_description
        elif isinstance(scopes, list):
            # In case scopes are provided as a list, store them with empty descriptions
            for scope_name in scopes:
                cls.security_roles[scope_name] = ""

        return None

