class RouteFactory:
    def fetch_shared_objects(self, perm, principals, get_bound_permissions):
        """
        This function fetches objects that are readable or writable for the current principals based on the given permissions. It sets shared ids to the context with the fetched object IDs. If no object is shared, it returns None.
        Input-Output Arguments
        :param self: RouteFactory. An instance of the RouteFactory class.
        :param perm: The permission to check for the objects.
        :param principals: The current principals.
        :param get_bound_permissions: Bool. Whether to get bound permissions for the object ID match.
        :return: List of object IDs that are readable or writable for the current principals.
        """
        # Try to obtain a permission-aware object store/query interface.
        store = getattr(self, "store", None) or getattr(self, "db", None) or getattr(self, "session", None)
        if store is None:
            return None

        # Common patterns for fetching shared objects.
        objects = None

        if hasattr(store, "fetch_shared_objects"):
            objects = store.fetch_shared_objects(perm, principals, get_bound_permissions)
        elif hasattr(store, "get_shared_objects"):
            objects = store.get_shared_objects(perm, principals, get_bound_permissions)
        elif hasattr(store, "shared_objects"):
            objects = store.shared_objects(perm, principals, get_bound_permissions)
        else:
            # Fallback: try to query a generic "objects" collection if present.
            query = None
            if hasattr(store, "query"):
                query = store.query
            elif hasattr(store, "objects"):
                query = store.objects

            if query is not None:
                try:
                    # Best-effort filtering by permission/principals.
                    if hasattr(query, "filter"):
                        objects = query.filter(perm=perm, principals=principals, get_bound_permissions=get_bound_permissions)
                    elif callable(query):
                        objects = query(perm, principals, get_bound_permissions)
                except Exception:
                    objects = None

        if not objects:
            return None

        # Normalize to a list of IDs.
        shared_ids = []
        for obj in objects:
            if isinstance(obj, dict):
                obj_id = obj.get("id") or obj.get("_id") or obj.get("object_id")
            else:
                obj_id = getattr(obj, "id", None) or getattr(obj, "_id", None) or getattr(obj, "object_id", None)

            if obj_id is not None:
                shared_ids.append(obj_id)

        if not shared_ids:
            return None

        # Store shared ids in context if available.
        if hasattr(self, "context") and self.context is not None:
            try:
                setattr(self.context, "shared_ids", shared_ids)
            except Exception:
                try:
                    self.context["shared_ids"] = shared_ids
                except Exception:
                    pass

        return shared_ids

