                "error": "read_only_error",
                "message": str(e),
            }
            raise Exception(self.http_error)

class ResourceReponses:
    def get_and_bind(self, endpoint_type, method, **kwargs):
        """
        This function wraps resource colander response schemas for a specific endpoint and method. It creates a dictionary of status codes mapping cloned and binded responses based on the default schemas, endpoint-specific schemas, and method-specific schemas. The response include type responses, method args and endpoint args, finded from this instance.
        Input-Output Arguments
        :param self: ResourceReponses. An instance of the ResourceReponses class.
        :param endpoint_type: String. The type of endpoint.
        :param method: String. The HTTP method.
        :param **kwargs: Additional keyword arguments.
        :return: Dict. A dictionary of status codes mapping cloned and binded responses.
        """
        import copy

        # Collect possible response schema sources from the instance
        default_responses = getattr(self, "default_responses", {}) or {}
        endpoint_responses = getattr(self, "endpoint_responses", {}) or {}
        method_responses = getattr(self, "method_responses", {}) or {}

        # Merge in order: default -> endpoint -> method
        merged = {}

        def _merge(source):
            if not isinstance(source, dict):
                return
            for status_code, response in source.items():
                merged[status_code] = response

        _merge(default_responses)
        _merge(endpoint_responses.get(endpoint_type, {}))
        _merge(method_responses.get(method, {}))

        # Bind/cloned responses
        bound = {}
        bind_kwargs = {}
        bind_kwargs.update(getattr(self, "endpoint_args", {}) or {})
        bind_kwargs.update(getattr(self, "method_args", {}) or {})
        bind_kwargs.update(kwargs)

        for status_code, response in merged.items():
            cloned = copy.deepcopy(response)

            # If the response/schema has a bind method, bind it
            if hasattr(cloned, "bind") and callable(getattr(cloned, "bind")):
                try:
                    cloned = cloned.bind(**bind_kwargs)
                except TypeError:
                    # Fallback for bind methods that accept a single mapping
                    cloned = cloned.bind(bind_kwargs)

            bound[status_code] = cloned

        return bound

class Resource:
    def get(self):
        """
        This function is the "GET" endpoint for retrieving an object. It performs several checks and operations before returning the object. It checks if the object is found, if it has been modified, and if any partial fields need to be extracted. It then adds a timestamp header and a cache header to the response and returns the object. If have partial fields, it extracts them from the object as the result object. Depending on the situation, different error labels may be raised.
        Input-Output Arguments
        :param self: Resource. An instance of the Resource class.
        :return: The retrieved object.
        """
        # Retrieve the object
        obj = getattr(self, "obj", None)
        if obj is None:
            raise ValueError("not_found")

        # Check if the object has been modified
        if hasattr(self, "is_modified") and callable(self.is_modified):
            if not self.is_modified(obj):
                raise ValueError("not_modified")

        # Handle partial field extraction if requested
        fields = getattr(self, "fields", None)
        if fields:
            if isinstance(fields, str):
                fields = [f.strip() for f in fields.split(",") if f.strip()]
            result = {field: obj.get(field) if isinstance(obj, dict) else getattr(obj, field, None)
                      for field in fields}
        else:
            result = obj

        # Add headers if supported
        headers = getattr(self, "headers", None)
        if headers is None:
            headers = {}
            setattr(self, "headers", headers)

        import time
        headers["Timestamp"] = str(int(time.time()))
        headers["Cache-Control"] = "no-cache"

        return result

class Resource:
    def plural_post(self):
        """
        This function is the "POST" endpoint for creating an object in a model. It first checks if the new object id conflicts with an existing one. If it does, the existing object is returned with a status code of 200. If the "If-Match" header is provided and the objects have been modified in the meantime, a "HTTPPreconditionFailed" exception is raised. If the object id is specified, it is added to the posted body and the existing object is looked up. If the object exists, it is returned with a status code of 200. If the object does not exist, the new object is processed, created, and returned with a status code of 201.
        Input-Output Arguments
        :param self: Resource. An instance of the Resource class.
        :return: The created or existing object with the appropriate status code.
        """
        # Get the posted body and any request headers
        body = getattr(self, "body", None) or {}
        headers = getattr(self, "headers", {}) or {}

        # If an object id is provided in the request, ensure it is part of the body
        obj_id = body.get("id") or body.get("_id")
        if obj_id is not None:
            body["id"] = obj_id

        # If-Match precondition handling
        if "If-Match" in headers:
            current_etag = None
            if hasattr(self, "get_etag"):
                current_etag = self.get_etag(body)
            elif hasattr(self, "etag"):
                current_etag = self.etag

            if current_etag is not None and headers["If-Match"] != current_etag:
                raise HTTPPreconditionFailed()

        # Look up an existing object if an id is specified
        existing = None
        if obj_id is not None and hasattr(self, "get"):
            existing = self.get(obj_id)

        # If it already exists, return it with 200
        if existing is not None:
            if hasattr(self, "set_status"):
                self.set_status(200)
            return existing

        # Otherwise create/process the new object
        created = None
        if hasattr(self, "create"):
            created = self.create(body)
        elif hasattr(self, "post"):
            created = self.post(body)
        else:
            created = body

        if hasattr(self, "set_status"):
            self.set_status(201)

        return created

class Resource:
    def delete(self):
        """
        This function deletes an object by sending a DELETE request to the object's endpoint. It performs some checks (like id does not match the format, can not get object, object is modified) and raises exceptions if necessary. Then retreive the last modified information from a querystring if present, if the modified less or equal than current object. Ignore it. After deleting the object, it returns the deleted object.
        Input-Output Arguments
        :param self: Resource. An instance of the Resource class.
        :return: No return values.
        """
        import re
        from urllib.parse import urlparse, parse_qs, urlunparse

        # Ensure the resource has an endpoint / URL to delete
        if not hasattr(self, "url") or not self.url:
            raise ValueError("Resource URL is missing.")

        # Validate id format if present
        if hasattr(self, "id") and self.id is not None:
            if not re.match(r"^[A-Za-z0-9_\-]+$", str(self.id)):
                raise ValueError("Resource id does not match the expected format.")

        # If the object cannot be retrieved, raise an error
        if hasattr(self, "get") and callable(getattr(self, "get")):
            current = self.get()
            if current is None:
                raise LookupError("Cannot get object.")
        else:
            current = self

        # Check modification timestamp if available
        current_modified = getattr(current, "modified", None)
        self_modified = getattr(self, "modified", None)
        if current_modified is not None and self_modified is not None:
            if current_modified <= self_modified:
                # Ignore if the server-side object is not newer than current object
                return current

        # Retrieve last modified info from querystring if present
        parsed = urlparse(self.url)
        query = parse_qs(parsed.query)
        last_modified = query.get("last_modified", [None])[0]

        # If last_modified exists and indicates object is not newer, ignore deletion
        if last_modified is not None and self_modified is not None:
            try:
                if float(last_modified) <= float(self_modified):
                    return current
            except (TypeError, ValueError):
                pass

        # Perform DELETE request
        if hasattr(self, "session") and hasattr(self.session, "delete"):
            response = self.session.delete(self.url)
        elif hasattr(self, "delete_request") and callable(getattr(self, "delete_request")):
            response = self.delete_request(self.url)
        else:
            raise NotImplementedError("No DELETE mechanism available for this Resource.")

        # Raise for HTTP errors if response supports it
        if hasattr(response, "raise_for_status"):
            response.raise_for_status()

        # Return the deleted object
        return current

class BatchPayloadSchema:
    def deserialize(self, cstruct=colander.null):

        """
        This function is a method of the BatchPayloadSchema class. It deserializes the received data and merges the defaults with the requests. It then returns the deserialized data.
        Input-Output Arguments
        :param self: BatchPayloadSchema. An instance of the BatchPayloadSchema class.
        :param cstruct: dict. The data to be deserialized. Defaults to colander.null.
        :return: The deserialized data after merging the defaults with the requests.
        """
        # If no input is provided, use an empty dict so defaults can be applied.
        if cstruct is colander.null:
            cstruct = {}

        # Let Colander handle deserialization and default merging.
        return super().deserialize(cstruct)

class OpenIDConnectPolicy:
    def _verify_token(self, access_token):
        """
        This function verifies the access token by fetching the user information from the profile endpoint. It sends a GET request to the userinfo endpoint with the access token in the Authorization header. If the request is successful, it returns the user profile information. If there is an error during the request or parsing the response, it logs a debug message and returns None.
        Input-Output Arguments
        :param self: OpenIDConnectPolicy. An instance of the OpenIDConnectPolicy class.
        :param access_token: String. The access token to verify.
        :return: Dictionary. The user profile information if the access token is valid, otherwise None.
        """
        import logging
        import requests

        logger = logging.getLogger(__name__)

        try:
            # Expect the policy to have a configured userinfo/profile endpoint
            userinfo_endpoint = getattr(self, "userinfo_endpoint", None) or getattr(self, "profile_endpoint", None)
            if not userinfo_endpoint:
                logger.debug("No userinfo/profile endpoint configured.")
                return None

            headers = {
                "Authorization": f"Bearer {access_token}",
                "Accept": "application/json",
            }

            response = requests.get(userinfo_endpoint, headers=headers, timeout=10)
            response.raise_for_status()

            try:
                return response.json()
            except ValueError:
                logger.debug("Failed to parse userinfo response as JSON.")
                return None

        except Exception as exc:
            logger.debug("Token verification failed: %s", exc)
            return None

class Config:
    def print_stdout(self, text: str, *arg) -> None:
        """
        This function is used to render a message to standard output. It takes a text string as input and formats it with additional arguments if provided. The formatted message is then output to the standard output. If no additional arguments are provided, the text is output verbatim. This function does nothing if the "quiet" messaging option is enabled.
        Input-Output Arguments
        :param self: Config. An instance of the Config class.
        :param text: String. The text to be rendered to standard output.
        :param *arg: Additional arguments to be formatted against the provided text.
        :return: None.
        """
        if getattr(self, "quiet", False):
            return

        if arg:
            print(text.format(*arg))
        else:
            print(text)

from collections import defaultdict

def infer_type(value):
    if value is None:
        return "null"
    if isinstance(value, bool):
        return "bool"
    if isinstance(value, int) and not isinstance(value, bool):
        return "int"
    if isinstance(value, float):
        return "float"
    if isinstance(value, str):
        return "str"
    return type(value).__name__

# Collect observed types for each column
column_types = defaultdict(set)

for record in records:
    if not isinstance(record, dict):
        continue
    for key, value in record.items():
        column_types[key].add(infer_type(value))

# Suggest a final type for each column
suggested_types = {}
for column, types in column_types.items():
    types.discard("null")

    if not types:
        suggested_types[column] = "null"
    elif types == {"bool"}:
        suggested_types[column] = "bool"
    elif types <= {"int"}:
        suggested_types[column] = "int"
    elif types <= {"int", "float"}:
        suggested_types[column] = "float"
    elif types == {"str"}:
        suggested_types[column] = "str"
    else:
        suggested_types[column] = "mixed"

return suggested_types

import pkg_resources

plugins_info = []

# Iterate over all installed entry points (plugins)
for entry_point in pkg_resources.iter_entry_points():
    plugin_data = {
        "name": entry_point.name,
        "hooks": []
    }

    # Collect hook names implemented by this plugin
    try:
        plugin_obj = entry_point.load()
        if hasattr(plugin_obj, "__dict__"):
            plugin_data["hooks"] = [
                attr_name for attr_name in dir(plugin_obj)
                if not attr_name.startswith("_")
            ]
    except Exception:
        # If the plugin cannot be loaded, keep hooks empty
        pass

    # Add distribution metadata if available
    try:
        dist = entry_point.dist
        if dist is not None:
            plugin_data["version"] = getattr(dist, "version", None)
            plugin_data["project_name"] = getattr(dist, "project_name", None)
    except Exception:
        pass

    plugins_info.append(plugin_data)

return plugins_info

