        )

class WAL:
    def checkpoint(self):
        """
        This function is used to checkpoint the modified data back to the tree and close the Write-Ahead Log (WAL). It first checks if there are any uncommitted data and logs a warning message if there are. Then, it performs a file sync operation on the file descriptor and directory file descriptor. Next, it reads the committed pages from the file and yields each page along with its corresponding data. After that, it closes the file descriptor, deletes the WAL file, and performs a file sync operation on the directory file descriptor if it exists.
        Input-Output Arguments
        :param self: WAL. An instance of the WAL class.
        :return: No return values.
        """
        import os
        import logging

        # If there is nothing to checkpoint, just return.
        if getattr(self, "fd", None) is None:
            return

        # Warn if there are uncommitted changes.
        if getattr(self, "uncommitted", False):
            logging.warning("Checkpointing WAL with uncommitted data present.")

        # Sync WAL file and directory if available.
        try:
            os.fsync(self.fd)
        except OSError:
            pass

        dir_fd = getattr(self, "dir_fd", None)
        if dir_fd is not None:
            try:
                os.fsync(dir_fd)
            except OSError:
                pass

        # Read committed pages from the WAL and apply them.
        # Expected format: iterable of (page, data) pairs.
        committed_pages = getattr(self, "committed_pages", None)
        if committed_pages is None:
            committed_pages = []

        for page, data in committed_pages:
            # If the WAL object provides a way to write back to the tree, use it.
            if hasattr(self, "tree") and hasattr(self.tree, "write_page"):
                self.tree.write_page(page, data)
            elif hasattr(self, "write_page"):
                self.write_page(page, data)

        # Close file descriptor.
        try:
            os.close(self.fd)
        except OSError:
            pass
        self.fd = None

        # Remove WAL file.
        wal_path = getattr(self, "path", None)
        if wal_path:
            try:
                os.remove(wal_path)
            except FileNotFoundError:
                pass

        # Sync directory after deleting WAL file.
        if dir_fd is not None:
            try:
                os.fsync(dir_fd)
            except OSError:
                pass

class Node:
    @classmethod
    def from_page_data(cls, tree_conf: TreeConf, data: bytes,
                       page: int = None) -> 'Node':
        """
        This function creates a Node instance based on the given tree configuration and data. It first extracts the node type from the data and then creates the corresponding Node instance based on the node type.
        Input-Output Arguments
        :param cls: Node. The class of the Node instance to be created.
        :param tree_conf: TreeConf. The tree configuration used to create the Node instance.
        :param data: Bytes. The data used to create the Node instance.
        :param page: Int. The page number associated with the Node instance. Defaults to None.
        :return: Node. The created Node instance based on the node type.
        """
        # Extract node type from the first byte of the page data
        node_type = data[0] if data else None

        # Create the appropriate node instance based on node type
        if node_type == tree_conf.leaf_node_type:
            return LeafNode.from_page_data(tree_conf, data, page)
        elif node_type == tree_conf.internal_node_type:
            return InternalNode.from_page_data(tree_conf, data, page)
        else:
            raise ValueError(f"Unknown node type: {node_type}")

