class Extension:
    def get_config_schema(self):
        """
        This function returns the configuration schema for the Extension class. It first calls the parent class's method to get the base schema, and then adds additional configuration options specific to the Extension class.
        Input-Output Arguments
        :param self: Extension. An instance of the Extension class.
        :return: dict. The configuration schema for the Extension class, including the base schema and additional options.
        """
        # Get the base schema from the parent class, if available
        base_schema = {}
        try:
            base_schema = super().get_config_schema()
        except AttributeError:
            pass

        # Add Extension-specific configuration options
        extension_schema = {
            "type": "object",
            "properties": {
                "enabled": {
                    "type": "boolean",
                    "default": True,
                    "description": "Whether the extension is enabled."
                },
                "name": {
                    "type": "string",
                    "default": "Extension",
                    "description": "Name of the extension."
                }
            },
            "required": []
        }

        # Merge base schema with extension schema
        if isinstance(base_schema, dict):
            merged_schema = dict(base_schema)
            merged_schema.setdefault("properties", {})
            merged_schema["properties"].update(extension_schema["properties"])

            # Preserve or combine required fields
            base_required = set(merged_schema.get("required", []))
            ext_required = set(extension_schema.get("required", []))
            merged_schema["required"] = list(base_required | ext_required)

            # Ensure type is object
            merged_schema["type"] = merged_schema.get("type", "object")
            return merged_schema

        return extension_schema

