    return getattr(obj, name, default)

def _load_json_maybe(path_or_data):
    if path_or_data is None:
        return {}
    if isinstance(path_or_data, (dict, list)):
        return path_or_data
    if isinstance(path_or_data, str):
        try:
            with open(path_or_data, "r", encoding="utf-8") as f:
                return json.load(f)
        except (FileNotFoundError, OSError, json.JSONDecodeError):
            try:
                return json.loads(path_or_data)
            except Exception:
                return {}
    return {}

def _validate_against_schema(data, schema):
    # Lightweight validation: if schema is unavailable, return data unchanged.
    # If schema is a dict with "required" keys, ensure they exist.
    if not isinstance(schema, dict):
        return data
    required = schema.get("required", [])
    if isinstance(required, list):
        for key in required:
            if key not in data:
                data[key] = None
    return data

