class Bar:
    def transpose(self, interval, up=True):
        """
        Transpose the notes in the bar up or down the given interval.

        Input-Output Arguments
        :param self: Bar, an instance of the Bar class.
        :param interval: str, the interval by which to transpose the notes.
        :param up: bool, optional. Determines whether to transpose the notes up or down. If True (default), transpose up. If False, transpose down.
        :return: no return values.
        """
        # If the bar has no notes, nothing to do
        if not hasattr(self, "notes") or self.notes is None:
            return

        # Try to use music21 if available
        try:
            from music21 import interval as m21_interval
        except ImportError:
            raise ImportError("transpose() requires the music21 package.")

        # Create the interval object
        iv = m21_interval.Interval(interval)
        if not up:
            iv = iv.reverse()

        # Transpose each note/chord/rest-like element in the bar
        for i, n in enumerate(self.notes):
            try:
                self.notes[i] = n.transpose(iv)
            except Exception:
                # If an element cannot be transposed, leave it unchanged
                self.notes[i] = n

class Bar:
    def determine_chords(self, shorthand=False):
        """
        This function returns possible chord for each place in the bar.

        Input-Output Arguments
        :param shorthand: bool. Whether or not to use shorthand notation when determining the chords. Defaults to False if not specified.
        :return: List of lists. Each inner list contains the place in the beat and the possible chords for that position in the bar.
        """
        # If the bar has no notes, there are no chords to determine.
        if not hasattr(self, "notes") or not self.notes:
            return []

        # Collect all note positions in the bar.
        # Expected note structure: each note has a "place" and a pitch-like attribute.
        chord_map = {}

        for note in self.notes:
            # Try to get the beat/place of the note
            place = getattr(note, "place", None)
            if place is None:
                continue

            # Try to get pitch information
            pitch = None
            for attr in ("pitch", "note", "name", "value"):
                if hasattr(note, attr):
                    pitch = getattr(note, attr)
                    break

            if pitch is None:
                continue

            chord_map.setdefault(place, []).append(pitch)

        # Build output as list of [place, possible_chords]
        result = []
        for place in sorted(chord_map.keys()):
            pitches = chord_map[place]

            # Remove duplicates while preserving order
            seen = set()
            unique_pitches = []
            for p in pitches:
                if p not in seen:
                    seen.add(p)
                    unique_pitches.append(p)

            # Very simple chord inference:
            # - 3 notes -> treat as a triad
            # - 4 notes -> treat as a seventh chord
            # - otherwise return the pitch collection itself
            if shorthand:
                if len(unique_pitches) >= 3:
                    chord = f"{unique_pitches[0]} chord"
                else:
                    chord = unique_pitches[0] if unique_pitches else None
            else:
                if len(unique_pitches) == 3:
                    chord = f"Triad: {', '.join(map(str, unique_pitches))}"
                elif len(unique_pitches) == 4:
                    chord = f"Seventh chord: {', '.join(map(str, unique_pitches))}"
                else:
                    chord = ", ".join(map(str, unique_pitches))

            result.append([place, chord])

        return result

