        Input-Output Arguments
        :param self: Info. An instance of the Info class.
        :return: Optional[datetime]. The creation time of the resource, or None if it is not available.
        """
        if not hasattr(self, "details") or self.details is None:
            raise AttributeError('Info instance has no "details" namespace')

        return getattr(self.details, "created", None)

