class MechInventoryConnector:
    def make_names_data(limit=None):
        """
        This function retrieves Mech SSH information and processes it to create a list of host names and their corresponding data. It iterates through the Mech SSH information, extracts the host names and their data, and appends them to a list. Finally, it returns the list of host names and data.
        Input-Output Arguments
        :param limit: Integer. The maximum number of Mech SSH information to retrieve. Defaults to None.
        :return: List of dictionaries. Each dictionary contains the host name and its corresponding data.
        """
        names_data = []

        # Retrieve Mech SSH information
        mech_ssh_info = MechInventoryConnector.get_mech_ssh_info(limit=limit)

        # Process each entry and build the output list
        for item in mech_ssh_info:
            if isinstance(item, dict):
                host_name = item.get("host_name") or item.get("name") or item.get("hostname")
                data = item.get("data", item)

                if host_name is not None:
                    names_data.append({
                        "host_name": host_name,
                        "data": data
                    })

        return names_data

    src,
    dest,
    user=None,
    group=None,
    mode=None,
    add_deploy_dir=True,
    create_remote_dir=True,
    force=False,
    assume_exists=False,
):
    """
    This function uploads a local file or file-like object to a remote system. It allows for specifying various parameters such as the user, group, mode, and destination directory. It also provides options for creating the remote directory if it doesn't exist and forcing the upload even if the remote copy matches.
    Input-Output Arguments
    :param src: The filename or IO-like object to upload.
    :param dest: The remote filename to upload to.
    :param user: The user to own the files.
    :param group: The group to own the files.
    :param mode: The permissions of the files. Use "True" to copy the local file.
    :param add_deploy_dir: Whether the src is relative to the deploy directory.
    :param create_remote_dir: Whether to create the remote directory if it doesn't exist.
    :param force: Whether to always upload the file, even if the remote copy matches.
    :param assume_exists: Whether to assume the local file exists.
    :return: No return values.
    """
    import os
    import shutil
    import hashlib

    def _is_file_like(obj):
        return hasattr(obj, "read")

    def _hash_file(path_or_file):
        h = hashlib.sha1()
        if _is_file_like(path_or_file):
            pos = path_or_file.tell() if hasattr(path_or_file, "tell") else None
            if hasattr(path_or_file, "seek"):
                path_or_file.seek(0)
            while True:
                chunk = path_or_file.read(8192)
                if not chunk:
                    break
                if isinstance(chunk, str):
                    chunk = chunk.encode("utf-8")
                h.update(chunk)
            if hasattr(path_or_file, "seek") and pos is not None:
                path_or_file.seek(pos)
        else:
            with open(path_or_file, "rb") as f:
                for chunk in iter(lambda: f.read(8192), b""):
                    h.update(chunk)
        return h.hexdigest()

    # Resolve source path if needed
    if add_deploy_dir and isinstance(src, str) and not os.path.isabs(src):
        src = os.path.abspath(src)

    # Basic existence check for local file paths
    if not assume_exists and isinstance(src, str) and not os.path.exists(src):
        raise FileNotFoundError(f"Source file does not exist: {src}")

    # Ensure destination directory exists if requested
    dest_dir = os.path.dirname(dest)
    if create_remote_dir and dest_dir:
        os.makedirs(dest_dir, exist_ok=True)

    # If destination exists and force is False, skip if contents match
    if not force and isinstance(src, str) and os.path.exists(dest):
        try:
            if _hash_file(src) == _hash_file(dest):
                return
        except Exception:
            pass

    # Perform the copy
    if _is_file_like(src):
        if hasattr(src, "seek"):
            src.seek(0)
        with open(dest, "wb") as f:
            shutil.copyfileobj(src, f)
    else:
        shutil.copy2(src, dest)

    # Apply mode if provided
    if mode is not None:
        os.chmod(dest, mode)

    # Ownership changes are platform-dependent and may require privileges.
    # They are intentionally ignored here if not supported.
    if user is not None or group is not None:
        try:
            import pwd
            import grp

            uid = pwd.getpwnam(user).pw_uid if user is not None else -1
            gid = grp.getgrnam(group).gr_gid if group is not None else -1
            os.chown(dest, uid, gid)
        except Exception:
            pass

