    path,
    present=True,
    user=None,
    group=None,
    mode=None,
    touch=False,
    create_remote_dir=True,
    force=False,
    force_backup=True,
    force_backup_dir=None,
):
    """
    This function is used to add, remove, or update files. It performs different actions based on the input parameters. It can create a file, remove a file, or update the properties of an existing file.
    Input-Output Arguments
    :param path: String. The name or path of the remote file.
    :param present: Bool. Whether the file should exist. If set to False, the file will be removed if it exists.
    :param user: String. The user to own the files.
    :param group: String. The group to own the files.
    :param mode: Integer. The permissions of the files.
    :param touch: Bool. Whether to touch the file.
    :param create_remote_dir: Bool. Whether to create the remote directory if it doesn't exist.
    :param force: Bool. If the target exists and is not a file, move or remove it and continue.
    :param force_backup: Bool. Whether to remove any existing non-file when force=True.
    :param force_backup_dir: String. The directory to move any backup to when force=True.
    :return: No return values.
    """
    import os
    import shutil
    import stat

    def _is_file(p):
        return os.path.exists(p) and os.path.isfile(p)

    def _ensure_parent_dir(p):
        parent = os.path.dirname(os.path.abspath(p))
        if parent and not os.path.exists(parent):
            if create_remote_dir:
                os.makedirs(parent, exist_ok=True)
            else:
                raise FileNotFoundError(f"Parent directory does not exist: {parent}")

    def _apply_metadata(p):
        if user is not None or group is not None:
            try:
                import pwd
                import grp

                uid = pwd.getpwnam(user).pw_uid if user is not None else -1
                gid = grp.getgrnam(group).gr_gid if group is not None else -1
                os.chown(p, uid, gid)
            except Exception:
                # Ignore ownership errors in environments where chown is not permitted
                pass

        if mode is not None:
            try:
                os.chmod(p, mode if isinstance(mode, int) else int(str(mode), 8))
            except Exception:
                pass

    # Remove file if requested
    if not present:
        if os.path.exists(path):
            if os.path.isdir(path) and not os.path.islink(path):
                shutil.rmtree(path)
            else:
                os.remove(path)
        return

    # Ensure parent directory exists
    _ensure_parent_dir(path)

    # Handle existing non-file target
    if os.path.exists(path) and not _is_file(path):
        if not force:
            raise IsADirectoryError(f"Target exists and is not a file: {path}")

        backup_target = None
        if force_backup_dir:
            os.makedirs(force_backup_dir, exist_ok=True)
            backup_target = os.path.join(
                force_backup_dir, os.path.basename(path)
            )
        elif force_backup:
            backup_target = path + ".bak"

        if backup_target:
            if os.path.exists(backup_target):
                if os.path.isdir(backup_target) and not os.path.islink(backup_target):
                    shutil.rmtree(backup_target)
                else:
                    os.remove(backup_target)
            shutil.move(path, backup_target)
        else:
            if os.path.isdir(path) and not os.path.islink(path):
                shutil.rmtree(path)
            else:
                os.remove(path)

    # Create or touch file
    if touch or not os.path.exists(path):
        with open(path, "a"):
            os.utime(path, None)

    # Apply metadata if file exists
    if os.path.exists(path):
        _apply_metadata(path)

