def connect_host(host):
    try:
        # Determine whether the host is already connected/active
        is_connected = False
        if isinstance(host, dict):
            is_connected = host.get("connected", False) or host.get("active", False) or host.get("online", False)
        else:
            is_connected = (
                getattr(host, "connected", False)
                or getattr(host, "active", False)
                or getattr(host, "online", False)
            )

        # If not connected, attempt to connect using a common method name
        if not is_connected:
            if isinstance(host, dict):
                connect_fn = host.get("connect")
                if callable(connect_fn):
                    connect_fn()
                host["connected"] = True
                host["active"] = True
                host["online"] = True
            else:
                connect_fn = getattr(host, "connect", None)
                if callable(connect_fn):
                    connect_fn()
                setattr(host, "connected", True)
                setattr(host, "active", True)
                setattr(host, "online", True)

        # Update state/inventory safely if needed
        with lock:
            if isinstance(host, dict):
                host["connected"] = True
                host["active"] = True
                host["online"] = True
            else:
                setattr(host, "connected", True)
                setattr(host, "active", True)
                setattr(host, "online", True)

    except Exception:
        # Keep going even if one host fails
        pass

threads = []
