class _VizTracer:
    def stop(self) -> None:
        """
        Stop the VizTracer instance. It disables the tracer, restores the print function if the log print is True, and stops the tracer.
        Input-Output Arguments
        :param self: _VizTracer. An instance of the _VizTracer class.
        :return: No return values.
        """
        # Disable tracing
        if hasattr(self, "enable"):
            self.enable = False

        # Restore original print if it was replaced for logging
        if getattr(self, "log_print", False) and hasattr(self, "_orig_print"):
            import builtins
            builtins.print = self._orig_print

        # Stop the tracer if a stop method exists
        if hasattr(self, "_stop"):
            self._stop()
        elif hasattr(self, "stop_tracing"):
            self.stop_tracing()

