        :param self: _VizTracer. An instance of the _VizTracer class.
        :return: No return values.
        """
        self.enable = True
        self.parsed = False

        if getattr(self, "log_print", False):
            self._overload_print()

        included_files = getattr(self, "included_files", None)
        excluded_files = getattr(self, "excluded_files", None)
        if included_files and excluded_files:
            raise ValueError("included_files and excluded_files cannot both be specified")

        if hasattr(self, "config") and self.config is not None:
            self.config.enable()

        if hasattr(self, "tracer") and self.tracer is not None:
            self.tracer.start()

