class HadoopJobRunner:
    def _find_binaries_and_jars(self):
        """
        This function is used to find the necessary Hadoop and Spark binaries and jars before continuing with the job. It triggers the loading of the Hadoop binary and checks if there are Hadoop streaming steps or Spark steps in the job. If there are, it also loads the Hadoop streaming jar and the Spark submit binary.
        Input-Output Arguments
        :param self: HadoopJobRunner. An instance of the HadoopJobRunner class.
        :return: No return values.
        """
        # Find Hadoop binary
        if hasattr(self, "_find_hadoop_binary"):
            self._find_hadoop_binary()

        # Determine whether the job contains Hadoop streaming or Spark steps
        has_hadoop_streaming = False
        has_spark = False

        if hasattr(self, "steps") and self.steps:
            for step in self.steps:
                step_type = None

                if isinstance(step, dict):
                    step_type = step.get("type") or step.get("step_type") or step.get("name")
                else:
                    step_type = getattr(step, "type", None) or getattr(step, "step_type", None) or getattr(step, "name", None)

                if step_type is None:
                    continue

                step_type_str = str(step_type).lower()

                if "streaming" in step_type_str:
                    has_hadoop_streaming = True
                if "spark" in step_type_str:
                    has_spark = True

        # Load Hadoop streaming jar if needed
        if has_hadoop_streaming and hasattr(self, "_find_hadoop_streaming_jar"):
            self._find_hadoop_streaming_jar()

        # Load Spark submit binary if needed
        if has_spark and hasattr(self, "_find_spark_submit_binary"):
            self._find_spark_submit_binary()

class HadoopJobRunner:
    def _stream_history_log_dirs(self, output_dir=None):
        """
        This function yields lists of directories to search for the history log in. It first checks if logs should be read, and then iterates over unique log directories obtained from the hadoop log directories. If the directory exists, it logs an info message: 'Looking for history log in {directory}...'. It then yields a list containing the directory.
        Input-Output Arguments
        :param self: HadoopJobRunner. An instance of the HadoopJobRunner class.
        :param output_dir: str. The output directory to search for the history log. Defaults to None.
        :return: Generator. Yields lists of directories to search for the history log in.
        """
        # If logs should not be read, stop immediately.
        if not getattr(self, "read_logs", True):
            return

        seen = set()

        # Collect candidate directories from Hadoop log directories and optional output_dir.
        candidate_dirs = []

        if output_dir:
            candidate_dirs.append(output_dir)

        # Try to obtain Hadoop log directories from the instance.
        hadoop_log_dirs = getattr(self, "hadoop_log_dirs", None)
        if callable(hadoop_log_dirs):
            candidate_dirs.extend(hadoop_log_dirs())
        elif hadoop_log_dirs:
            candidate_dirs.extend(hadoop_log_dirs)

        # Yield each unique existing directory.
        for directory in candidate_dirs:
            if not directory or directory in seen:
                continue
            seen.add(directory)

            if hasattr(self, "fs") and hasattr(self.fs, "exists"):
                exists = self.fs.exists(directory)
            else:
                import os
                exists = os.path.exists(directory)

            if exists:
                if hasattr(self, "log") and hasattr(self.log, "info"):
                    self.log.info(f"Looking for history log in {directory}...")
                yield [directory]

