        def add_entries(items):
            for item in items:
                if isinstance(item, tuple) and len(item) == 2:
                    name, path = item
                else:
                    path = item
                    name = os.path.basename(path)
                result[name] = path

        if type is None:
            files = getattr(self, "files", [])
            archives = getattr(self, "archives", [])
            add_entries(files)
            add_entries(archives)
        elif type == "file":
            add_entries(getattr(self, "files", []))
        elif type == "archive":
            add_entries(getattr(self, "archives", []))
        else:
            raise ValueError('type must be either "archive", "file", or None')

        return result

