# Normalize stderr into a list of text lines
if hasattr(stderr, "read"):
    stderr = stderr.read()

if isinstance(stderr, bytes):
    stderr = stderr.decode("utf-8", errors="replace")

if isinstance(stderr, str):
    lines = stderr.splitlines()
else:
    # assume iterable of lines/bytes
    lines = []
    for line in stderr:
        if isinstance(line, bytes):
            line = line.decode("utf-8", errors="replace")
        lines.append(line.rstrip("\n\r"))

statuses = []
other = []

# Common MRJob stderr patterns:
#   reporter:counter:Group,Counter,1
#   reporter:status:some message
counter_re = re.compile(r"^reporter:counter:([^,]+),([^,]+),(-?\d+)\s*$")
status_re = re.compile(r"^reporter:status:(.*)$")

for line in lines:
    m = counter_re.match(line)
    if m:
        group, name, value = m.group(1), m.group(2), int(m.group(3))
        counters.setdefault(group, {})
        counters[group][name] = counters[group].get(name, 0) + value
        continue

    m = status_re.match(line)
    if m:
        statuses.append(m.group(1).strip())
        continue

    other.append(line)

return {
    "counters": counters,
    "statuses": statuses,
    "other": other,
}

import re

app_id = None
errors = []

# Common Spark application ID pattern: application_1234567890123_0001
app_id_re = re.compile(r"\b(application_\d+_\d+)\b")

# Basic error detection patterns
error_start_re = re.compile(r"(?i)\b(ERROR|FATAL|EXCEPTION)\b")
traceback_re = re.compile(r"^\s+at\s+.*|^Caused by:.*|^Traceback \(most recent call last\):")

current_error = None

def emit(record_type, payload):
    if record_callback is not None:
        record_callback(record_type, payload)

for raw_line in lines:
    line = raw_line.rstrip("\n")

    # Extract application ID if present
    if app_id is None:
        m = app_id_re.search(line)
        if m:
            app_id = m.group(1)
            emit("application_id", app_id)

    # Start of a new error block
    if error_start_re.search(line):
        if current_error is not None:
            errors.append(current_error)
            emit("error", current_error)
        current_error = {
            "message": line,
            "details": []
        }
        continue

    # Continuation of an error block
    if current_error is not None:
        if traceback_re.search(line) or line.startswith("\t") or line.startswith(" "):
            current_error["details"].append(line)
        else:
            errors.append(current_error)
            emit("error", current_error)
            current_error = None

# Flush any pending error
if current_error is not None:
    errors.append(current_error)
    emit("error", current_error)

return {
    "application_id": app_id,
    "errors": errors,
}

