# from successful tasks.
if "counters" not in result and task_to_counters:
    result["counters"] = task_to_counters

return result

if not errors:
    return []

attempt_to_container_id = attempt_to_container_id or {}
merged = {}

for error in errors:
    if not isinstance(error, dict):
        continue

    # Try to determine a stable merge key
    container_id = error.get("container_id")

    if container_id is None:
        attempt_id = error.get("attempt_id")
        if attempt_id is not None:
            container_id = attempt_to_container_id.get(attempt_id)

    if container_id is None:
        # Fall back to a time-based key if no container/attempt mapping exists
        time_key = error.get("time") or error.get("timestamp") or error.get("created_at")
        container_id = f"time:{time_key}" if time_key is not None else f"error:{id(error)}"

    # Merge errors by key, keeping the most recent one if possible
    if container_id in merged:
        existing = merged[container_id]
        existing_time = existing.get("time") or existing.get("timestamp") or existing.get("created_at")
        new_time = error.get("time") or error.get("timestamp") or error.get("created_at")

        if new_time is not None and (existing_time is None or new_time >= existing_time):
            merged[container_id] = error
    else:
        merged[container_id] = error

def sort_key(err):
    # Prioritize task errors, then sort by recency descending
    is_task_error = 0 if err.get("type") == "task" or err.get("error_type") == "task" else 1
    t = err.get("time") or err.get("timestamp") or err.get("created_at") or 0
    return (is_task_error, -t if isinstance(t, (int, float)) else 0)

return sorted(merged.values(), key=sort_key)

class HadoopFilesystem:
    def exists(self, path_glob):
        """
        Check if the given path exists in the Hadoop filesystem. If the path is a directory (ends with a '/'), it checks if there are any files starting with that path. It invokes Hadoop 'fs -ls' command to check if the path exists. If the command returns 0, it returns True. If the command returns -1 or 255, it returns False. If the command returns any other value or the stderr has any output except for 'No such file', it raises an IOError: 'Could not check path {path}'.
        Input-Output Arguments
        :param self: HadoopFilesystem. An instance of the HadoopFilesystem class.
        :param path_glob: str. The path to check in the Hadoop filesystem.
        :return: bool. True if the path exists, False otherwise.
        """
        import subprocess

        path = path_glob
        if path.endswith("/"):
            path = path.rstrip("/") + "/*"

        cmd = ["hadoop", "fs", "-ls", path]

        try:
            proc = subprocess.Popen(
                cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True
            )
            stdout, stderr = proc.communicate()
            return_code = proc.returncode
        except Exception as e:
            raise IOError(f"Could not check path {path_glob}") from e

        if return_code == 0:
            return True
        elif return_code in (-1, 255):
            if stderr and stderr.strip() and "No such file" not in stderr:
                raise IOError(f"Could not check path {path_glob}")
            return False
        else:
            if stderr and stderr.strip() and "No such file" not in stderr:
                raise IOError(f"Could not check path {path_glob}")
            raise IOError(f"Could not check path {path_glob}")

class LocalFilesystem:
    def ls(self, path_glob):
        """
        List all the files and directories in the given path. It first converts the input path from a file URI to a regular path. Then, it checks if the path is a directory. If it is, it recursively walks through all the subdirectories and yields the file paths. If it is not a directory, it simply yields the path. The returned paths are in file URI format.
        Input-Output Arguments
        :param self: LocalFilesystem. An instance of the LocalFilesystem class.
        :param path_glob: String. The path or file URI to list files and directories from.
        :return: String. Yields the paths of all files and directories in the given path.
        """
        import os
        from urllib.parse import urlparse, unquote

        def to_local_path(p):
            if p.startswith("file://"):
                parsed = urlparse(p)
                return unquote(parsed.path)
            return p

        def to_file_uri(p):
            return "file://" + os.path.abspath(p)

        path = to_local_path(path_glob)

        if os.path.isdir(path):
            for root, dirs, files in os.walk(path):
                for d in dirs:
                    yield to_file_uri(os.path.join(root, d))
                for f in files:
                    yield to_file_uri(os.path.join(root, f))
        else:
            if os.path.exists(path):
                yield to_file_uri(path)

class Filesystem:
    def cat(self, path_glob):
        """
        This function reads and concatenates the contents of all files that match the given path pattern. It decompresses the files if necessary. The function yields the contents of the files as bytes, yields `b''` between each file.
        Input-Output Arguments
        :param self: Filesystem. An instance of the Filesystem class.
        :param path_glob: String. The path pattern to match the files.
        :return: No return values. The function yields the contents of the files as bytes.
        """
        import glob
        import gzip
        import bz2
        import lzma
        import os

        def _open_file(path):
            if path.endswith(".gz"):
                return gzip.open(path, "rb")
            if path.endswith(".bz2"):
                return bz2.open(path, "rb")
            if path.endswith(".xz") or path.endswith(".lzma"):
                return lzma.open(path, "rb")
            return open(path, "rb")

        for i, path in enumerate(sorted(glob.glob(path_glob))):
            if i > 0:
                yield b""

            with _open_file(path) as f:
                while True:
                    chunk = f.read(8192)
                    if not chunk:
                        break
                    yield chunk

class MmapedDict:
    def read_value(self, key):
        """
        Read the value corresponding to the given key from the MmapedDict instance. If the key is not found in the instance, it initializes the value and then returns it.
        Input-Output Arguments
        :param self: MmapedDict. An instance of the MmapedDict class.
        :param key: The key to read the value from the instance.
        :return: The value corresponding to the key.
        """
        # If the underlying storage doesn't exist yet, create it.
        if not hasattr(self, "_data") or self._data is None:
            self._data = {}

        # Return existing value if present; otherwise initialize it.
        if key not in self._data:
            self._data[key] = None

        return self._data[key]

class MultiProcessCollector:
    def merge(files, accumulate=True):
        """
        Merge metrics from given mmap files. By default, histograms are accumulated, but if writing the merged data back to mmap files, use accumulate=False to avoid compound accumulation.
        Input-Output Arguments
        :param files: List of str. The mmap files to merge metrics from.
        :param accumulate: Bool. Whether to accumulate histograms. Defaults to True.
        :return: The merged metrics.
        """
        import os
        import json
        from collections import defaultdict

        merged = defaultdict(lambda: {"value": 0, "labels": {}, "type": None})

        for file_path in files:
            if not os.path.exists(file_path):
                continue

            with open(file_path, "r") as f:
                try:
                    data = json.load(f)
                except Exception:
                    continue

            # Expected format:
            # {
            #   "metric_name": {
            #       "type": "counter" | "gauge" | "histogram",
            #       "value": number,
            #       "labels": {...}
            #   }
            # }
            for metric_name, metric_data in data.items():
                if not isinstance(metric_data, dict):
                    continue

                metric_type = metric_data.get("type")
                metric_value = metric_data.get("value", 0)
                metric_labels = metric_data.get("labels", {})

                if merged[metric_name]["type"] is None:
                    merged[metric_name]["type"] = metric_type
                    merged[metric_name]["labels"] = metric_labels

                if metric_type == "histogram" and not accumulate:
                    # Keep the latest histogram value without accumulating.
                    merged[metric_name]["value"] = metric_value
                else:
                    merged[metric_name]["value"] += metric_value

        return dict(merged)

class MacVendorDB:
    def lookup(self, mac):
        """
        This function looks up the manufacturer name based on the MAC address provided. It takes a MAC address as input, converts it to uppercase and removes the colons. It then checks if the first 6 characters (':' removed) of the MAC address match any prefix in the database. If there is a match, it returns the corresponding manufacturer name.
        Input-Output Arguments
        :param self: MacVendorDB. An instance of the MacVendorDB class.
        :param mac: String. The MAC address to lookup the manufacturer for.
        :return: String. The manufacturer name corresponding to the MAC address. If no match is found, an empty string is returned.
        """
        if not mac:
            return ""

        mac = mac.upper().replace(":", "")
        prefix = mac[:6]

        # Try common storage patterns for the vendor database
        if hasattr(self, "db") and isinstance(self.db, dict):
            return self.db.get(prefix, "")

        if hasattr(self, "vendors") and isinstance(self.vendors, dict):
            return self.vendors.get(prefix, "")

        if hasattr(self, "vendor_db") and isinstance(self.vendor_db, dict):
            return self.vendor_db.get(prefix, "")

        return ""

import json

def parse_policy_document(stream):
    """
    This function takes a stream of JSON data and parses it into a PolicyDocument object. It first checks if the stream is a string, and if so, it loads the JSON data into a dictionary. Otherwise, it loads the JSON data as file stream. Finally, it creates a PolicyDocument object using the parsed statements and version from the JSON dictionary.
    Input-Output Arguments
    :param stream: The input stream of JSON data.
    :return: PolicyDocument. The parsed PolicyDocument object.
    """
    if isinstance(stream, str):
        data = json.loads(stream)
    else:
        data = json.load(stream)

    return PolicyDocument(
        statements=data.get("Statement", []),
        version=data.get("Version")
    )

import os
import sys
import optparse

# Keep only application-specific options from argv
app_argv = [argv[0]]
for arg in argv[1:]:
    if arg.startswith("--"):
        app_argv.append(arg)

# First parse only to discover the config file
parser = optparse.OptionParser(prog=prog_name)
parser.add_option("--conf", dest="conf", default=None)

try:
    opts, _ = parser.parse_args(app_argv[1:])
except SystemExit:
    # If parsing fails here, just re-raise
    raise

conf_file = opts.conf

# Default config file name used to decide whether to ignore IOError
default_conf = os.path.join(os.path.dirname(sys.argv[0]), f"{prog_name}.conf")

# If a config file is specified, try to parse it first
if conf_file:
    try:
        if os.path.exists(conf_file):
            with open(conf_file, "r") as f:
                # Parse config file as command-line style options
                conf_args = []
                for line in f:
                    line = line.strip()
                    if not line or line.startswith("#"):
                        continue
                    conf_args.extend(line.split())

                # Re-parse with config options first, then command line overrides
                parser.parse_args(conf_args + app_argv[1:])
        else:
            raise IOError(f"Configuration file not found: {conf_file}")
    except IOError:
        # Ignore missing/default config file errors only when it is the default config
        if os.path.basename(conf_file) != os.path.basename(default_conf):
            raise
else:
    # No config file specified; just parse the command line normally
    parser.parse_args(app_argv[1:])

import os

def discover_files(targets, excluded_files, recursive=False):
    """
    This function discovers files based on the given targets and excluded files. It searches for files with the extension ".py" in the target directories and appends them to the included_files list. It also logs the discovered files debug mode ('Discovered file: %s').
    Input-Output Arguments
    :param targets: List of strings. The target directories or files to search for files.
    :param excluded_files: String. A comma-separated list of files to exclude from the search.
    :param recursive: Bool. Whether to search for files recursively in subdirectories. Defaults to False.
    :return: List of strings. The list of discovered files.
    """
    included_files = []
    excluded_set = {
        os.path.abspath(f.strip())
        for f in excluded_files.split(",")
        if f.strip()
    } if excluded_files else set()

    for target in targets:
        if not target:
            continue

        target = os.path.abspath(target)

        # If target is a file, include it if it is a .py file and not excluded
        if os.path.isfile(target):
            if target.endswith(".py") and target not in excluded_set:
                included_files.append(target)
                print("Discovered file: %s" % target)
            continue

        # If target is a directory, walk it
        if os.path.isdir(target):
            if recursive:
                for root, _, files in os.walk(target):
                    for filename in files:
                        if filename.endswith(".py"):
                            filepath = os.path.abspath(os.path.join(root, filename))
                            if filepath not in excluded_set:
                                included_files.append(filepath)
                                print("Discovered file: %s" % filepath)
            else:
                for filename in os.listdir(target):
                    filepath = os.path.abspath(os.path.join(target, filename))
                    if os.path.isfile(filepath) and filename.endswith(".py"):
                        if filepath not in excluded_set:
                            included_files.append(filepath)
                            print("Discovered file: %s" % filepath)

    return included_files

