            sanitiser_names.add(sink.sanitiser)
        elif hasattr(sink, "sanitizer") and sink.sanitizer:
            sanitiser_names.add(sink.sanitizer)

    # Traverse CFG and collect matching sanitiser nodes
    # Support common CFG shapes: iterable of nodes, or object with nodes()/get_nodes()
    if hasattr(cfg, "nodes") and callable(cfg.nodes):
        cfg_nodes = cfg.nodes()
