        cfg_nodes = cfg

    for node in cfg_nodes:
        node_name = None

        # Try common attribute names for node/function name
        for attr in ("name", "label", "func_name", "function_name", "callee", "call_name"):
            if hasattr(node, attr):
                node_name = getattr(node, attr)
