from typing import Optional

def _statement_matches_resource(
    statement: dict,
    resource: str,
    condition_keys: Optional[CaseInsensitiveDict] = None
) -> bool:
    """
    This function is a helper function that checks if a given resource is present in a policy statement. It checks if the resource matches any of the resources listed in the 'Resource' field of the statement. If it does, it returns True. If 'Resource' not in statement and the 'NotResource' field is present, it checks if the resource matches any of the resources listed in that field. If it does, it returns False. If neither 'Resource' nor 'NotResource' fields are present, it returns True.
    Input-Output Arguments
    :param statement: dict. The policy statement to check.
    :param resource: str. The resource to check for.
    :param condition_keys: Optional[CaseInsensitiveDict]. A dictionary of condition keys. Defaults to None.
    :return: bool. True if the resource is in the policy statement, False otherwise.
    """
    import fnmatch

    def _as_list(value):
        if value is None:
            return []
        if isinstance(value, list):
            return value
        return [value]

    def _matches(pattern: str, value: str) -> bool:
        # IAM-style wildcard matching
        return fnmatch.fnmatchcase(value, pattern)

    # If Resource is present, the statement applies only if the resource matches one of them.
    if "Resource" in statement:
        resources = _as_list(statement["Resource"])
        return any(_matches(pattern, resource) for pattern in resources)

    # If NotResource is present, the statement applies unless the resource matches one of them.
    if "NotResource" in statement:
        not_resources = _as_list(statement["NotResource"])
        return not any(_matches(pattern, resource) for pattern in not_resources)

    # If neither is present, the statement applies to all resources.
    return True

class Ingestor:
    def run(self):
        """
        This function runs the Ingestor instance either once or forever, depending on the configuration. If the configuration specifies to run as a daemon, it runs the instance in a loop. Otherwise, it runs the instance once to completion.
        Input-Output Arguments
        :param self: Ingestor. An instance of the Ingestor class.
        :return: No return values.
        """
        if getattr(self, "daemon", False):
            while True:
                self.ingest()
        else:
            self.ingest()

from typing import List, Union
import math

def compute_likelihood_windows_in_session(
    session: List[str],
    prior_probs: Union["StateMatrix", dict],
    trans_probs: Union["StateMatrix", dict],
    window_len: int,
    use_start_end_tokens: bool,
    start_token: str = None,
    end_token: str = None,
    use_geo_mean: bool = False,
) -> List[float]:
    """
    This function computes the likelihoods of a sliding window of commands in a session.
    It iterates through the session and calculates the likelihood of each window based on
    the prior probabilities and transition probabilities.
    """
    if window_len <= 0:
        raise ValueError("window_len must be a positive integer")

    # Optionally add start/end tokens
    seq = list(session)
    if use_start_end_tokens:
        if start_token is None or end_token is None:
            raise ValueError("start_token and end_token must be provided when use_start_end_tokens=True")
        seq = [start_token] + seq + [end_token]

    # Not enough commands for even one window
    if len(seq) < window_len:
        return []

    def get_prob(matrix, row, col=None):
        """
        Supports either:
        - dict of dicts: matrix[row][col]
        - dict: matrix[row] when col is None
        - StateMatrix-like objects with .get(row, col) or indexing
        """
        if isinstance(matrix, dict):
            if col is None:
                return matrix.get(row, 0.0)
            return matrix.get(row, {}).get(col, 0.0)

        # Fallback for custom matrix types
        if col is None:
            try:
                return matrix[row]
            except Exception:
                return 0.0
        try:
            return matrix[row, col]
        except Exception:
            try:
                return matrix.get(row, col)
            except Exception:
                return 0.0

    likelihoods = []

    for i in range(len(seq) - window_len + 1):
        window = seq[i : i + window_len]

        # Likelihood of first item in the window from prior
        likelihood = get_prob(prior_probs, window[0])

        # Multiply by transition probabilities through the window
        for j in range(1, len(window)):
            likelihood *= get_prob(trans_probs, window[j - 1], window[j])

        if use_geo_mean:
            likelihood = likelihood ** (1.0 / window_len)

        likelihoods.append(likelihood)

    return likelihoods

    session: List[Cmd],
    prior_probs: StateMatrix,
    trans_probs: StateMatrix,
    param_cond_cmd_probs: StateMatrix,
    window_len: int,
    use_start_end_tokens: bool,
    start_token: str,
    end_token: str,
    use_geo_mean=False,
) -> Tuple[List[Cmd], float]:

    """
    This function finds and computes the likelihood of the rarest window of a given length in a session. It calculates the likelihoods of all sliding windows in the session and returns the rarest window and its likelihood.
    Input-Output Arguments
    :param session: List[Cmd]. A list of Cmd objects representing a session.
    :param prior_probs: Union[StateMatrix, dict]. Computed probabilities of individual commands.
    :param trans_probs: Union[StateMatrix, dict]. Computed probabilities of sequences of commands (length 2).
    :param param_cond_cmd_probs: Union[StateMatrix, dict]. Computed probabilities of the params conditional on the command.
    :param window_len: int. The length of the sliding window for likelihood calculations.
    :param use_start_end_tokens: bool. If True, the `start_token` and `end_token` will be added to the session before calculations.
    :param start_token: str. A dummy command to signify the start of the session.
    :param end_token: str. A dummy command to signify the end of the session.
    :param use_geo_mean: bool. If True, each likelihood of the sliding windows will be raised to the power of (1/`window_len`).
    :return: Tuple[List[Cmd], float]. The rarest window part of the session and the likelihood of the rarest window.
    """
    import math

    if window_len <= 0:
        raise ValueError("window_len must be positive")

    # Optionally pad session with start/end tokens
    if use_start_end_tokens:
        session = [Cmd(start_token)] + list(session) + [Cmd(end_token)]
    else:
        session = list(session)

    if len(session) < window_len:
        return [], 0.0

    def _cmd_name(cmd):
        # Support Cmd objects with either `.cmd` or `.name`, or plain strings
        if isinstance(cmd, str):
            return cmd
        return getattr(cmd, "cmd", getattr(cmd, "name", str(cmd)))

    def _cmd_params(cmd):
        # Best-effort extraction of params; if unavailable, assume no params
        if isinstance(cmd, str):
            return []
        return getattr(cmd, "params", getattr(cmd, "args", [])) or []

    def _lookup(matrix, key, default=0.0):
        if matrix is None:
            return default
        if isinstance(matrix, dict):
            return matrix.get(key, default)
        # StateMatrix-like access
        try:
            return matrix[key]
        except Exception:
            return default

    def _cmd_prob(cmd):
        name = _cmd_name(cmd)
        p = _lookup(prior_probs, name, 0.0)
        # Multiply by conditional parameter probabilities if available
        params = _cmd_params(cmd)
        if params:
            for param in params:
                p *= _lookup(param_cond_cmd_probs, (name, param), 0.0)
        return p

    def _trans_prob(cmd1, cmd2):
        return _lookup(trans_probs, (_cmd_name(cmd1), _cmd_name(cmd2)), 0.0)

    best_window = session[:window_len]
    best_likelihood = -1.0

    for i in range(len(session) - window_len + 1):
        window = session[i : i + window_len]

        # Likelihood = prior of first cmd * transitions between consecutive cmds
        likelihood = _cmd_prob(window[0])
        for j in range(1, len(window)):
            likelihood *= _trans_prob(window[j - 1], window[j])
            likelihood *= _cmd_prob(window[j])

        if use_geo_mean:
            likelihood = likelihood ** (1.0 / window_len) if likelihood > 0 else 0.0

        if best_likelihood < 0 or likelihood < best_likelihood:
            best_likelihood = likelihood
            best_window = window

    return best_window, best_likelihood

    param_counts: Union[StateMatrix, dict], param_value_counts: Union[StateMatrix, dict]
) -> set:
    """
    This function determines which parameters should be modeled as categorical variables based on heuristics.
    It calculates the statistics of each parameter and its corresponding values, and then selects the
    parameters that meet certain criteria.

    Input-Output Arguments
    :param param_counts: Union[StateMatrix, dict]. The counts of each individual parameter.
    :param param_value_counts: Union[StateMatrix, dict]. The counts of each value conditional on the parameters.
    :return: set. A set of parameters that have been determined to be categorical.
    """
    import math

    # Helper to support either dict-like or StateMatrix-like inputs
    def _items(obj):
        if isinstance(obj, dict):
            return obj.items()
        if hasattr(obj, "items"):
            return obj.items()
        raise TypeError("Unsupported input type for counts object.")

    def _get(obj, key, default=None):
        if isinstance(obj, dict):
            return obj.get(key, default)
        if hasattr(obj, "get"):
            return obj.get(key, default)
        return default

    params_to_model_values = set()

    # Heuristic thresholds
    min_param_count = 2
    min_unique_values = 3
    max_dominant_value_ratio = 0.95

    for param, count in _items(param_counts):
        if count is None or count < min_param_count:
            continue

        value_counts = _get(param_value_counts, param, {})
        if value_counts is None:
            continue

        # Support nested dicts or similar mappings
        if hasattr(value_counts, "values"):
            counts = list(value_counts.values())
        else:
            counts = list(value_counts)

        if not counts:
            continue

        unique_values = len(counts)
        total = sum(counts)

        if total <= 0:
            continue

        dominant_ratio = max(counts) / total if total else 0.0

        # Model as categorical if it has enough distinct values and isn't overwhelmingly dominated
        if unique_values >= min_unique_values and dominant_ratio <= max_dominant_value_ratio:
            params_to_model_values.add(param)

    return params_to_model_values

from typing import List, Union
import math

def compute_likelihood_windows_in_session(
    session: List[Cmd],
    prior_probs: Union[StateMatrix, dict],
    trans_probs: Union[StateMatrix, dict],
    param_cond_cmd_probs: Union[StateMatrix, dict],
    window_len: int,
    use_start_end_tokens: bool,
    start_token: str = None,
    end_token: str = None,
    use_geo_mean: bool = False,
) -> List[float]:

    """
    This function computes the likelihoods of a sliding window in a session. It takes a session, prior probabilities, transition probabilities, parameter conditional command probabilities, window length, start and end tokens, and a flag to indicate whether to use geometric mean. It iterates through the session and calculates the likelihood for each sliding window. If the use_geo_mean flag is set to True, it raises each likelihood to the power of (1/window_len) before appending it to the list of likelihoods.
    Input-Output Arguments
    :param session: List[Cmd]. A list of Cmd objects representing a session.
    :param prior_probs: Union[StateMatrix, dict]. Computed probabilities of individual commands.
    :param trans_probs: Union[StateMatrix, dict]. Computed probabilities of sequences of commands (length 2).
    :param param_cond_cmd_probs: Union[StateMatrix, dict]. Computed probabilities of the parameters conditional on the command.
    :param window_len: int. The length of the sliding window for likelihood calculations.
    :param use_start_end_tokens: bool. If True, start and end tokens will be prepended and appended to the session respectively before the calculations are done.
    :param start_token: str. A dummy command to signify the start of the session. Defaults to None.
    :param end_token: str. A dummy command to signify the end of the session. Defaults to None.
    :param use_geo_mean: bool. If True, each likelihood of the sliding windows will be raised to the power of (1/window_len).
    :return: List[float]. A list of likelihoods.
    """

    def _get_prob(matrix, key1, key2=None, default=0.0):
        if matrix is None:
            return default
        if isinstance(matrix, dict):
            if key2 is None:
                return matrix.get(key1, default)
            return matrix.get(key1, {}).get(key2, default)
        # Fallback for matrix-like objects
        try:
            if key2 is None:
                return matrix[key1]
            return matrix[key1, key2]
        except Exception:
            return default

    def _cmd_name(cmd):
        if isinstance(cmd, str):
            return cmd
        if hasattr(cmd, "name"):
            return cmd.name
        if hasattr(cmd, "cmd"):
            return cmd.cmd
        return str(cmd)

    def _cmd_params(cmd):
        if isinstance(cmd, str):
            return None
        if hasattr(cmd, "params"):
            return cmd.params
        if hasattr(cmd, "arguments"):
            return cmd.arguments
        return None

    # Prepare session with optional boundary tokens
    cmds = list(session)
    if use_start_end_tokens:
        if start_token is not None:
            cmds = [start_token] + cmds
        if end_token is not None:
            cmds = cmds + [end_token]

    if window_len <= 0 or len(cmds) < window_len:
        return []

    likelihoods = []

    for i in range(len(cmds) - window_len + 1):
        window = cmds[i : i + window_len]
        likelihood = 1.0

        for j, cmd in enumerate(window):
            cmd_name = _cmd_name(cmd)
            params = _cmd_params(cmd)

            # Prior probability for the command
            p_cmd = _get_prob(prior_probs, cmd_name, default=0.0)

            # Conditional probability of parameters given command
            p_params = 1.0
            if params is not None:
                if isinstance(params, dict):
                    for param_name, param_val in params.items():
                        # Try nested dict lookup: P(param_val | cmd, param_name)
                        p = _get_prob(param_cond_cmd_probs, cmd_name, param_name, default=None)
                        if isinstance(p, dict):
                            p_params *= p.get(param_val, 0.0)
                        elif p is not None:
                            p_params *= p
                        else:
                            p_params *= 0.0
                else:
                    # If params are not dict-like, treat them as a single value
                    p = _get_prob(param_cond_cmd_probs, cmd_name, default=None)
                    if isinstance(p, dict):
                        p_params *= p.get(params, 0.0)
                    elif p is not None:
                        p_params *= p
                    else:
                        p_params *= 0.0

            # Transition probability from previous command to current command
            p_trans = 1.0
            if j > 0:
                prev_cmd_name = _cmd_name(window[j - 1])
                p_trans = _get_prob(trans_probs, prev_cmd_name, cmd_name, default=0.0)

            # Combine probabilities
            if j == 0:
                likelihood *= p_cmd * p_params
            else:
                likelihood *= p_trans * p_params

        if use_geo_mean:
            likelihood = likelihood ** (1.0 / window_len)

        likelihoods.append(likelihood)

    return likelihoods

    cmd: str,
    params_with_vals: Union[dict, set],
    param_cond_cmd_probs: Union[StateMatrix, dict],
    value_cond_param_probs: Union[StateMatrix, dict],
    modellable_params: Union[set, list],
    use_geo_mean: bool = True,
) -> float:
    """
    This function computes the probability of a set of parameters and their values given a command.
    It takes into account the conditional probabilities of the parameters given the command
    and the conditional probabilities of the values given the parameters. It also includes
    the probabilities of values for modellable parameters in the calculation of the likelihood.
    The function allows for the option to use the geometric mean to compare probabilities
    across different commands with varying numbers of parameters.
    """

    # Normalize input to a dict of {param: value}
    if isinstance(params_with_vals, set):
        params_with_vals = {p: None for p in params_with_vals}

    if params_with_vals is None:
        return 0.0

    modellable_params = set(modellable_params) if modellable_params is not None else set()

    prob = 1.0
    k = 0  # number of factors included in the product

    # 1) Multiply by P(param | cmd) for each parameter present
    for param, val in params_with_vals.items():
        p_param_given_cmd = 0.0

        if isinstance(param_cond_cmd_probs, dict):
            p_param_given_cmd = (
                param_cond_cmd_probs.get(cmd, {}).get(param, 0.0)
                if cmd in param_cond_cmd_probs
                else 0.0
            )
        else:
            # Assume StateMatrix-like access: [cmd][param]
            try:
                p_param_given_cmd = param_cond_cmd_probs[cmd][param]
            except Exception:
                p_param_given_cmd = 0.0

        prob *= p_param_given_cmd
        k += 1

        # 2) If parameter is modellable and a value is provided, multiply by P(value | param)
        if param in modellable_params and val is not None:
            p_val_given_param = 0.0

            if isinstance(value_cond_param_probs, dict):
                p_val_given_param = (
                    value_cond_param_probs.get(param, {}).get(val, 0.0)
                    if param in value_cond_param_probs
                    else 0.0
                )
            else:
                # Assume StateMatrix-like access: [param][value]
                try:
                    p_val_given_param = value_cond_param_probs[param][val]
                except Exception:
                    p_val_given_param = 0.0

            prob *= p_val_given_param
            k += 1

    # Optionally use geometric mean to normalize across different numbers of factors
    if use_geo_mean and k > 0:
        prob = prob ** (1.0 / k)

    return float(prob)

from typing import List, Union
import math

def compute_likelihood_window(
    window: List[Cmd],
    prior_probs: Union[StateMatrix, dict],
    trans_probs: Union[StateMatrix, dict],
    param_cond_cmd_probs: Union[StateMatrix, dict],
    value_cond_param_probs: Union[StateMatrix, dict],
    modellable_params: set,
    use_start_token: bool,
    use_end_token: bool,
    start_token: str = None,
    end_token: str = None,
) -> float:
    """
    This function computes the likelihood of a given window of commands. It calculates the probability of the window based on the prior probabilities, transition probabilities, and conditional probabilities of parameters and values.
    """
    # Build the sequence with optional boundary tokens
    cmds = list(window)
    if use_start_token and start_token is not None:
        cmds = [Cmd(cmd=start_token, params={})] + cmds
    if use_end_token and end_token is not None:
        cmds = cmds + [Cmd(cmd=end_token, params={})]

    if not cmds:
        return 0.0

    def _get_prob(matrix, key1, key2=None, default=0.0):
        """
        Helper to retrieve probabilities from either dict-like or matrix-like objects.
        Supports:
          - matrix[key1]
          - matrix[key1][key2]
          - matrix.get(...)
        """
        try:
            if key2 is None:
                if hasattr(matrix, "get"):
                    return matrix.get(key1, default)
                return matrix[key1]
            else:
                if hasattr(matrix, "get"):
                    row = matrix.get(key1, {})
                    if isinstance(row, dict):
                        return row.get(key2, default)
                    return row[key2]
                return matrix[key1][key2]
        except Exception:
            return default

    likelihood = 1.0

    for i, cmd_obj in enumerate(cmds):
        cmd_name = getattr(cmd_obj, "cmd", cmd_obj)

        # Prior / initial probability
        if i == 0:
            p_cmd = _get_prob(prior_probs, cmd_name, default=0.0)
        else:
            prev_name = getattr(cmds[i - 1], "cmd", cmds[i - 1])
            p_cmd = _get_prob(trans_probs, prev_name, cmd_name, default=0.0)

        likelihood *= p_cmd
        if likelihood == 0.0:
            return 0.0

        # Parameter probabilities conditioned on command
        params = getattr(cmd_obj, "params", {}) or {}
        for param_name, param_value in params.items():
            p_param = _get_prob(param_cond_cmd_probs, cmd_name, param_name, default=1.0)
            likelihood *= p_param
            if likelihood == 0.0:
                return 0.0

            # Value probabilities conditioned on parameter
            if param_name in modellable_params:
                p_value = _get_prob(value_cond_param_probs, param_name, param_value, default=1.0)
                likelihood *= p_value
                if likelihood == 0.0:
                    return 0.0

    return float(likelihood)

    seq1_counts: Union[StateMatrix, dict],
    seq2_counts: Union[StateMatrix, dict],
    unk_token: str,
) -> Tuple[StateMatrix, StateMatrix]:
    """
    This function computes the probabilities for individual commands and the probabilities for the transitions of commands. It takes the counts of individual commands and sequence commands as input and returns the computed probabilities.
    Input-Output Arguments
    :param seq1_counts: Union[StateMatrix, dict]. The counts of individual commands.
    :param seq2_counts: Union[StateMatrix, dict]. The counts of sequence commands (length 2).
    :param unk_token: str. A dummy command to represent unseen commands.
    :return: Tuple[StateMatrix, StateMatrix]. The computed probabilities for individual commands and sequence commands (length 2).
    """
    # Convert dict inputs to StateMatrix if needed
    if isinstance(seq1_counts, dict):
        seq1_counts = StateMatrix(seq1_counts)
    if isinstance(seq2_counts, dict):
        seq2_counts = StateMatrix(seq2_counts)

    # Compute probabilities for single commands
    seq1_probs = StateMatrix()
    total_seq1 = sum(seq1_counts.values())

    if total_seq1 > 0:
        for cmd, count in seq1_counts.items():
            seq1_probs[cmd] = count / total_seq1
    else:
        seq1_probs[unk_token] = 1.0

    # Ensure unk token exists in unigram probabilities
    if unk_token not in seq1_probs:
        seq1_probs[unk_token] = 0.0

    # Compute probabilities for command transitions
    seq2_probs = StateMatrix()
    for prev_cmd, next_cmds in seq2_counts.items():
        if isinstance(next_cmds, dict):
            row_total = sum(next_cmds.values())
            seq2_probs[prev_cmd] = StateMatrix()
            if row_total > 0:
                for next_cmd, count in next_cmds.items():
                    seq2_probs[prev_cmd][next_cmd] = count / row_total
            else:
                seq2_probs[prev_cmd][unk_token] = 1.0
        else:
            # If seq2_counts is flattened or unexpected, preserve structure safely
            seq2_probs[prev_cmd] = next_cmds

        # Ensure unk token exists in each transition row
        if unk_token not in seq2_probs[prev_cmd]:
            seq2_probs[prev_cmd][unk_token] = 0.0

    return seq1_probs, seq2_probs

class QueryParameterEditWidget:
    def delete_parameter(self, button):
        """
        This function deletes a parameter item from the QueryParameterEditWidget instance. It removes the parameter from the parameters dictionary and clears the input widgets. It also sets the changed data flag to True.
        Input-Output Arguments
        :param self: QueryParameterEditWidget. An instance of the QueryParameterEditWidget class.
        :param button: The button that triggered the delete action. It is not used in the function.
        :return: No return values.
        """
        # Remove the parameter from the internal dictionary if it exists
        if hasattr(self, "parameters") and self.current_parameter_name in self.parameters:
            del self.parameters[self.current_parameter_name]

        # Clear input widgets if they exist
        if hasattr(self, "name_input"):
            self.name_input.clear()
        if hasattr(self, "value_input"):
            self.value_input.clear()
        if hasattr(self, "description_input"):
            self.description_input.clear()

        # Mark data as changed
        if hasattr(self, "changed_data"):
            self.changed_data = True

class MSALDelegatedAuth:
    def get_token(self):
        """
        This function is a method of the MSALDelegatedAuth class. It is used to get an authentication token. It first tries to get the chosen account using the app's get_accounts method. If a chosen account is found, it acquires a token with the specified scopes and chosen account. If the result is empty, it then authenticates with the specified authentication type. Finally, it refreshs the token.
        Input-Output Arguments
        :param self: MSALDelegatedAuth. An instance of the MSALDelegatedAuth class.
        :return: No return values.
        """
        result = None

        # Try to use an existing account first
        accounts = self.app.get_accounts()
        if accounts:
            chosen_account = accounts[0]
            result = self.app.acquire_token_silent(self.scopes, account=chosen_account)

        # If no token was found, authenticate interactively/device-code/etc.
        if not result:
            if self.auth_type == "device_code":
                flow = self.app.initiate_device_flow(scopes=self.scopes)
                if "user_code" in flow:
                    print(flow["message"])
                    result = self.app.acquire_token_by_device_flow(flow)
                else:
                    raise RuntimeError("Failed to create device flow")
            elif self.auth_type == "interactive":
                result = self.app.acquire_token_interactive(scopes=self.scopes)
            elif self.auth_type == "username_password":
                result = self.app.acquire_token_by_username_password(
                    self.username,
                    self.password,
                    scopes=self.scopes
                )
            else:
                raise ValueError(f"Unsupported auth_type: {self.auth_type}")

        # Refresh token if needed / possible
        if result and "access_token" in result:
            self.access_token = result["access_token"]
            return self.access_token

        raise RuntimeError(f"Failed to acquire token: {result}")

def display_time(seconds):
    if seconds < 1:
        return "less than a second"
    minute = 60
    hour = minute * 60
    day = hour * 24
    month = day * 31
    year = day * 365

    if seconds < minute:
        return f"{round(seconds)} seconds"
    if seconds < hour:
        return f"{round(seconds / minute)} minutes"
    if seconds < day:
        return f"{round(seconds / hour)} hours"
    if seconds < month:
        return f"{round(seconds / day)} days"
    if seconds < year:
        return f"{round(seconds / month)} months"
    return f"{round(seconds / year)} years"

