def regex_guesses(match):
    """
    This function calculates the number of possible guesses for a given regular expression match.
    It first defines a dictionary of character class bases, which represent the number of possible
    characters in each character class. Then, it checks the type of the regular expression match
    and calculates the number of possible guesses based on the match type.

    :param match: Dictionary. The regular expression match object, which contains information about the match.
    :return: Integer. The number of possible guesses for the given regular expression match.
    """
    if not match:
        return 0

    # Character class sizes / base possibilities
    char_class_bases = {
        "digit": 10,
        "lower": 26,
        "upper": 26,
        "alpha": 52,
        "alnum": 62,
        "word": 63,   # letters + digits + underscore
        "space": 6,
        "any": 95,    # printable ASCII excluding space? kept as a reasonable default
    }

    # If a plain string is passed, treat it as a literal with one possibility
    if isinstance(match, str):
        return 1

    # If a regex match object is passed, use its matched text
    if hasattr(match, "group"):
        text = match.group(0)
    else:
        text = str(match)

    # Heuristic handling for common regex-like tokens
    if text == r"\d":
        return char_class_bases["digit"]
    if text == r"\w":
        return char_class_bases["word"]
    if text == r"\s":
        return char_class_bases["space"]
    if text == r".":
        return char_class_bases["any"]
    if text == r"[a-z]":
        return char_class_bases["lower"]
    if text == r"[A-Z]":
        return char_class_bases["upper"]
    if text == r"[a-zA-Z]":
        return char_class_bases["alpha"]
    if text == r"[a-zA-Z0-9]":
        return char_class_bases["alnum"]

    # If the match is a literal character, there is only one guess
    if len(text) == 1:
        return 1

    # For longer literal strings, assume each character is fixed
    return 1

token = match.get("token", "")

