"""
This function returns a list of supported server authentication methods. It iterates through a list of authentication methods and checks if each method is supported by the server. If a method is supported, it is added to the list of supported methods.
Input-Output Arguments
:param conn: SSHServerConnection. An instance of the SSHServerConnection class.
:return: Sequence[bytes]. A list of supported server authentication methods.
"""
supported_methods = []

# Common SSH authentication methods to probe
auth_methods = [
    b"publickey",
    b"password",
    b"keyboard-interactive",
    b"hostbased",
    b"none",
]

for method in auth_methods:
    try:
        # Prefer a dedicated capability/query method if available
        if hasattr(conn, "supports_auth_method"):
            is_supported = conn.supports_auth_method(method)
        elif hasattr(conn, "is_auth_method_supported"):
            is_supported = conn.is_auth_method_supported(method)
        else:
            # Fallback: inspect advertised auth methods if exposed
            advertised = None
            for attr in ("auth_methods", "supported_auth_methods", "server_auth_methods"):
                if hasattr(conn, attr):
                    advertised = getattr(conn, attr)
                    break

            if advertised is None:
                # If we cannot inspect capabilities, conservatively skip
                is_supported = False
            else:
                if callable(advertised):
                    advertised = advertised()
                is_supported = method in advertised

        if is_supported:
            supported_methods.append(method)
    except Exception:
        # Ignore probing errors and continue with the next method
        continue

return supported_methods

