class SSHPacket:
    def check_end(self) -> None:
        """
        This function checks if all the data in the SSHPacket instance has been consumed. If there is any remaining data, it raises an error.
        Input-Output Arguments
        :param self: SSHPacket. An instance of the SSHPacket class.
        :return: No return values.
        """
        # Commonly, packet parsers track the current read position and the total
        # packet length. If there is unread data left, raise an error.
        if hasattr(self, "pos") and hasattr(self, "data"):
            if self.pos != len(self.data):
                raise ValueError("Unexpected extra data remaining in SSHPacket")
        elif hasattr(self, "offset") and hasattr(self, "data"):
            if self.offset != len(self.data):
                raise ValueError("Unexpected extra data remaining in SSHPacket")
        else:
            # Fallback: if the class uses a different internal representation,
            # try to detect a generic "remaining" indicator.
            remaining = None
            if hasattr(self, "remaining"):
                remaining = self.remaining
            elif hasattr(self, "get_remaining"):
                remaining = self.get_remaining()

            if remaining not in (None, 0, b"", ""):
                raise ValueError("Unexpected extra data remaining in SSHPacket")

class SSHKey:
    def verify(self, data: bytes, sig: bytes) -> bool:
        """
        This function verifies an SSH signature of the specified data using the SSHKey instance. It decodes the signature packet, checks if the signature algorithm is supported, and performs the actual verification.
        Input-Output Arguments
        :param self: SSHKey. An instance of the SSHKey class.
        :param data: bytes. The data to be verified.
        :param sig: bytes. The SSH signature to be verified.
        :return: bool. True if the signature is valid, False otherwise.
        """
        try:
            # If the key object provides its own verification method, use it.
            if hasattr(self, "public_key") and self.public_key is not None:
                pub = self.public_key
            else:
                pub = self

            # Decode SSH signature packet: string algorithm, string signature blob
            # SSH "string" format is 4-byte big-endian length + bytes.
            def _read_ssh_string(buf: bytes, offset: int = 0):
                if offset + 4 > len(buf):
                    raise ValueError("Invalid SSH signature format")
                n = int.from_bytes(buf[offset:offset + 4], "big")
                start = offset + 4
                end = start + n
                if end > len(buf):
                    raise ValueError("Invalid SSH signature format")
                return buf[start:end], end

            alg, pos = _read_ssh_string(sig, 0)
            sig_blob, pos2 = _read_ssh_string(sig, pos)
            if pos2 != len(sig):
                raise ValueError("Invalid SSH signature format")

            alg = alg.decode("utf-8", errors="strict")

            # If the key exposes an expected algorithm, enforce it.
            expected_alg = None
            for attr in ("algorithm", "alg", "name", "key_type"):
                if hasattr(pub, attr):
                    expected_alg = getattr(pub, attr)
                    break
            if expected_alg is not None and isinstance(expected_alg, bytes):
                expected_alg = expected_alg.decode("utf-8", errors="ignore")

            if expected_alg is not None and str(expected_alg) != alg:
                return False

            # Perform verification using common backend APIs.
            if hasattr(pub, "verify"):
                try:
                    result = pub.verify(data, sig_blob)
                    return bool(result)
                except TypeError:
                    # Some APIs expect (signature, data) or similar; try a few common forms.
                    pass

            if hasattr(pub, "public_key") and callable(getattr(pub.public_key, "__call__", None)):
                pk = pub.public_key()
                if hasattr(pk, "verify"):
                    try:
                        return bool(pk.verify(sig_blob, data))
                    except Exception:
                        try:
                            return bool(pk.verify(data, sig_blob))
                        except Exception:
                            return False

            # If no verification backend is available, fail safely.
            return False

        except Exception:
            return False

