from typing import Union
from urllib.parse import urlparse

def resolve_invite(invite: Union[Invite, str]) -> ResolvedInvite:
    """
    This function resolves an invite from a Discord invite, URL, or code. It returns a data class containing the invite code and the event ID.
    Input-Output Arguments
    :param invite: Union[Invite, str]. The invite to resolve.
    :return: ResolvedInvite. A data class containing the invite code and the event ID.
    """
    # If already an Invite object, extract the relevant fields directly
    if isinstance(invite, Invite):
        return ResolvedInvite(code=invite.code, event_id=getattr(invite, "event_id", None))

    if not isinstance(invite, str):
        raise TypeError("invite must be an Invite or str")

    invite = invite.strip()

    # If it's a full URL, parse out the invite code
    if invite.startswith("http://") or invite.startswith("https://"):
        parsed = urlparse(invite)
        path_parts = [p for p in parsed.path.split("/") if p]

        # Common Discord invite formats:
        #   https://discord.gg/<code>
        #   https://discord.com/invite/<code>
        #   https://discord.com/invite/<code>?event=<event_id>
        code = path_parts[-1] if path_parts else ""
        query = parsed.query

        event_id = None
        if query:
            # Simple query parsing without extra dependencies
            for part in query.split("&"):
                if "=" in part:
                    k, v = part.split("=", 1)
                    if k in ("event", "event_id"):
                        event_id = v
                        break

        if not code:
            raise ValueError("Could not resolve invite code from URL")

        return ResolvedInvite(code=code, event_id=event_id)

    # If it's a plain code, return it as-is
    return ResolvedInvite(code=invite, event_id=None)

class ReilParser:
    def parse(self, instrs):
        """
        This function parses a list of IR instructions. It converts each instruction to lowercase and checks if it is already present in the cache. If not, it parses the instruction and adds it to the cache. It then retrieves the parsed instruction from the cache, clones it, and adds it to the list of parsed instructions. If an error occurs during parsing, an error message is logged.
        Input-Output Arguments
        :param self: ReilParser. An instance of the ReilParser class.
        :param instrs: List of strings. The list of IR instructions to be parsed.
        :return: List of parsed instructions in REIL format.
        """
        parsed_instrs = []

        for instr in instrs:
            try:
                key = instr.lower()

                if key not in self.cache:
                    self.cache[key] = self._parse_instr(key)

                parsed_instrs.append(self.cache[key].clone())

            except Exception as e:
                if hasattr(self, "logger") and self.logger is not None:
                    self.logger.error("Error parsing instruction '%s': %s", instr, e)

        return parsed_instrs

