from typing import List
import importlib


def find_available_locales(providers: List[str]) -> List[str]:
    """
    This function finds and returns a list of available locales based on the given list of providers. It iterates through each provider, imports the provider module, checks if it is localized, and retrieves the list of languages from the module. The available locales are then updated with the languages found and returned in sorted order.
    Input-Output Arguments
    :param providers: List of strings. A list of provider paths.
    :return: List of strings. A sorted list of available locales.
    """
    available_locales = set()

    for provider_path in providers:
        try:
            module = importlib.import_module(provider_path)
        except ImportError:
            continue

        # Only consider localized providers
        if not getattr(module, "localized", False):
            continue

        languages = getattr(module, "languages", None)
        if languages:
            available_locales.update(languages)

    return sorted(available_locales)

from types import ModuleType
from typing import List
import os

def find_available_providers(modules: List[ModuleType]) -> List[str]:
    """
    This function takes a list of modules as input and finds the available providers.
    It iterates over each module in the input list, checks if the module has a package,
    and then creates a list of providers by joining the package name with each module
    name (excluding "__pycache__"). The function then updates a set of available providers
    with the newly created list and returns the sorted list of available providers.

    :param modules: List of ModuleType. A list of modules to search for available providers.
    :return: List of str. The sorted list of available providers.
    """
    available_providers = set()

    for module in modules:
        package = getattr(module, "__package__", None)
        if not package:
            continue

        module_path = getattr(module, "__path__", None)
        if module_path is None:
            continue

        for _, name, _ in os.walk(module_path[0]):
            # os.walk yields (root, dirs, files); we only need directory names
            pass

        # Collect immediate submodules/subpackages from the package directory
        try:
            for entry in os.listdir(module_path[0]):
                if entry == "__pycache__":
                    continue
                full_path = os.path.join(module_path[0], entry)
                if os.path.isdir(full_path):
                    available_providers.add(f"{package}.{entry}")
                elif entry.endswith(".py") and entry != "__init__.py":
                    available_providers.add(f"{package}.{entry[:-3]}")
        except (FileNotFoundError, NotADirectoryError, PermissionError):
            continue

    return sorted(available_providers)

