class DataSet:
    def tables(self):
        """
        This function retrieves a list of tables from the DataSet instance. It first gets the tables from the database and then adds any views if the include_views flag is set to True.
        Input-Output Arguments
        :param self: DataSet. An instance of the DataSet class.
        :return: List. A list of tables in the DataSet, including views if include_views is True.
        """
        tables = []

        # Get tables from the database if available
        if hasattr(self, "db") and self.db is not None:
            if hasattr(self.db, "tables") and callable(self.db.tables):
                tables = list(self.db.tables())
            elif hasattr(self.db, "get_tables") and callable(self.db.get_tables):
                tables = list(self.db.get_tables())

        # Optionally include views
        include_views = getattr(self, "include_views", False)
        if include_views and hasattr(self, "db") and self.db is not None:
            views = []
            if hasattr(self.db, "views") and callable(self.db.views):
                views = list(self.db.views())
            elif hasattr(self.db, "get_views") and callable(self.db.get_views):
                views = list(self.db.get_views())

            # Avoid duplicates while preserving order
            existing = set(tables)
            for view in views:
                if view not in existing:
                    tables.append(view)
                    existing.add(view)

        return tables

