# Helper for nested/recursive conversion
def _convert(obj):
    if not obj:
        return "Any"

    # react-docgen often uses `name`
    type_name = obj.get("name") or obj.get("type") or obj.get("value") or ""

    # Normalize common wrappers
    if type_name in ("arrayOf", "Array"):
        value = obj.get("value")
        inner = _convert(value) if isinstance(value, dict) else "Any"
        return f"List[{inner}]"

    if type_name in ("objectOf",):
        value = obj.get("value")
        inner = _convert(value) if isinstance(value, dict) else "Any"
        return f"Dict[str, {inner}]"

    if type_name in ("shape", "exact"):
        value = obj.get("value") or {}
        if isinstance(value, dict):
            fields = []
            for k, v in value.items():
                fields.append(f"'{k}': {_convert(v)}")
            return f"Dict[str, Any]" if not fields else f"Dict[str, Any]"
        return "Dict[str, Any]"

    if type_name in ("enum",):
        values = obj.get("value") or []
        if isinstance(values, list) and values:
            py_vals = []
            for v in values:
                if isinstance(v, dict):
                    py_vals.append(repr(v.get("value")))
                else:
                    py_vals.append(repr(v))
            return "Literal[" + ", ".join(py_vals) + "]"
        return "Any"

    if type_name in ("union",):
        values = obj.get("value") or []
        if isinstance(values, list) and values:
            parts = []
            for v in values:
                if isinstance(v, dict):
                    parts.append(_convert(v))
                else:
                    parts.append(_convert({"name": v}))
            # de-duplicate while preserving order
            seen = set()
            uniq = []
            for p in parts:
                if p not in seen:
                    seen.add(p)
                    uniq.append(p)
            return "Union[" + ", ".join(uniq) + "]"
        return "Any"

    if type_name in ("func", "function"):
        return "Callable"

    if type_name in ("bool", "boolean"):
        return "bool"

    if type_name in ("string",):
        return "str"

    if type_name in ("number", "float", "double", "integer", "int"):
        return "int" if type_name in ("integer", "int") else "float"

    if type_name in ("object",):
        return "Dict[str, Any]"

    if type_name in ("array",):
        return "List[Any]"

    if type_name in ("node", "element", "ReactNode"):
        return "Any"

    if type_name in ("symbol",):
        return "Any"

    if type_name in ("any", "mixed", "unknown"):
        return "Any"

    # Flow-specific names may appear directly
    if is_flow_type:
        flow_map = {
            "String": "str",
            "Number": "float",
            "Boolean": "bool",
            "Object": "Dict[str, Any]",
            "Array": "List[Any]",
            "Function": "Callable",
            "Void": "None",
            "Null": "None",
            "Any": "Any",
        }
        if type_name in flow_map:
            return flow_map[type_name]

    # Fallback: preserve unknown type names as Any
    return "Any"

py_type = _convert(type_object)

# Optional formatting hook for docstrings/indentation if needed by caller
if indent_num and isinstance(py_type, str):
    return py_type

return py_type

if nodes is None:
    nodes = []

if not isinstance(metadata, dict):
    return nodes

for key, value in metadata.items():
    full_key = f"{base}.{key}" if base else key

    if isinstance(value, dict):
        # If this dict looks like a typed node, collect it and recurse into nested structures
        node_type = value.get("type")

        if node_type in {"array", "shape", "union", "object"}:
            nodes.append(full_key)

            # Recurse into common nested containers
            if node_type == "array":
                if "items" in value:
                    collect_nodes(value["items"], full_key + ".items", nodes)
            elif node_type == "shape":
                if "fields" in value:
                    collect_nodes(value["fields"], full_key + ".fields", nodes)
            elif node_type == "union":
                if "variants" in value:
                    collect_nodes(value["variants"], full_key + ".variants", nodes)
                elif "options" in value:
                    collect_nodes(value["options"], full_key + ".options", nodes)
            elif node_type == "object":
                # Recurse into all nested dict/list values
                for sub_key, sub_val in value.items():
                    if isinstance(sub_val, dict):
                        collect_nodes(sub_val, full_key + f".{sub_key}", nodes)
                    elif isinstance(sub_val, list):
                        for i, item in enumerate(sub_val):
                            collect_nodes(item, full_key + f".{sub_key}[{i}]", nodes)

        elif node_type is not None:
            # Any other typed dict is treated as a node
            nodes.append(full_key)

        else:
            # Plain nested dict: recurse
            collect_nodes(value, full_key, nodes)

    elif isinstance(value, list):
        for i, item in enumerate(value):
            collect_nodes(item, f"{full_key}[{i}]", nodes)

return nodes

class DataSet:
    def update_cache(self, table=None):
        """
        Update the cache of the DataSet instance based on the given table. If a table is specified, it updates the cache for that table and its related tables. If no table is specified, it updates the cache for all tables. It generates and updates the models in the cache based on the updated cache.
        Input-Output Arguments
        :param self: DataSet. An instance of the DataSet class.
        :param table: String. The name of the table to update the cache for. Defaults to None.
        :return: No return values.
        """
        # Ensure required cache structures exist
        if not hasattr(self, "cache"):
            self.cache = {}
        if not hasattr(self, "models"):
            self.models = {}

        # Determine which tables need to be refreshed
        if table is None:
            tables_to_update = list(self.cache.keys())
        else:
            tables_to_update = [table]

            # If related tables are tracked, include them as well
            related = set()
            if hasattr(self, "relations") and isinstance(self.relations, dict):
                related.update(self.relations.get(table, []))
                for t, rels in self.relations.items():
                    if table in rels:
                        related.add(t)

            tables_to_update.extend([t for t in related if t not in tables_to_update])

        # Refresh cache entries
        for tbl in tables_to_update:
            # Prefer a dedicated refresh method if available
            if hasattr(self, "load_table") and callable(getattr(self, "load_table")):
                self.cache[tbl] = self.load_table(tbl)
            elif hasattr(self, "get_table_data") and callable(getattr(self, "get_table_data")):
                self.cache[tbl] = self.get_table_data(tbl)
            elif tbl in self.cache:
                # Keep existing cache entry if no loader is available
                self.cache[tbl] = self.cache[tbl]
            else:
                self.cache[tbl] = None

        # Rebuild/update models from refreshed cache
        if hasattr(self, "generate_models") and callable(getattr(self, "generate_models")):
            self.models = self.generate_models(self.cache)
        elif hasattr(self, "build_models") and callable(getattr(self, "build_models")):
            self.models = self.build_models(self.cache)
        else:
            # Fallback: create simple model placeholders from cache
            self.models = {tbl: self.cache.get(tbl) for tbl in self.cache}

class ChangeLog:
    def install(self, model, skip_fields=None, drop=True, insert=True,
                update=True, delete=True, create_table=True):

        """
        This function is used to install a change log for a model. It creates a table for the change log if the "create_table" parameter is set to True. It then generates and executes SQL statements to create triggers for insert, update, and delete actions on the model.
        Input-Output Arguments
        :param self: ChangeLog. An instance of the ChangeLog class.
        :param model: The model for which the change log is being installed.
        :param skip_fields: List of strings. The fields to skip when generating triggers. Defaults to None.
        :param drop: Bool. Whether to drop existing triggers before installing new ones. Defaults to True.
        :param insert: Bool. Whether to create triggers for insert actions. Defaults to True.
        :param update: Bool. Whether to create triggers for update actions. Defaults to True.
        :param delete: Bool. Whether to create triggers for delete actions. Defaults to True.
        :param create_table: Bool. Whether to create a table for the change log. Defaults to True.
        :return: No return values.
        """
        skip_fields = skip_fields or []

        # Determine table/model metadata
        table_name = getattr(model, "_meta", None)
        if table_name is not None:
            table_name = getattr(table_name, "db_table", None) or getattr(table_name, "table_name", None)
        if not table_name:
            table_name = getattr(model, "__name__", str(model)).lower()

        # Create changelog table if requested
        if create_table:
            create_sql = self.create_table_sql(model, skip_fields=skip_fields)
            if create_sql:
                self.execute(create_sql)

        # Drop existing triggers if requested
        if drop:
            for sql in self.drop_trigger_sql(model):
                self.execute(sql)

        # Create triggers
        if insert:
            sql = self.insert_trigger_sql(model, skip_fields=skip_fields)
            if sql:
                self.execute(sql)

        if update:
            sql = self.update_trigger_sql(model, skip_fields=skip_fields)
            if sql:
                self.execute(sql)

        if delete:
            sql = self.delete_trigger_sql(model, skip_fields=skip_fields)
            if sql:
                self.execute(sql)

class Signal:
    def connect(self, receiver, name=None, sender=None):
        """
        Connect a receiver function to a signal. It adds the receiver function to the list of receivers for the signal, along with the name and sender (if specified). If a receiver with the same name and sender already exists, it raises a ValueError.
        Input-Output Arguments
        :param self: Signal. An instance of the Signal class.
        :param receiver: The function to be connected as a receiver.
        :param name: String. The name of the receiver. If not specified, it defaults to the name of the receiver function. Defaults to None.
        :param sender: Any. The sender object. If specified, the receiver will only be called when the signal is emitted by this sender. Defaults to None.
        :return: No return values.
        """
        if not hasattr(self, "_receivers"):
            self._receivers = []

        if name is None:
            name = getattr(receiver, "__name__", str(receiver))

        for existing_receiver, existing_name, existing_sender in self._receivers:
            if existing_name == name and existing_sender == sender:
                raise ValueError(
                    f"A receiver with name '{name}' and sender '{sender}' is already connected."
                )

        self._receivers.append((receiver, name, sender))

