import json
from typing import Union

class HMACAlgorithm:
    @staticmethod
    def to_jwk(key_obj: str | bytes, as_dict: bool = False) -> Union["JWKDict", str]:
        """
        This function converts a key object to a JSON Web Key (JWK) representation.
        It creates a JWK dictionary with the key value and key type, and returns it
        as a JSON string or dictionary based on the value of the `as_dict` parameter.

        :param key_obj: str or bytes. The key object to be converted to JWK.
        :param as_dict: bool. Optional parameter to specify whether to return the JWK
                        as a dictionary or JSON string. Defaults to False.
        :return: Union[JWKDict, str]. The JWK representation of the key object.
                 If `as_dict` is True, it returns a dictionary. Otherwise, it returns
                 a JSON string.
        """
        if isinstance(key_obj, bytes):
            key_value = key_obj.decode("utf-8")
        elif isinstance(key_obj, str):
            key_value = key_obj
        else:
            raise TypeError("key_obj must be of type str or bytes")

        jwk_dict = {
            "kty": "oct",
            "k": key_value,
        }

        return jwk_dict if as_dict else json.dumps(jwk_dict)

import threading

class MusicSource:
    def search(self, keyword, sources_list) -> list:
        """
        This function searches for a keyword in a list of music sources. It creates multiple threads to search for the keyword in each source concurrently. It then sorts and removes duplicates from the search results based on song title, singer, and file size.
        Input-Output Arguments
        :param self: MusicSource. An instance of the MusicSource class.
        :param keyword: String. The keyword to search for in the music sources.
        :param sources_list: List of strings. The list of music sources to search in.
        :return: List of songs. The search results containing songs that match the keyword.
        """
        results = []
        lock = threading.Lock()

        def search_source(source):
            try:
                # Expect each source to provide a search method or callable behavior
                if hasattr(source, "search") and callable(source.search):
                    found = source.search(keyword)
                elif callable(source):
                    found = source(keyword)
                else:
                    found = []
                if found:
                    with lock:
                        results.extend(found)
            except Exception:
                # Ignore failing sources and continue searching others
                pass

        threads = []
        for source in sources_list:
            t = threading.Thread(target=search_source, args=(source,))
            t.start()
            threads.append(t)

        for t in threads:
            t.join()

        # Remove duplicates based on (title, singer, file size)
        unique = {}
        for song in results:
            if isinstance(song, dict):
                key = (
                    song.get("title"),
                    song.get("singer"),
                    song.get("file_size"),
                )
            else:
                # Fallback for object-like song entries
                key = (
                    getattr(song, "title", None),
                    getattr(song, "singer", None),
                    getattr(song, "file_size", None),
                )
            if key not in unique:
                unique[key] = song

        # Sort results by title, then singer, then file size
        def sort_key(song):
            if isinstance(song, dict):
                return (
                    song.get("title") or "",
                    song.get("singer") or "",
                    song.get("file_size") or 0,
                )
            return (
                getattr(song, "title", "") or "",
                getattr(song, "singer", "") or "",
                getattr(song, "file_size", 0) or 0,
            )

        return sorted(unique.values(), key=sort_key)

