import json
import base64

class HMACAlgorithm:
    @staticmethod
    def from_jwk(jwk: str | dict) -> bytes:
        """
        This function takes a JWK (JSON Web Key) as input and returns the corresponding HMAC (Hash-based Message Authentication Code) key.
        It first checks if the input is a valid JSON string or dictionary. Then, it verifies if the key type is "oct" (indicating HMAC).
        Finally, it decodes and returns the HMAC key.

        :param jwk: str or dict. The JWK (JSON Web Key) to extract the HMAC key from.
        :return: bytes. The extracted HMAC key.
        """
        # Parse JSON string if needed
        if isinstance(jwk, str):
            try:
                jwk = json.loads(jwk)
            except json.JSONDecodeError as e:
                raise ValueError("Invalid JWK JSON string") from e

        # Validate input type
        if not isinstance(jwk, dict):
            raise TypeError("JWK must be a JSON string or dictionary")

        # Validate key type
        if jwk.get("kty") != "oct":
            raise ValueError('Invalid JWK: expected key type "oct" for HMAC')

        # Extract and decode key material
        k = jwk.get("k")
        if not k:
            raise ValueError('Invalid JWK: missing "k" parameter')

        # Base64url decode (with padding fix)
        padding = "=" * (-len(k) % 4)
        try:
            return base64.urlsafe_b64decode(k + padding)
        except Exception as e:
            raise ValueError("Invalid JWK: unable to decode key material") from e

