path_change_token = object()

if manually_sorted_keys is None:
    manually_sorted_keys = []

def _iterate(d, prefix=""):
    # Preserve manual order first
    seen = set()

    for key in manually_sorted_keys:
        if key in d and key not in seen:
            seen.add(key)
            value = d[key]
            full_key = f"{prefix}.{key}" if prefix else str(key)

            if isinstance(value, dict):
                if value:
                    yield full_key, path_change_token
                    yield from _iterate(value, full_key)
                else:
                    yield full_key, value
            else:
                yield full_key, value

    # Then non-dictionary values sorted by key
    for key in sorted(k for k in d.keys() if k not in seen and not isinstance(d[k], dict)):
        seen.add(key)
        full_key = f"{prefix}.{key}" if prefix else str(key)
        yield full_key, d[key]

    # Finally dictionary values sorted by key
    for key in sorted(k for k in d.keys() if k not in seen and isinstance(d[k], dict)):
        seen.add(key)
        value = d[key]
        full_key = f"{prefix}.{key}" if prefix else str(key)

        if value:
            yield full_key, path_change_token
            yield from _iterate(value, full_key)
        else:
            yield full_key, value

