class Ingredient:
    def command(self, function=None, prefix=None, unobserved=False):

        """
        This function is a decorator used to define a new command for an Ingredient or Experiment. It captures the function and adds it to the commands dictionary of the Ingredient instance. The name of the command will be the name of the function. It can be called from the command-line or by using the run_command function.
        Input-Output Arguments
        :param self: Ingredient. An instance of the Ingredient class.
        :param function: Function. The function to be decorated and added as a command.
        :param prefix: String. The prefix to restrict the configuration space of the command. Defaults to None.
        :param unobserved: Bool. Whether the command should be unobserved, i.e., ignoring all observers. Defaults to False.
        :return: The captured function.
        """
        def decorator(func):
            # Initialize command registry if needed
            if not hasattr(self, "commands") or self.commands is None:
                self.commands = {}

            # Store command metadata
            self.commands[func.__name__] = {
                "function": func,
                "prefix": prefix,
                "unobserved": unobserved,
            }

            return func

        # Support both @command and @command(...)
        if function is None:
            return decorator
        return decorator(function)

class Ingredient:
    def gather_commands(self):
        """
        This function collects all commands from the Ingredient instance and its sub-ingredients. It iterates through each ingredient and its commands, and yields the full name of the command and the corresponding captured function.
        Input-Output Arguments
        :param self: Ingredient. An instance of the Ingredient class.
        :return: Yields a tuple containing the full name of the command (cmd_name) and the corresponding captured function (cmd).
        """
        # Yield commands defined directly on this ingredient
        for cmd_name, cmd in getattr(self, "commands", {}).items():
            yield cmd_name, cmd

        # Recursively yield commands from sub-ingredients
        for sub_name, sub_ingredient in getattr(self, "ingredients", {}).items():
            for cmd_name, cmd in sub_ingredient.gather_commands():
                yield f"{sub_name}.{cmd_name}", cmd

class Ingredient:
    def gather_named_configs(
        self,
    ) -> Generator[Tuple[str, Union[ConfigScope, ConfigDict, str]], None, None]:

        """
        This function gathers all named configurations from the Ingredient instance and its sub-ingredients. It iterates through each ingredient and its named configurations to collect the configuration names and corresponding configurations.
        Input-Output Arguments
        :param self: Ingredient. An instance of the Ingredient class.
        :return: Generator. A generator that yields tuples containing the full name of the named configuration and the corresponding configuration.
        """
        # Yield named configs defined on this ingredient
        for name, cfg in getattr(self, "named_configs", {}).items():
            yield name, cfg

        # Recursively yield named configs from sub-ingredients, prefixing with the sub-ingredient name
        for sub_name, sub_ingredient in getattr(self, "ingredients", {}).items():
            for name, cfg in sub_ingredient.gather_named_configs():
                yield f"{sub_name}.{name}", cfg

class PackageDependency:
    @classmethod
    def create(cls, mod):
        """
        Create a PackageDependency instance based on the given module. It caches the correspondence between module names and package names from the metadata "top_level.txt" file in the working set. It then create the PackageDependency instance by retrieving the package name and version from the cached dictionary.
        Input-Output Arguments
        :param cls: type. The PackageDependency class.
        :param mod: Module. The module for which the PackageDependency instance is created.
        :return: PackageDependency. The created PackageDependency instance.
        """
        import os
        import pkg_resources

        # Initialize cache on first use
        if not hasattr(cls, "_module_to_package_cache"):
            cls._module_to_package_cache = {}

            for dist in pkg_resources.working_set:
                try:
                    top_level = dist.get_metadata("top_level.txt")
                except (FileNotFoundError, IOError, KeyError):
                    continue

                for line in top_level.splitlines():
                    module_name = line.strip()
                    if module_name:
                        cls._module_to_package_cache[module_name] = (
                            dist.project_name,
                            dist.version,
                        )

        module_name = getattr(mod, "__name__", None)
        if not module_name:
            raise ValueError("Invalid module provided: missing __name__")

        # Handle submodules by using the top-level package name
        top_level_name = module_name.split(".")[0]

        if top_level_name not in cls._module_to_package_cache:
            raise ValueError(f"Could not determine package for module '{module_name}'")

        package_name, version = cls._module_to_package_cache[top_level_name]

        # Create and return the PackageDependency instance
        return cls(package_name, version)

class FileStorageObserver:
    def resource_event(self, filename):
        """
        This function handles a resource event by finding or saving the file, updating the 'resources' field of the running entry, and saving the updated running entry as 'run.json'.
        Input-Output Arguments
        :param self: FileStorageObserver. An instance of the FileStorageObserver class.
        :param filename: str. The name of the file for the resource event.
        :return: No return values.
        """
        import os
        import json

        # Determine the path to the resource file
        resource_path = filename

        # If the file does not exist, try to save/find it using the observer's storage location
        if not os.path.exists(resource_path):
            if hasattr(self, "storage_dir"):
                resource_path = os.path.join(self.storage_dir, filename)
            elif hasattr(self, "base_dir"):
                resource_path = os.path.join(self.base_dir, filename)

        # Load the current running entry
        run_path = None
        if hasattr(self, "storage_dir"):
            run_path = os.path.join(self.storage_dir, "run.json")
        elif hasattr(self, "base_dir"):
            run_path = os.path.join(self.base_dir, "run.json")
        else:
            run_path = "run.json"

        running_entry = {}
        if os.path.exists(run_path):
            with open(run_path, "r", encoding="utf-8") as f:
                try:
                    running_entry = json.load(f)
                except json.JSONDecodeError:
                    running_entry = {}

        # Update resources field
        resources = running_entry.get("resources", [])
        if not isinstance(resources, list):
            resources = [resources]

        if resource_path not in resources:
            resources.append(resource_path)

        running_entry["resources"] = resources

        # Save updated running entry back to run.json
        os.makedirs(os.path.dirname(run_path) or ".", exist_ok=True)
        with open(run_path, "w", encoding="utf-8") as f:
            json.dump(running_entry, f, indent=2)

