class FunctionBuilder:
    def get_invocation_str(self):
        """
        This function returns the invocation string of a function based on the arguments and keyword-only arguments of the FunctionBuilder instance.
        Input-Output Arguments
        :param self: FunctionBuilder. An instance of the FunctionBuilder class.
        :return: str. The invocation string of the function.
        """
        parts = []

        # Positional / regular arguments
        for arg in getattr(self, "args", []):
            if isinstance(arg, str):
                parts.append(arg)
            else:
                parts.append(str(arg))

        # Keyword-only arguments
        for key, value in getattr(self, "kwargs", {}).items():
            if isinstance(value, str):
                parts.append(f"{key}={value}")
            else:
                parts.append(f"{key}={repr(value)}")

        return f"({', '.join(parts)})"

class Signature:
    def construct_arguments(self, args, kwargs, options, bound=False):
        """
        This function constructs the arguments list and keyword arguments dictionary for a Signature instance. It ensures that the original explicit call arguments are preserved, missing arguments are filled in by name using options (if possible), default arguments are overridden by options, and it ensures that there are no unexpected arguments, conflicting values for a parameter in both args and kwargs, or unfilled parameters at the end of the process.
        Input-Output Arguments
        :param self: Signature. An instance of the Signature class.
        :param args: list. The original explicit call arguments.
        :param kwargs: dict. The original explicit call keyword arguments.
        :param options: dict. The options to fill in missing arguments and override default arguments.
        :param bound: bool. Whether the Signature instance is bound to an object.
        :return: Tuple[list, dict]. The constructed args list and kwargs dictionary.
        """
        import inspect

        args = list(args or [])
        kwargs = dict(kwargs or {})
        options = dict(options or {})

        # Try to infer the underlying callable signature.
        sig = getattr(self, "signature", None)
        if sig is None:
            sig = getattr(self, "_signature", None)
        if sig is None:
            sig = getattr(self, "__signature__", None)

        if sig is None:
            raise ValueError("Signature object does not define an inspect.Signature.")

        params = list(sig.parameters.values())

        # If bound, ignore the first parameter when constructing arguments.
        if bound and params:
            params = params[1:]

        positional_params = [
            p for p in params
            if p.kind in (inspect.Parameter.POSITIONAL_ONLY, inspect.Parameter.POSITIONAL_OR_KEYWORD)
        ]
        keyword_only_params = [
            p for p in params
            if p.kind == inspect.Parameter.KEYWORD_ONLY
        ]
        var_positional = any(p.kind == inspect.Parameter.VAR_POSITIONAL for p in params)
        var_keyword = any(p.kind == inspect.Parameter.VAR_KEYWORD for p in params)

        # Validate unexpected kwargs unless **kwargs is accepted.
        if not var_keyword:
            unexpected = set(kwargs) - {p.name for p in params}
            if unexpected:
                raise TypeError(f"Unexpected keyword arguments: {sorted(unexpected)}")

        # Validate too many positional args unless *args is accepted.
        if not var_positional and len(args) > len(positional_params):
            raise TypeError("Too many positional arguments")

        # Build final arguments by parameter order.
        final_args = []
        final_kwargs = {}

        # Fill positional / positional-or-keyword parameters.
        for i, param in enumerate(positional_params):
            has_positional = i < len(args)
            has_kw = param.name in kwargs
            has_opt = param.name in options

            if has_positional and has_kw:
                raise TypeError(f"Multiple values for argument '{param.name}'")

            if has_positional:
                value = args[i]
            elif has_kw:
                value = kwargs.pop(param.name)
            elif has_opt:
                value = options[param.name]
            elif param.default is not inspect._empty:
                value = param.default
            else:
                raise TypeError(f"Missing required argument: '{param.name}'")

            final_args.append(value)

        # Preserve extra positional args if *args exists.
        if var_positional:
            final_args.extend(args[len(positional_params):])

        # Fill keyword-only parameters.
        for param in keyword_only_params:
            has_kw = param.name in kwargs
            has_opt = param.name in options

            if has_kw and has_opt:
                raise TypeError(f"Multiple values for argument '{param.name}'")

            if has_kw:
                final_kwargs[param.name] = kwargs.pop(param.name)
            elif has_opt:
                final_kwargs[param.name] = options[param.name]
            elif param.default is not inspect._empty:
                final_kwargs[param.name] = param.default
            else:
                raise TypeError(f"Missing required keyword-only argument: '{param.name}'")

        # Any remaining kwargs are only allowed if **kwargs exists.
        if kwargs and not var_keyword:
            raise TypeError(f"Unexpected keyword arguments: {sorted(kwargs)}")

        final_kwargs.update(kwargs)

        return final_args, final_kwargs

class FunctionBuilder:
    def get_arg_names(self, only_required=False):
        """
        This function returns a tuple of argument names for a function. It includes both positional arguments and keyword-only arguments. If the "only_required" parameter is set to True, it only returns the names of required arguments, excluding those with default values.
        Input-Output Arguments
        :param self: FunctionBuilder. An instance of the FunctionBuilder class.
        :param only_required: bool. Whether to only return the names of required arguments. Defaults to False.
        :return: Tuple. A tuple of argument names.
        """
        arg_names = []

        # Positional arguments
        for name in getattr(self, "args", []):
            if only_required and name in getattr(self, "defaults", {}):
                continue
            arg_names.append(name)

        # Keyword-only arguments
        for name in getattr(self, "kwonlyargs", []):
            if only_required and name in getattr(self, "kwonlydefaults", {}):
                continue
            arg_names.append(name)

        return tuple(arg_names)

