class SpooledBytesIO:
    def seek(self, pos, mode=0):
        """
        This function seeks to a specified position in the SpooledBytesIO instance. It checks if the instance is closed and then seeks in the buffer.
        Input-Output Arguments
        :param self: SpooledBytesIO. An instance of the SpooledBytesIO class.
        :param pos: int. The position to seek to.
        :param mode: int. The mode to use for seeking. Defaults to 0.
        :return: The result of the seek operation.
        """
        if self.closed:
            raise ValueError("I/O operation on closed file.")

        return self._file.seek(pos, mode)

class SpooledBytesIO:
    def write(self, s):
        """
        Write the input bytes to the SpooledBytesIO instance. It first checks if the instance is closed. Then, it checks if the input string is of binary type. If not, it raises a TypeError: 'bytes expected, got {type of s}'. If writing the input string exceeds the maximum size of the instance, it will roll the instance over to a temp file. Finally, it writes the input string to the buffer.
        Input-Output Arguments
        :param self: SpooledBytesIO. An instance of the SpooledBytesIO class.
        :param s: bytes. The string to be written to the instance.
        :return: No return values.
        """
        if getattr(self, "closed", False):
            raise ValueError("I/O operation on closed file.")

        if not isinstance(s, (bytes, bytearray, memoryview)):
            raise TypeError(f"bytes expected, got {type(s).__name__}")

        # Normalize to bytes
        if isinstance(s, memoryview):
            s = s.tobytes()
        elif isinstance(s, bytearray):
            s = bytes(s)

        # Ensure required attributes exist
        if not hasattr(self, "_file"):
            raise AttributeError("SpooledBytesIO instance is missing '_file' attribute")
        if not hasattr(self, "_max_size"):
            raise AttributeError("SpooledBytesIO instance is missing '_max_size' attribute")

        # Roll over to a temp file if needed
        try:
            current_pos = self._file.tell()
            self._file.seek(0, 2)  # move to end
            end_pos = self._file.tell()
            new_size = end_pos + len(s)
            self._file.seek(current_pos)
        except Exception:
            new_size = len(s)

        if self._max_size is not None and new_size > self._max_size:
            if hasattr(self, "rollover"):
                self.rollover()
            else:
                raise AttributeError("SpooledBytesIO instance has no 'rollover' method")

        # Write to the underlying buffer
        return self._file.write(s)

class SpooledStringIO:
    def read(self, n=-1):
        """
        Read and return the specified number of characters from the SpooledStringIO instance. It checks if the instance is closed, reads the characters from the buffer, updates the current position, and returns the characters.
        Input-Output Arguments
        :param self: SpooledStringIO. An instance of the SpooledStringIO class.
        :param n: int. The number of characters to read. Defaults to -1, which means read all characters.
        :return: str. The characters read from the instance.
        """
        if getattr(self, "closed", False):
            raise ValueError("I/O operation on closed file.")

        # Ensure required attributes exist
        if not hasattr(self, "_buffer"):
            self._buffer = ""
        if not hasattr(self, "_pos"):
            self._pos = 0

        # Normalize n
        if n is None or n < 0:
            end = len(self._buffer)
        else:
            end = min(self._pos + n, len(self._buffer))

        start = self._pos
        result = self._buffer[start:end]
        self._pos = end
        return result

class BarrelList:
    def pop(self, *a):
        """
        Remove and return an item from the BarrelList based on the specified indexes.

        Input-Output Arguments
        :param self: BarrelList, an instance of BarrelList class.
        :param *a: Tuple, the index of the item to be popped. Default is an empty tuple.
        :return: The item that is removed and returned from the BarrelList. No return values if the list is empty or the index is invalid.
        """
        # If the BarrelList has no internal storage, treat it as empty
        if not hasattr(self, "_items"):
            return None

        if len(self._items) == 0:
            return None

        # Default behavior: pop the last item
        if len(a) == 0:
            return self._items.pop()

        # Use the first provided index
        index = a[0]

        # Validate index type
        if not isinstance(index, int):
            return None

        # Handle negative indexes
        if index < 0:
            index += len(self._items)

        # Validate range
        if index < 0 or index >= len(self._items):
            return None

        return self._items.pop(index)

class MultiFileReader:
    def read(self, amt=None):
        """
        This function reads data from multiple files seamlessly. It reads up to the specified amount of data and returns in the appropriate type of string (bytes or text) for the input. If the files are exhausted, it returns an empty string.
        Input-Output Arguments
        :param self: MultiFileReader. An instance of the MultiFileReader class.
        :param amt: int. The maximum amount of data to read. If not specified, it reads all the data from the files. Defaults to None.
        :return: str. The read data from the files.
        """
        # If there are no files left, return empty string/bytes
        if not hasattr(self, "files") or not self.files:
            return b"" if getattr(self, "binary", False) else ""

        # Determine output type
        is_binary = getattr(self, "binary", False)

        # Read all remaining data if amt is None
        if amt is None:
            chunks = []
            while self.files:
                f = self.files[0]
                data = f.read()
                if data:
                    chunks.append(data)
                else:
                    self.files.pop(0)
                    try:
                        f.close()
                    except Exception:
                        pass
            return b"".join(chunks) if is_binary else "".join(chunks)

        # Read up to amt bytes/chars across multiple files
        remaining = amt
        chunks = []

        while remaining > 0 and self.files:
            f = self.files[0]
            data = f.read(remaining)

            if not data:
                self.files.pop(0)
                try:
                    f.close()
                except Exception:
                    pass
                continue

            chunks.append(data)
            remaining -= len(data)

            # If current file is exhausted, move to next one
            if remaining > 0:
                # If file pointer is at EOF, remove it
                pos = None
                try:
                    pos = f.tell()
                    f.seek(0, 2)
                    end = f.tell()
                    f.seek(pos)
                    if pos == end:
                        self.files.pop(0)
                        try:
                            f.close()
                        except Exception:
                            pass
                except Exception:
                    # If tell/seek isn't supported, rely on next read() returning empty
                    pass

        return b"".join(chunks) if is_binary else "".join(chunks)

class URL:
    def navigate(self, dest):
        """
        This function is a factory method that returns a new URL object based on a given destination. It is used to navigate relative links easily. The newly created URL is normalized before being returned.
        Input-Output Arguments
        :param self: URL. An instance of the URL class.
        :param dest: str or URL. The destination to navigate to. It can be a string or a URL object.
        :return: URL. The newly created URL object.
        """
        # If dest is already a URL object, use it directly.
        if isinstance(dest, URL):
            new_url = dest
        else:
            # Otherwise, create a new URL from the string destination.
            # Assumes the URL class can be initialized from a string.
            new_url = URL(dest)

        # Normalize before returning.
        if hasattr(new_url, "normalize") and callable(new_url.normalize):
            return new_url.normalize()

        return new_url

class QueryParamDict:
    def to_text(self, full_quote=False):
        """
        This function takes a QueryParamDict instance and converts it into a query string. It iterates over the key-value pairs in the instance and percent-quotes special characters if full_quote is set to True.
        Input-Output Arguments
        :param self: QueryParamDict. An instance of the QueryParamDict class.
        :param full_quote: bool. Whether or not to percent-quote special characters in the query string. Defaults to False.
        :return: str. The query string representation of the QueryParamDict instance.
        """
        from urllib.parse import quote

        parts = []
        for key, value in self.items():
            if value is None:
                continue

            if isinstance(value, (list, tuple)):
                values = value
            else:
                values = [value]

            for v in values:
                k = str(key)
                val = str(v)

                if full_quote:
                    k = quote(k, safe="")
                    val = quote(val, safe="")

                parts.append(f"{k}={val}")

        return "&".join(parts)

class URL:
    def to_text(self, full_quote=False):
        """
        This function returns a string representation of the current state of the URL object. It constructs the URL string by combining the different components of the URL object, such as scheme, authority, path, query string, and fragment.
        Input-Output Arguments
        :param self: URL. An instance of the URL class.
        :param full_quote: bool. Whether to fully quote the URL or use minimal quoting. Defaults to False.
        :return: str. The string representation of the URL object.
        """
        from urllib.parse import quote, quote_plus

        def _q(value, safe="/:@", plus=False):
            if value is None:
                return ""
            value = str(value)
            if full_quote:
                return quote(value, safe="")
            return quote_plus(value, safe=safe) if plus else quote(value, safe=safe)

        parts = []

        # Scheme
        scheme = getattr(self, "scheme", None)
        if scheme:
            parts.append(f"{scheme}:")

        # Authority / netloc
        userinfo = ""
        username = getattr(self, "username", None)
        password = getattr(self, "password", None)
        host = getattr(self, "host", None)
        port = getattr(self, "port", None)

        if username is not None:
            userinfo = _q(username, safe="", plus=False)
            if password is not None:
                userinfo += ":" + _q(password, safe="", plus=False)
            userinfo += "@"

        if host:
            authority = userinfo + host
            if port is not None:
                authority += f":{port}"
            parts.append("//" + authority)

        # Path
        path = getattr(self, "path", None)
        if path:
            parts.append(_q(path, safe="/:@", plus=False))
        elif host and (getattr(self, "query", None) is not None or getattr(self, "fragment", None) is not None):
            parts.append("")

        # Query
        query = getattr(self, "query", None)
        if query is not None:
            if isinstance(query, dict):
                from urllib.parse import urlencode
                parts.append("?" + urlencode(query, doseq=True))
            else:
                q = str(query)
                parts.append("?" + (q[1:] if q.startswith("?") else _q(q, safe="=&?/:@", plus=True)))

        # Fragment
        fragment = getattr(self, "fragment", None)
        if fragment is not None:
            f = str(fragment)
            parts.append("#" + (f[1:] if f.startswith("#") else _q(f, safe="=&?/:@", plus=False)))

        return "".join(parts)

class Table:
    @classmethod
    def from_object(cls, data, headers=_MISSING, max_depth=1, metadata=None):
        """
        Create a Table instance from an object.
        Input-Output Arguments
        :param cls: type. The class of the Table instance.
        :param data: object. The data to create the Table from.
        :param headers: Iterable[str]. The headers of the Table. Defaults to _MISSING.
        :param max_depth: Integer. The level to which nested Tables should be created. Defaults to 1.
        :param metadata: Optional. Additional metadata for the Table. Defaults to None.
        :return: Table. The created Table instance.
        """
        # Helper to detect scalar-like values
        def _is_scalar(value):
            return isinstance(value, (str, bytes, int, float, bool, type(None)))

        # Convert mappings to rows
        if isinstance(data, dict):
            if headers is _MISSING:
                headers = list(data.keys())
            row = []
            for h in headers:
                value = data.get(h)
                if max_depth > 0 and isinstance(value, (dict, list, tuple)):
                    value = cls.from_object(value, max_depth=max_depth - 1)
                row.append(value)
            return cls([row], headers=headers, metadata=metadata)

        # Convert list/tuple of mappings or sequences
        if isinstance(data, (list, tuple)):
            if not data:
                return cls([], headers=[] if headers is _MISSING else headers, metadata=metadata)

            # List of dicts
            if all(isinstance(item, dict) for item in data):
                if headers is _MISSING:
                    headers = []
                    for item in data:
                        for key in item.keys():
                            if key not in headers:
                                headers.append(key)

                rows = []
                for item in data:
                    row = []
                    for h in headers:
                        value = item.get(h)
                        if max_depth > 0 and isinstance(value, (dict, list, tuple)):
                            value = cls.from_object(value, max_depth=max_depth - 1)
                        row.append(value)
                    rows.append(row)
                return cls(rows, headers=headers, metadata=metadata)

            # List of sequences
            if all(isinstance(item, (list, tuple)) for item in data):
                if headers is _MISSING:
                    headers = [f"col_{i}" for i in range(len(data[0]))]
                rows = []
                for item in data:
                    row = list(item)
                    if max_depth > 0:
                        row = [
                            cls.from_object(v, max_depth=max_depth - 1)
                            if isinstance(v, (dict, list, tuple)) and not _is_scalar(v)
                            else v
                            for v in row
                        ]
                    rows.append(row)
                return cls(rows, headers=headers, metadata=metadata)

            # Single-column table from scalar list
            if headers is _MISSING:
                headers = ["value"]
            rows = [[item] for item in data]
            return cls(rows, headers=headers, metadata=metadata)

        # Fallback: scalar or unsupported object -> single cell table
        if headers is _MISSING:
            headers = ["value"]
        return cls([[data]], headers=headers, metadata=metadata)

class IndexedSet:
    def add(self, item):
        """
        Add an item to the IndexedSet instance if the item is not already in the set.
        Input-Output Arguments
        :param self: IndexedSet. An instance of the IndexedSet class.
        :param item: The item to be added to the set.
        :return: No return values.
        """
        if not hasattr(self, "_items"):
            self._items = []
        if not hasattr(self, "_index"):
            self._index = {}

        if item not in self._index:
            self._index[item] = len(self._items)
            self._items.append(item)

class Table:
    def to_text(self, with_headers=True, maxlen=None):
        """
        This function returns the textual representation of a Table object. It includes the header row at the top and formats the data in a table-like structure. Each cell is first tried to be converted to a string. If that fails, it is converted to a repr string. If it exceeds the maximum length, it is truncated and an ellipsis is added. The text is padded with spaces to be centered in the cell. Each column is separated by ' | '. The header row is separated from the data by a line of dashes, where the intersection of each column and the header row is '-|-'.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param with_headers: bool. Whether to include a header row at the top. It defaults to True if not specified.
        :param maxlen: int. The maximum length of data in each cell. It defaults to None if not specified.
        :return: str. The textual representation of the Table object.
        """
        def cell_to_text(value):
            try:
                text = str(value)
            except Exception:
                text = repr(value)

            if maxlen is not None and len(text) > maxlen:
                if maxlen <= 3:
                    text = "." * maxlen
                else:
                    text = text[:maxlen - 3] + "..."
            return text

        # Try to infer common table attributes
        headers = getattr(self, "headers", None)
        rows = getattr(self, "rows", None)

        if rows is None:
            rows = getattr(self, "data", [])

        if headers is None:
            headers = []

        # Convert all cells to text
        text_rows = []
        if with_headers and headers:
            text_rows.append([cell_to_text(h) for h in headers])

        for row in rows:
            text_rows.append([cell_to_text(cell) for cell in row])

        if not text_rows:
            return ""

        # Determine column widths
        num_cols = max(len(r) for r in text_rows)
        widths = [0] * num_cols
        for row in text_rows:
            for i in range(num_cols):
                cell = row[i] if i < len(row) else ""
                widths[i] = max(widths[i], len(cell))

        def format_row(row):
            cells = []
            for i in range(num_cols):
                cell = row[i] if i < len(row) else ""
                cells.append(cell.center(widths[i]))
            return " | ".join(cells)

        lines = []

        if with_headers and headers:
            header_row = [cell_to_text(h) for h in headers]
            lines.append(format_row(header_row))
            lines.append("-|-".join("-" * w for w in widths))
            for row in rows:
                lines.append(format_row([cell_to_text(cell) for cell in row]))
        else:
            for row in rows:
                lines.append(format_row([cell_to_text(cell) for cell in row]))

        return "\n".join(lines)

