import re

def strip_ansi(text):
    """
    This function strips ANSI escape codes from the input text. It is useful when a log or redirected output accidentally captures console color codes. The function supports unicode, str, bytes, and bytearray content as input and returns the same type as the input.
    Input-Output Arguments
    :param text: The input text from which ANSI escape codes need to be stripped.
    :return: The cleaned text with ANSI escape codes removed.
    """
    ansi_re = re.compile(
        r'(?:\x1B[@-Z\\-_]|\x1B\[?[0-?]*[ -/]*[@-~])'
    )

    if isinstance(text, str):
        return ansi_re.sub('', text)

    if isinstance(text, bytes):
        cleaned = ansi_re.sub(b'', text.decode('utf-8', errors='ignore')).encode('utf-8')
        return cleaned

    if isinstance(text, bytearray):
        cleaned = ansi_re.sub(b'', bytes(text).decode('utf-8', errors='ignore')).encode('utf-8')
        return bytearray(cleaned)

    raise TypeError("strip_ansi() expects str, bytes, or bytearray input")

class Stats:
    def get_histogram_counts(self, bins=None, **kw):
        """
        This function produces a list of (bin, count) pairs that represents a histogram of the Stats object's data using fixed-width bins.

        Input-Output Arguments
        :param self: Stats. An instance of the Stats class.
        :param bins: int or list of float. The maximum number of bins or the list of floating-point bin boundaries. Defaults to the output of Freedman's algorithm.
        :param bin_digits: int. Number of digits used to round down the bin boundaries. Defaults to 1.
        :return: list of (bin, count) pairs. The histogram counts of the Stats object's data.
        """
        import math

        data = list(getattr(self, "data", []))
        if not data:
            return []

        bin_digits = kw.get("bin_digits", 1)

        # If bins is not provided, use Freedman-Diaconis rule
        if bins is None:
            sorted_data = sorted(data)
            n = len(sorted_data)

            if n == 1:
                return [(round(sorted_data[0], bin_digits), 1)]

            q1_idx = (n - 1) * 0.25
            q3_idx = (n - 1) * 0.75

            def _interp_quantile(arr, idx):
                lo = int(math.floor(idx))
                hi = int(math.ceil(idx))
                if lo == hi:
                    return arr[lo]
                return arr[lo] * (hi - idx) + arr[hi] * (idx - lo)

            q1 = _interp_quantile(sorted_data, q1_idx)
            q3 = _interp_quantile(sorted_data, q3_idx)
            iqr = q3 - q1

            if iqr == 0:
                # Fallback to sqrt rule if data is constant or nearly constant
                num_bins = max(1, int(math.sqrt(n)))
            else:
                bin_width = 2 * iqr / (n ** (1 / 3))
                if bin_width <= 0:
                    num_bins = max(1, int(math.sqrt(n)))
                else:
                    num_bins = max(1, int(math.ceil((max(data) - min(data)) / bin_width)))

            bins = num_bins

        # If bins is an integer, create fixed-width boundaries
        if isinstance(bins, int):
            if bins <= 0:
                raise ValueError("bins must be a positive integer")

            mn, mx = min(data), max(data)
            if mn == mx:
                return [(round(mn, bin_digits), len(data))]

            width = (mx - mn) / bins
            boundaries = [mn + i * width for i in range(bins + 1)]
        else:
            boundaries = list(bins)
            if len(boundaries) < 2:
                raise ValueError("bins boundary list must contain at least two values")

        # Round down boundaries
        factor = 10 ** bin_digits
        boundaries = [math.floor(b * factor) / factor for b in boundaries]

        # Ensure boundaries are non-decreasing after rounding
        cleaned = [boundaries[0]]
        for b in boundaries[1:]:
            if b < cleaned[-1]:
                b = cleaned[-1]
            cleaned.append(b)
        boundaries = cleaned

        counts = [0] * (len(boundaries) - 1)

        # Count data points into bins
        for x in data:
            placed = False
            for i in range(len(boundaries) - 1):
                left, right = boundaries[i], boundaries[i + 1]
                if i == len(boundaries) - 2:
                    if left <= x <= right:
                        counts[i] += 1
                        placed = True
                        break
                else:
                    if left <= x < right:
                        counts[i] += 1
                        placed = True
                        break

            if not placed and x == boundaries[-1]:
                counts[-1] += 1

        return list(zip(boundaries[:-1], counts))

