class BufferedSocket:
    def recv_close(self, timeout=_UNSET, maxsize=_UNSET):
        """
        This function receives data from the socket until the connection is closed, up to a specified maximum size. If more than the maximum size is received, it raises a `MessageTooLong` exception.

        Input-Output Arguments
        :param self: BufferedSocket, an instance of the BufferedSocket class.
        :param timeout: int. The timeout value for receiving data. Defaults to `_UNSET` if not specified.
        :param maxsize: int. The maximum size of received data. Defaults to `_UNSET` if not specified.
        :return: bytes. The received data up to the maximum size specified.
        """
        # Resolve timeout and maxsize defaults
        if timeout is _UNSET:
            timeout = self.timeout if hasattr(self, "timeout") else None
        if maxsize is _UNSET:
            maxsize = self.maxsize if hasattr(self, "maxsize") else None

        chunks = []
        total = 0

        # Save current socket timeout if possible
        sock = getattr(self, "sock", None)
        if sock is None:
            raise AttributeError("BufferedSocket has no underlying socket attribute 'sock'")

        old_timeout = None
        try:
            old_timeout = sock.gettimeout()
        except Exception:
            pass

        try:
            if timeout is not None:
                sock.settimeout(timeout)

            while True:
                try:
                    data = sock.recv(4096)
                except socket.timeout:
                    # Propagate timeout as-is
                    raise

                if not data:
                    break

                total += len(data)
                if maxsize is not None and total > maxsize:
                    raise MessageTooLong("received message exceeds maximum size")

                chunks.append(data)

            return b"".join(chunks)

        finally:
            # Restore previous timeout
            try:
                if old_timeout is not None:
                    sock.settimeout(old_timeout)
            except Exception:
                pass

