        import socket

        # Close the underlying socket if it exists
        if hasattr(self, "sock") and self.sock is not None:
            try:
                self.sock.close()
            finally:
                self.sock = None

        # Clear internal buffers/state if present
        if hasattr(self, "recv_buffer"):
            self.recv_buffer = b""
        if hasattr(self, "send_buffer"):
            self.send_buffer = b""
        if hasattr(self, "buffer"):
            self.buffer = b""

        # Mark as closed if the class tracks state
        if hasattr(self, "closed"):
            self.closed = True

