            s = socket.fromfd(fd, socket.AF_INET, socket.SOCK_STREAM)
            sockets.append(s)
        except OSError:
            # Try Unix domain socket as a fallback
            s = socket.fromfd(fd, socket.AF_UNIX, socket.SOCK_STREAM)
            sockets.append(s)
