    if isinstance(addr, str) and addr.startswith("/"):
        s = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
        try:
            s.bind(addr)
        except OSError as e:
            log.error("Failed to bind Unix socket %s: %s", addr, e)
            s.close()
            raise
        sockets.append(s)
        continue

    # Otherwise assume TCP host:port or (host, port)
    if isinstance(addr, tuple) and len(addr) == 2:
