class JcCli:
    @staticmethod
    def about_jc() -> JSONDictType:
        """
        This function returns a dictionary containing information about the jc library and the contents of each parser.info. It includes details such as the library name, version, description, author, author email, website, copyright, license, Python version, Python path, parser count, standard parser count, streaming parser count, plugin parser count, and all parser information.
        Input-Output Arguments
        :param: No input parameters.
        :return: JSONDictType. A dictionary containing information about the jc library and parser.info.
        """
        import sys
        import platform

        try:
            import jc
        except Exception:
            jc = None

        result = {
            "library": "jc",
            "version": getattr(jc, "__version__", None) if jc else None,
            "description": getattr(jc, "__description__", None) if jc else None,
            "author": getattr(jc, "__author__", None) if jc else None,
            "author_email": getattr(jc, "__author_email__", None) if jc else None,
            "website": getattr(jc, "__website__", None) if jc else None,
            "copyright": getattr(jc, "__copyright__", None) if jc else None,
            "license": getattr(jc, "__license__", None) if jc else None,
            "python_version": platform.python_version(),
            "python_path": sys.executable,
            "parser_count": 0,
            "standard_parser_count": 0,
            "streaming_parser_count": 0,
            "plugin_parser_count": 0,
            "parsers": {},
        }

        # Collect parser information if available
        try:
            from jc import parsers as jc_parsers
            parser_names = getattr(jc_parsers, "__all__", None)

            if parser_names is None:
                parser_names = [
                    name for name in dir(jc_parsers)
                    if not name.startswith("_")
                ]

            for parser_name in parser_names:
                parser_info = {}
                try:
                    parser_module = getattr(jc_parsers, parser_name, None)
                    if parser_module is None:
                        continue

                    parser_info = getattr(parser_module, "info", {}) or {}
                    result["parsers"][parser_name] = parser_info

                    result["parser_count"] += 1
                    if parser_info.get("streaming", False):
                        result["streaming_parser_count"] += 1
                    elif parser_info.get("plugin", False):
                        result["plugin_parser_count"] += 1
                    else:
                        result["standard_parser_count"] += 1
                except Exception:
                    result["parsers"][parser_name] = parser_info
        except Exception:
            pass

        return result

class OpenSSLPrerequisite:
    def darwin_pkg_config_location(self):
        """
        This function returns the location of the pkg-config directory for OpenSSL on macOS. It constructs the path by combining the prefix location of the Homebrew formula for OpenSSL and the "lib/pkgconfig" directory.
        Input-Output Arguments
        :param self: OpenSSLPrerequisite. An instance of the OpenSSLPrerequisite class.
        :return: String. The location of the pkg-config directory for OpenSSL on macOS.
        """
        import os
        import subprocess

        try:
            # Get the Homebrew prefix for openssl@3 (preferred) or openssl@1.1 as fallback
            for formula in ("openssl@3", "openssl@1.1", "openssl"):
                try:
                    prefix = subprocess.check_output(
                        ["brew", "--prefix", formula],
                        text=True
                    ).strip()
                    if prefix:
                        return os.path.join(prefix, "lib", "pkgconfig")
                except subprocess.CalledProcessError:
                    continue
        except FileNotFoundError:
            pass

        return None

class AutoconfPrerequisite:
