class Bootstrap:
    @classmethod
    def get_bootstrap_from_recipes(cls, recipes, ctx):
        """
        This function selects a recommended default bootstrap from a list of recipes and returns it.
        It follows a set of rules to determine the appropriate bootstrap based on the given recipes.
        The rules are following SDL2 bootstrap if there's an sdl2 dep or "webview" if we depend on common web recipe.

        Input-Output Arguments
        :param cls: Class. The Bootstrap class.
        :param recipes: List of strings. The list of recipes to consider when selecting the bootstrap.
        :param ctx: Context. The context in which the function is being called.
        :return: Bootstrap. The selected default bootstrap.
        """
        recipes = recipes or []

        # Normalize recipe names for matching
        normalized = {str(r).lower() for r in recipes}

        # Prefer SDL2 bootstrap if any SDL2-related dependency is present
        if any("sdl2" in r for r in normalized):
            return cls("sdl2")

        # Prefer webview bootstrap if common web recipe is present
        if "webview" in normalized or any("web" == r or r.endswith("/web") for r in normalized):
            return cls("webview")

        # Fallbacks based on context if available
        if ctx is not None:
            # Try common context hints if they exist
            for attr in ("bootstrap", "default_bootstrap", "preferred_bootstrap"):
                value = getattr(ctx, attr, None)
                if value:
                    return cls(value)

        # Final fallback
        return cls("default")

if not recipes:
