    alternatives = getattr(recipe, "alternatives", None)
    if not alternatives:
        alternatives = [recipe]

    new_expanded = []
    for combo in expanded:
        for alt in alternatives:
            # Add dependencies for recipes without alternatives.
            deps = getattr(alt, "dependencies", None)
            if deps:
                # Keep dependency expansion simple: append dependencies to the combo
                # if they are not already present.
                dep_list = list(deps) if isinstance(deps, (list, tuple, set)) else [deps]
                merged = list(combo)
                for dep in dep_list:
                    if dep not in merged:
                        merged.append(dep)
                merged.append(alt)
                new_expanded.append(merged)
            else:
                new_expanded.append(combo + [alt])

    expanded = new_expanded

return expanded

# Get set of recipe/dependency names, clean up and add bootstrap deps:

"""
This function takes in a context, a list of recipe/dependency names, an optional bootstrap instance, and an optional blacklist. It performs various operations on the input names to clean them up and add bootstrap dependencies. It then checks for conflicts and generates all possible order graphs based on the names. It converts each order graph into a linear list and sorts them based on preference. Finally, it returns the chosen order, along with the corresponding recipes, python modules, and bootstrap instance.
Input-Output Arguments
:param ctx: The context in which the function is being called.
:param names: List of strings. The recipe/dependency names.
:param bs: Bootstrap instance. An optional bootstrap instance. Defaults to None.
:param blacklist: Set of strings. An optional set of names to be blacklisted. Defaults to None.
:return: Tuple. The chosen order of dependencies, the corresponding recipes, python modules, and bootstrap instance.
"""
# Normalize inputs
names = list(names or [])
blacklist = set(blacklist or [])

# Remove duplicates while preserving order
seen = set()
cleaned_names = []
for n in names:
    if n is None:
        continue
    n = str(n).strip()
    if not n or n in seen or n in blacklist:
        continue
    seen.add(n)
    cleaned_names.append(n)

names = cleaned_names

# Bootstrap handling
if bs is None and hasattr(ctx, "bootstrap"):
    bs = ctx.bootstrap

# Add bootstrap dependencies if available
if bs is not None:
    bootstrap_deps = []
    for attr in ("deps", "dependencies", "recipes", "names"):
        if hasattr(bs, attr):
            val = getattr(bs, attr)
            if val:
                bootstrap_deps = list(val)
                break

    for dep in bootstrap_deps:
        dep = str(dep).strip()
        if dep and dep not in seen and dep not in blacklist:
            seen.add(dep)
            names.append(dep)

# Resolve recipes/modules from context if possible
recipes = []
py_modules = []

# Try common context APIs
if hasattr(ctx, "get_recipe"):
    for n in names:
        try:
            r = ctx.get_recipe(n)
            if r is not None:
                recipes.append(r)
        except Exception:
            pass
elif hasattr(ctx, "recipes"):
    recipe_map = getattr(ctx, "recipes")
    if isinstance(recipe_map, dict):
        for n in names:
            if n in recipe_map:
                recipes.append(recipe_map[n])

if hasattr(ctx, "get_python_module"):
    for n in names:
        try:
            m = ctx.get_python_module(n)
            if m is not None:
                py_modules.append(m)
        except Exception:
            pass
elif hasattr(ctx, "python_modules"):
    mod_map = getattr(ctx, "python_modules")
    if isinstance(mod_map, dict):
        for n in names:
            if n in mod_map:
                py_modules.append(mod_map[n])

# Determine order
order = []
if hasattr(ctx, "get_recipe_order"):
    try:
        order = list(ctx.get_recipe_order(names, bs=bs, blacklist=blacklist))
    except TypeError:
        try:
            order = list(ctx.get_recipe_order(names))
        except Exception:
            order = list(names)
    except Exception:
        order = list(names)
else:
    order = list(names)

# If order is empty, fall back to names
if not order:
    order = list(names)

return order, recipes, py_modules, bs

import os
import shutil

def copy(src, dst):
    """
    This function copies a file or a folder (recursively) from the source path to the destination path. It first checks if the source and destination paths are valid and absolute paths. Then, it creates the necessary directories in the destination path if they do not exist. If the source is a file, it copies the file to the destination. If the source is a folder, it copies the entire folder to the destination. If the source is neither a file nor a folder, it raises a ValueError. Finally, it sets the appropriate file permissions for the copied file or folder.
    Input-Output Arguments
    :param src: str. The source file or folder path.
    :param dst: str. The destination file or folder path.
    :return: No return values.
    """
    if not isinstance(src, str) or not isinstance(dst, str):
        raise TypeError("src and dst must be strings")

    if not os.path.isabs(src) or not os.path.isabs(dst):
        raise ValueError("src and dst must be absolute paths")

    if not os.path.exists(src):
        raise FileNotFoundError(f"Source path does not exist: {src}")

    # Ensure destination parent directory exists
    dst_parent = os.path.dirname(dst) if os.path.splitext(dst)[1] else dst
    if dst_parent:
        os.makedirs(dst_parent, exist_ok=True)

    if os.path.isfile(src):
        # If dst is an existing directory, copy into it using the source basename
        if os.path.isdir(dst):
            final_dst = os.path.join(dst, os.path.basename(src))
        else:
            final_dst = dst

        shutil.copy2(src, final_dst)

    elif os.path.isdir(src):
        # If dst exists and is a directory, copy src folder inside it
        if os.path.isdir(dst):
            final_dst = os.path.join(dst, os.path.basename(src))
        else:
            final_dst = dst

        if os.path.exists(final_dst):
            raise FileExistsError(f"Destination already exists: {final_dst}")

        shutil.copytree(src, final_dst, copy_function=shutil.copy2)

    else:
        raise ValueError("Source must be either a file or a folder")

    # Set permissions to match source
    shutil.copystat(src, final_dst if 'final_dst' in locals() else dst)

