class Config:
    @classmethod
    def discover(cls):
        """
        This function is a class method that discovers the location of the config file and tries to load it. It constructs the file path by joining the config directory and the config name of and then load the config from the constructed file path.
        Input-Output Arguments
        :param cls: The class object itself.
        :return: The loaded config object.
        """
        import os

        # Try common class attributes for config location/name
        config_dir = getattr(cls, "config_dir", None) or getattr(cls, "CONFIG_DIR", None) or "."
        config_name = getattr(cls, "config_name", None) or getattr(cls, "CONFIG_NAME", None) or "config.json"

        config_path = os.path.join(config_dir, config_name)

        if not os.path.exists(config_path):
            raise FileNotFoundError(f"Config file not found: {config_path}")

        # Load based on file extension
        _, ext = os.path.splitext(config_path)
        ext = ext.lower()

        if ext == ".json":
            import json
            with open(config_path, "r", encoding="utf-8") as f:
                return json.load(f)
        elif ext in (".yml", ".yaml"):
            try:
                import yaml
            except ImportError as e:
                raise ImportError("PyYAML is required to load YAML config files.") from e
            with open(config_path, "r", encoding="utf-8") as f:
                return yaml.safe_load(f)
        else:
            # Fallback: return raw file contents
            with open(config_path, "r", encoding="utf-8") as f:
                return f.read()

