        Input-Output Arguments
        :param self: Tweet. An instance of the Tweet class.
        :return: String. A human-readable relative time string.
        """
        now = datetime.now()

        # Try common attribute names for the tweet timestamp
        created_at = getattr(self, "created_at", None) or getattr(self, "timestamp", None)
        if created_at is None:
            raise AttributeError("Tweet object must have a 'created_at' or 'timestamp' attribute.")

        # If timestamp is a string, try to parse it
        if isinstance(created_at, str):
            try:
                created_at = datetime.fromisoformat(created_at)
            except ValueError:
                raise ValueError("Timestamp string must be in ISO format.")

        delta_seconds = int((now - created_at).total_seconds())
        tense = "ago" if delta_seconds >= 0 else "from now"
        delta_seconds = abs(delta_seconds)

        if delta_seconds < 60:
            delta = f"{delta_seconds} second{'s' if delta_seconds != 1 else ''}"
        elif delta_seconds < 3600:
            minutes = delta_seconds // 60
            delta = f"{minutes} minute{'s' if minutes != 1 else ''}"
        elif delta_seconds < 86400:
            hours = delta_seconds // 3600
            delta = f"{hours} hour{'s' if hours != 1 else ''}"
        elif delta_seconds < 2592000:
            days = delta_seconds // 86400
            delta = f"{days} day{'s' if days != 1 else ''}"
        elif delta_seconds < 31536000:
            months = delta_seconds // 2592000
            delta = f"{months} month{'s' if months != 1 else ''}"
        else:
            years = delta_seconds // 31536000
            delta = f"{years} year{'s' if years != 1 else ''}"

        return f"{delta} {tense}"

tweets = []

for raw_tweet in raw_tweets:
    try:
        # Skip empty lines and comments
        if not raw_tweet or not raw_tweet.strip() or raw_tweet.lstrip().startswith("#"):
            continue

        # Expected format: "<timestamp>\t<content>"
        parts = raw_tweet.split("\t", 1)
        if len(parts) != 2:
            continue

        timestamp_str, content = parts
        timestamp_str = timestamp_str.strip()
        content = content.strip()

        # Parse timestamp
        try:
            timestamp = datetime.fromisoformat(timestamp_str)
        except Exception:
            # Fallback for timestamps ending with Z
            if timestamp_str.endswith("Z"):
                timestamp = datetime.fromisoformat(timestamp_str[:-1] + "+00:00")
            else:
                raise

        tweet = Tweet(
            source=source,
            content=content,
            created_at=timestamp,
            now=now
        )
        tweets.append(tweet)

    except Exception:
        # Ignore malformed tweet lines and continue parsing the rest
        continue

return tweets

class WikipediaPage:
    def sections_by_title(
        self,
        title: str,
    ) -> List[WikipediaPageSection]:

        """
        This function returns all sections of the current Wikipedia page with a given title. It first checks if the "extracts" data has been fetched for the page. If not, it fetches the "extracts" data. Then, it retrieves the sections with the given title from the section mapping. If no sections are found, an empty list is returned.
        Input-Output Arguments
        :param self: WikipediaPage. An instance of the WikipediaPage class.
        :param title: str. The title of the section to retrieve.
        :return: List[WikipediaPageSection]. A list of WikipediaPageSection objects representing the sections with the given title.
        """
        if not getattr(self, "_extracts_fetched", False):
            self.fetch_extracts()

        sections = self._sections_by_title.get(title, [])
        return list(sections)

class WikipediaPage:
    def text(self) -> str:

        """
        This function returns the text of the current Wikipedia page. It first initializes the text with the summary of the page. Then, it appends the full text of each section to the text. Finally, it returns the trimmed text.
        Input-Output Arguments
        :param self: WikipediaPage. An instance of the WikipediaPage class.
        :return: str. The text of the current Wikipedia page.
        """
        text = self.summary if hasattr(self, "summary") and self.summary else ""

        if hasattr(self, "sections") and self.sections:
            for section in self.sections:
                section_text = section.text() if hasattr(section, "text") and callable(section.text) else str(section)
                if section_text:
                    if text:
                        text += "\n"
                    text += section_text

        return text.strip()

class WikipediaPage:
    def links(self) -> PagesDict:
        """
        This function returns all the pages that are linked from the current Wikipedia page. It is a wrapper for the MediaWiki API's query+links module and API:Links documentation.
        Input-Output Arguments
        :param self: WikipediaPage. An instance of the WikipediaPage class.
        :return: PagesDict. A dictionary-like object that contains the linked pages.
        """
        params = {
            "action": "query",
            "prop": "links",
            "titles": self.title,
            "pllimit": "max",
            "format": "json",
        }

        pages = PagesDict()

        while True:
            response = self._request(params)
            query = response.get("query", {})
            for page in query.get("pages", {}).values():
                for link in page.get("links", []):
                    title = link.get("title")
                    if title:
                        pages[title] = WikipediaPage(title, self._session)

            cont = response.get("continue")
            if not cont:
                break
            params.update(cont)

        return pages

class WikipediaPage:
    def langlinks(self) -> PagesDict:
        """
        This function returns all language links to pages in other languages. It is a wrapper for the MediaWiki API's query+langlinks module and the API:Langlinks page.
        Input-Output Arguments
        :param self: WikipediaPage. An instance of the WikipediaPage class.
        :return: PagesDict. A dictionary containing language links to pages in other languages.
        """
        # If the page has no title or API session, return an empty dict
        if not getattr(self, "title", None) or not getattr(self, "_api", None):
            return {}

        params = {
            "action": "query",
            "prop": "langlinks",
            "titles": self.title,
            "lllimit": "max",
            "format": "json",
        }

        result = self._api.get(params)
        pages_dict = {}

        query = result.get("query", {})
        pages = query.get("pages", {})

        for _, page in pages.items():
            for ll in page.get("langlinks", []):
                lang = ll.get("lang")
                title = ll.get("*")
                if lang and title:
                    pages_dict[lang] = title

        return pages_dict

class WikipediaPage:
    def backlinks(self) -> PagesDict:
        """
        This function returns all the pages that link to the current Wikipedia page. It is a wrapper for the MediaWiki API's backlinks module.
        Input-Output Arguments
        :param self: WikipediaPage. An instance of the WikipediaPage class.
        :return: PagesDict. A dictionary containing the pages that link to the current page.
        """
        params = {
            "action": "query",
            "list": "backlinks",
            "bltitle": self.title,
            "bllimit": "max",
            "format": "json",
        }

        backlinks = {}
        continue_params = {}

        while True:
            response = self._request(params | continue_params)
            data = response.json()

            for page in data.get("query", {}).get("backlinks", []):
                title = page.get("title")
                if title:
                    backlinks[title] = page

            if "continue" not in data:
                break

            continue_params = data["continue"]

        return backlinks

class IMAPClient:
    def shutdown(self) -> None:
        """
        Close the connection to the IMAP server without logging out. It shuts down the connection to the IMAP server and logs a message indicating that the connection has been closed.
        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :return: None.
        """
        if hasattr(self, "connection") and self.connection is not None:
            try:
                self.connection.shutdown()
            except Exception:
                # Some IMAP connections may not support shutdown cleanly
                pass
            finally:
                try:
                    self.connection.close()
                except Exception:
                    pass
                self.connection = None

        if hasattr(self, "logger") and self.logger is not None:
            self.logger.info("IMAP connection has been closed.")

class IMAPClient:
    def enable(self, *capabilities):
        """
        This function enables one or more server-side capability extensions in the IMAPClient instance. It sends an ENABLE command to the server with the requested extensions and returns a list of the successfully enabled extensions.
        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :param capabilities: Variable number of strings. The capability extensions to enable on the server.
        :return: List of strings. The requested extensions that were successfully enabled on the server.
        """
        if not capabilities:
            return []

        # Normalize capability names to strings
        requested = [str(cap) for cap in capabilities]

        # Send ENABLE command to the server
        typ, data = self._imap.enable(*requested)

        # IMAP ENABLE typically returns OK with a list of enabled capabilities
        if typ != "OK":
            raise self.error(f"ENABLE failed: {typ} {data}")

        enabled = []
        if data:
            for item in data:
                if isinstance(item, bytes):
                    item = item.decode("utf-8", errors="ignore")
                if isinstance(item, str):
                    enabled.extend(item.split())

        # Return only the capabilities that were requested and actually enabled
        requested_set = {cap.upper() for cap in requested}
        return [cap for cap in enabled if cap.upper() in requested_set]

class IMAPClient:
    def select_folder(self, folder, readonly=False):
        """
        This function sets the current folder on the server for the IMAPClient instance. It allows future calls to methods such as search and fetch to act on the selected folder.
        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :param folder: String. The name of the folder to select on the server.
        :param readonly: Bool. Whether to open the folder in read-only mode. Defaults to False.
        :return: Dictionary. A dictionary containing the response from the server after selecting the folder. The keys "EXISTS", "FLAGS", and "RECENT" are guaranteed to exist in the dictionary.
        """
        if readonly:
            typ, data = self._imap.select(folder, readonly=True)
        else:
            typ, data = self._imap.select(folder)

        if typ != "OK":
            raise Exception(f"Unable to select folder {folder!r}: {data}")

        response = {}
        for item in data:
            if not item:
                continue
            if isinstance(item, bytes):
                item = item.decode("utf-8", errors="ignore")

            parts = item.split()
            if len(parts) >= 2:
                try:
                    value = int(parts[0])
                except ValueError:
                    continue

                key = parts[1].upper()
                response[key] = value

        # Ensure required keys exist
        response.setdefault("EXISTS", 0)
        response.setdefault("FLAGS", [])
        response.setdefault("RECENT", 0)

        return response

class IMAPClient:
    def unselect_folder(self):
        """
        This function unselects the current folder in the IMAPClient instance and releases any associated resources. It sends the "UNSELECT" command to the server and returns the UNSELECT response string.
        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :return: String. The UNSELECT response string returned by the server.
        """
        # Ensure the client is connected and a folder is currently selected
        if not hasattr(self, "imap") or self.imap is None:
            raise RuntimeError("IMAP client is not connected.")

        # Try the IMAP UNSELECT command first (RFC 3691)
        try:
            typ, data = self.imap.unselect()
        except AttributeError:
            # Fallback for servers/clients that do not support UNSELECT
            typ, data = self.imap.close()

        # Release any local state associated with the selected folder
        if hasattr(self, "selected_folder"):
            self.selected_folder = None
        if hasattr(self, "mailbox"):
            self.mailbox = None

        # Return a readable response string
        response_parts = [typ]
        if data:
            if isinstance(data, (list, tuple)):
                response_parts.extend(
                    item.decode() if isinstance(item, bytes) else str(item)
                    for item in data
                    if item is not None
                )
            else:
                response_parts.append(data.decode() if isinstance(data, bytes) else str(data))

        return " ".join(response_parts).strip()

class IMAPClient:
    def _proc_folder_list(self, folder_data):
        # Filter out empty strings and None's.
        # This also deals with the special case of - no 'untagged'
        # responses (ie, no folders). This comes back as [None].

        """
        This function processes the folder data returned by the IMAP server and filters out empty strings and None values. It then parses the response and extracts the flags, delimiter, and name of each folder. If the folder name is an integer, it converts it back to a string. If folder encoding is enabled, it decodes the folder name using UTF-7 encoding. Finally, it returns a list of tuples containing the flags, delimiter, and name of each folder.
        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :param folder_data: List of bytes. The folder data returned by the IMAP server.
        :return: List of tuples. Each tuple contains the flags, delimiter, and name of a folder.
        """
        import re

        if not folder_data:
            return []

        folder_data = [x for x in folder_data if x not in (None, b"", "")]
        if not folder_data:
            return []

        folders = []
        pattern = re.compile(
            r'^\((?P<flags>.*?)\)\s+(?P<delim>NIL|"(?:[^"\\]|\\.)*")\s+(?P<name>NIL|"(?:[^"\\]|\\.)*"|.+)$'
        )

        for item in folder_data:
            if isinstance(item, bytes):
                item = item.decode("utf-8", "replace")

            item = item.strip()
            m = pattern.match(item)
            if not m:
                continue

            flags = m.group("flags").split() if m.group("flags") else []
            delim = m.group("delim")
            name = m.group("name")

            if delim == "NIL":
                delim = None
            else:
                delim = delim[1:-1].encode("utf-8").decode("unicode_escape")

            if name == "NIL":
                name = None
            else:
                if name.startswith('"') and name.endswith('"'):
                    name = name[1:-1].encode("utf-8").decode("unicode_escape")

            # Convert integer-like folder names back to strings if needed.
            if isinstance(name, int):
                name = str(name)

            # Decode modified UTF-7 folder names if enabled.
            if getattr(self, "folder_encode", False) and isinstance(name, str):
                try:
                    name = name.encode("ascii").decode("imap4-utf-7")
                except Exception:
                    pass

            folders.append((flags, delim, name))

        return folders

class IMAPClient:
    def noop(self):
        """
        This function executes the NOOP command in the IMAPClient instance. The NOOP command returns immediately and can be used to receive any server-side status updates or reset any auto-logout timers.
        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :return: The server command response message followed by a list of status responses.
        """
        return self._imap.noop()

class IMAPClient:
    def starttls(self, ssl_context=None):
        """
        This function switches the connection to an SSL encrypted connection by sending a STARTTLS command. It establishes an SSL connection using the provided SSL context or a default SSL context. It also checks the hostname in the server's certificate against the hostname used for connecting. If the SSL connection cannot be established or the server does not support STARTTLS, appropriate exceptions are raised.
        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :param ssl_context: SSLContext. Optional. The SSL context to use for establishing the SSL connection. If not provided, a default SSL context with reasonable default settings will be used.
        :return: The response from the server after executing the STARTTLS command.
        """
        import ssl as _ssl

        if getattr(self, "_tls_established", False):
            raise RuntimeError("TLS is already established")

        # Ensure the server supports STARTTLS
        capabilities = getattr(self, "capabilities", None)
        if capabilities is None:
            try:
                capabilities = self.capabilities()
            except Exception:
                capabilities = None

        if capabilities is not None:
            if isinstance(capabilities, (set, frozenset, list, tuple)):
                caps = {c.decode() if isinstance(c, bytes) else str(c) for c in capabilities}
            else:
                caps = {str(capabilities)}
            if "STARTTLS" not in {c.upper() for c in caps}:
                raise RuntimeError("Server does not support STARTTLS")

        # Use a default SSL context if none was provided
        if ssl_context is None:
            ssl_context = _ssl.create_default_context()

        # Enable hostname checking when possible
        host = getattr(self, "host", None) or getattr(self, "_host", None)
        if host and hasattr(ssl_context, "check_hostname"):
            ssl_context.check_hostname = True

        # Send STARTTLS command
        if not hasattr(self, "execute"):
            raise AttributeError("IMAPClient instance does not support command execution")

        response = self.execute("STARTTLS")

        # Validate response if it looks like a typical IMAP response
        if response is None:
            raise RuntimeError("STARTTLS failed: no response from server")

        resp_text = str(response).upper()
        if "OK" not in resp_text and not resp_text.startswith("OK"):
            raise RuntimeError(f"STARTTLS failed: {response}")

        # Wrap the underlying socket/connection with SSL
        sock = getattr(self, "sock", None) or getattr(self, "_sock", None)
        if sock is None:
            raise RuntimeError("No underlying socket available for TLS upgrade")

        server_hostname = host
        try:
            tls_sock = ssl_context.wrap_socket(sock, server_hostname=server_hostname)
        except Exception as e:
            raise RuntimeError(f"Failed to establish TLS connection: {e}") from e

        # Replace the underlying socket with the TLS-wrapped socket
        if hasattr(self, "sock"):
            self.sock = tls_sock
        else:
            self._sock = tls_sock

        self._tls_established = True
        return response

class IMAPClient:
    def idle_check(self, timeout=None):
        """
        Check for any IDLE responses sent by the server. This method should only be called if the server is in IDLE mode. It blocks until an IDLE response is received, or until a timeout is reached.
        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :param timeout: int or None. The maximum number of seconds to wait for an IDLE response. If None, the call will block indefinitely.
        :return: list. A list of received IDLE responses, parsed with values converted to appropriate types.
        """
        import select
        import time

        # Ensure we're in IDLE mode
        if not getattr(self, "_idle", False):
            raise RuntimeError("idle_check() can only be called while in IDLE mode")

        sock = getattr(self, "_sock", None)
        if sock is None:
            raise RuntimeError("No active socket connection")

        responses = []
        start = time.time()

        while True:
            # Compute remaining timeout
            if timeout is None:
                wait_time = None
            else:
                elapsed = time.time() - start
                remaining = timeout - elapsed
                if remaining <= 0:
                    break
                wait_time = remaining

            rlist, _, _ = select.select([sock], [], [], wait_time)
            if not rlist:
                break

            # Read a line from the server
            line = sock.recv(4096)
            if not line:
                break

            # Handle bytes -> string
            if isinstance(line, bytes):
                line = line.decode("utf-8", errors="replace")

            # Split into lines in case multiple responses arrived
            for raw in line.splitlines():
                raw = raw.strip()
                if not raw:
                    continue

                # Parse common IMAP untagged responses, e.g.:
                # "* 23 EXISTS" -> [23, "EXISTS"]
                # "* OK ..."    -> ["OK", "..."]
                if raw.startswith("* "):
                    parts = raw[2:].split()
                    parsed = []
                    for p in parts:
                        if p.isdigit():
                            parsed.append(int(p))
                        else:
                            parsed.append(p)
                    responses.append(parsed)
                else:
                    responses.append([raw])

            # If we got at least one response, return immediately
            if responses:
                break

        return responses

class IMAPClient:
    def get_flags(self, messages):
        """
        Return a dictionary that contains the flags set for each message in the input parameter `messages`.

        Input-Output Arguments
        :param self: IMAPClient, an instance of IMAPClient class.
        :param messages: List, a list of message IDs for which to retrieve the flags.
        :return: Dict, a dictionary that contains the flags set for each message, structured as follows: "{msgid1: (flag1, flag2, ...),}".
        """
        flags_dict = {}

        for msgid in messages:
            # Fetch flags for the message
            typ, data = self.connection.fetch(str(msgid), "(FLAGS)")

            if typ != "OK" or not data:
                flags_dict[msgid] = ()
                continue

            # Parse returned flags
            msg_flags = ()
            for item in data:
                if isinstance(item, tuple) and len(item) > 1:
                    response = item[1].decode() if isinstance(item[1], bytes) else str(item[1])
                    start = response.find("FLAGS")
                    if start != -1:
                        start = response.find("(", start)
                        end = response.find(")", start)
                        if start != -1 and end != -1:
                            flags_str = response[start + 1:end].strip()
                            msg_flags = tuple(flag for flag in flags_str.split() if flag)
                            break

            flags_dict[msgid] = msg_flags

        return flags_dict

class IMAPClient:
    def thread(self, algorithm="REFERENCES", criteria="ALL", charset="UTF-8"):
        """
        Return a list of message threads from the currently selected folder that match the specified criteria.
        Each returned thread is a list of message IDs.

        Input-Output Arguments
        :param algorithm: String, the threading algorithm to use. It defaults to "REFERENCES" if not specified.
        :param criteria: String, the search criteria to match the messages. It defaults to "ALL" if not specified.
        :param charset: String, the character set to be used. It defaults to "UTF-8" if not specified.
        :return: List[Tuple], each tuple represents a message thread, where each element of the tuple is a message ID.
                 For example, "((1, 2), (3,), (4, 5, 6))".
        """
        if not hasattr(self, "_imap"):
            raise AttributeError("IMAP connection not initialized")

        # Build IMAP THREAD command
        args = [algorithm]
        if charset is not None:
            args.extend([charset, criteria])
        else:
            args.append(criteria)

        typ, data = self._imap.thread(*args)

        if typ != "OK":
            raise Exception(f"THREAD command failed: {typ} {data}")

        if not data:
            return tuple()

        # IMAP THREAD response is typically a list containing one bytes object/string
        # like b'((1 2)(3)(4 5 6))'
        raw = data[0]
        if isinstance(raw, bytes):
            raw = raw.decode("utf-8", errors="replace")

        raw = raw.strip()
        if not raw:
            return tuple()

        # Parse IMAP thread response into nested tuples of ints
        def parse_thread(s, i=0):
            threads = []
            n = len(s)

            while i < n:
                while i < n and s[i].isspace():
                    i += 1

                if i >= n:
                    break

                if s[i] == "(":
                    sub, i = parse_thread(s, i + 1)
                    threads.append(sub)
                elif s[i] == ")":
                    return tuple(threads), i + 1
                else:
                    j = i
                    while j < n and s[j].isdigit():
                        j += 1
                    if j > i:
                        threads.append(int(s[i:j]))
                    i = j

            return tuple(threads), i

        parsed, _ = parse_thread(raw)
        return parsed

class IMAPClient:
    def multiappend(self, folder, msgs):
        """
        Append messages to a folder using the MULTIAPPEND feature. 

        Input-Output Arguments
        :param folder: String, the name of the folder to append the messages to.
        :param msgs: Iterable, an iterable containing the messages to be appended. Each item in the iterable can be either a string containing the full message including headers, or a dictionary containing the keys "msg" with the full message, "flags" with a sequence of message flags to set, and "date" with a datetime instance specifying the internal date to set.
        :return: The APPEND response from the server.
        """
        if not msgs:
            raise ValueError("msgs must contain at least one message")

        append_data = []
        for item in msgs:
            if isinstance(item, str):
                append_data.append((item, None, None))
            elif isinstance(item, dict):
                if "msg" not in item:
                    raise ValueError('Each dict message must contain a "msg" key')
                append_data.append((
                    item["msg"],
                    item.get("flags"),
                    item.get("date")
                ))
            else:
                raise TypeError(
                    "Each message must be either a string or a dict with keys "
                    '"msg", "flags", and "date"'
                )

        # Prefer MULTIAPPEND if the underlying client supports it.
        # Fallback to individual APPENDs if needed.
        if hasattr(self, "_imap") and hasattr(self._imap, "multiappend"):
            return self._imap.multiappend(folder, append_data)

        if hasattr(self, "append"):
            last_response = None
            for msg, flags, date in append_data:
                last_response = self.append(folder, msg, flags=flags, date=date)
            return last_response

        raise NotImplementedError(
            "No MULTIAPPEND or APPEND implementation available on this client"
        )

class IMAPClient:
    def get_gmail_labels(self, messages):

        """
        This function returns the label set for each message in the currently selected folder. It fetches the X-GM-LABELS attribute for the given messages from the IMAP server and filters the response to get the label information. It then decodes the labels using UTF-7 encoding and returns a dictionary with message IDs as keys and label sets as values.
        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :param messages: List of bytes. The messages for which to retrieve the labels.
        :return: Dictionary. A dictionary mapping message IDs to label sets.
        """
        if not messages:
            return {}

        # Ensure message ids are bytes/strings acceptable by IMAP fetch
        msg_set = b",".join(messages) if all(isinstance(m, (bytes, bytearray)) for m in messages) else ",".join(
            m.decode() if isinstance(m, (bytes, bytearray)) else str(m) for m in messages
        )

        typ, data = self.connection.fetch(msg_set, "(X-GM-LABELS)")
        if typ != "OK" or not data:
            return {}

        labels_by_msg = {}

        for item in data:
            if not item or not isinstance(item, tuple) or len(item) < 2:
                continue

            header, attrs = item[0], item[1]
            if not isinstance(header, (bytes, bytearray)):
                continue

            # Extract message id from the fetch response header
            # Example: b'1 (X-GM-LABELS (\\Inbox \\Sent))'
            try:
                msg_id = int(header.split(b" ", 1)[0])
            except Exception:
                continue

            labels = set()

            # attrs may be bytes containing the label list or a tuple/list depending on imaplib
            raw = attrs
            if isinstance(raw, (bytes, bytearray)):
                raw = raw.decode("utf-8", errors="ignore")

            # Normalize to a string and extract labels inside parentheses
            if isinstance(raw, str):
                start = raw.find("(")
                end = raw.rfind(")")
                if start != -1 and end != -1 and end > start:
                    raw_labels = raw[start + 1:end].strip()
                    if raw_labels:
                        for label in raw_labels.split():
                            # Decode modified UTF-7 if needed
                            try:
                                decoded = label.encode("ascii").decode("imap4-utf-7")
                            except Exception:
                                decoded = label
                            labels.add(decoded)

            labels_by_msg[msg_id] = labels

        return labels_by_msg

class IMAPClient:
    def expunge(self, messages=None):
        """
        This function is used to expunge messages from the selected folder in an IMAP client. If no messages are specified, it removes all messages with the "\\Deleted" flag set. If messages are specified, it removes the specified messages with the "\\Deleted" flag set. The function returns the server response message followed by a list of expunge responses. The implementation takes into account whether the client is using UIDs or not.
        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :param messages: List of int or str. The messages to be expunged. Defaults to None.
        :return: Tuple. The server response message followed by a list of expunge responses if no messages are specified. None if messages are specified.
        """
        if messages is None:
            # Standard IMAP EXPUNGE removes all messages marked \Deleted
            return self._command_and_check("EXPUNGE")

        if not isinstance(messages, (list, tuple, set)):
            messages = [messages]

        # Normalize message identifiers
        msg_set = self._message_set(messages)

        # If using UIDs, use UID EXPUNGE when available
        if getattr(self, "_use_uid", False):
            try:
                return self._command_and_check("UID EXPUNGE", msg_set)
            except Exception:
                # Fallback: mark deleted messages and expunge
                self._command_and_check("UID STORE", msg_set, "+FLAGS.SILENT", r"(\Deleted)")
                return self._command_and_check("EXPUNGE")

        # Non-UID mode: mark messages deleted, then expunge
        self._command_and_check("STORE", msg_set, "+FLAGS.SILENT", r"(\Deleted)")
        return self._command_and_check("EXPUNGE")

class IMAPClient:
    def getacl(self, folder):
        """
        Return a list of "(who, acl)" tuples describing the access controls for the specified folder in the IMAPClient instance. "who" denotes the users, and "acl" means access control list.

        Input-Output Arguments
        :param self: IMAPClient, an instance of IMAPClient class.
        :param folder: String, the name of the folder for which access controls need to be retrieved.
        :return: List[Tuple], a list of tuples containing two elements each: the "who" and the "acl" for the specified folder. "who" denotes the users, and "acl" means access control list.
        """
        typ, data = self._imap.getacl(folder)

        if typ != 'OK':
            raise Exception(f"GETACL failed for folder '{folder}': {data}")

        # IMAP GETACL response format is typically:
        # [b'foldername user1 acl1 user2 acl2 ...']
        if not data or not data[0]:
            return []

        if isinstance(data[0], bytes):
            acl_data = data[0].decode('utf-8', errors='ignore')
        else:
            acl_data = str(data[0])

        parts = acl_data.split()

        # First token is usually the folder name; remaining tokens are pairs of (who, acl)
        if len(parts) <= 1:
            return []

        acl_pairs = []
        for i in range(1, len(parts), 2):
            if i + 1 < len(parts):
                acl_pairs.append((parts[i], parts[i + 1]))

        return acl_pairs

class IMAPClient:
    def setacl(self, folder, who, what):
        """
        Set an access control list (ACL) for a given user on a specified folder in IMAPClient.
        Remove an ACL if the `what` is an empty string. Return the server response string.

        Input-Output Arguments
        :param folder: String, the folder path for which the ACL needs to be set.
        :param who: String, the user for whom the ACL is being set.
        :param what: String, the access control level to be set for the user. Empty string removes the ACL.
        :return: String, the server response string.
        """
        if what == "":
            return self._simple_command('SETACL', folder, who, '')
        return self._simple_command('SETACL', folder, who, what)

from datetime import date, datetime

def _normalise_search_criteria(criteria, charset=None):
    """
    This function normalizes the search criteria by converting them into a standardized format.
    It handles different types of criteria and converts them accordingly including
    int, str, datetime, list, tuple, bytes. If no criteria are specified, it raises
    the corresponding error. If no character set is specified, it defaults to "us-ascii".

    :param criteria: The search criteria to be normalized. It can be a string, bytes,
                     list, tuple, int, datetime, or date.
    :param charset: The character set to be used for encoding. Defaults to "us-ascii"
                    if not specified.
    :return: A list of normalized search criteria.
    """
    if charset is None:
        charset = "us-ascii"

    if criteria is None:
        raise ValueError("No search criteria specified")

    def _normalize_item(item):
        if isinstance(item, bytes):
            return item.decode(charset)
        if isinstance(item, str):
            return item
        if isinstance(item, int):
            return str(item)
        if isinstance(item, datetime):
            return item.strftime("%d-%b-%Y")
        if isinstance(item, date):
            return item.strftime("%d-%b-%Y")
        if isinstance(item, (list, tuple)):
            return [_normalize_item(x) for x in item]
        return str(item)

    normalized = _normalize_item(criteria)

    # Ensure the result is always a list at the top level
    if isinstance(normalized, list):
        return normalized
    return [normalized]

