from typing import Union
import datetime

def iso8601_date(s: str) -> Union[datetime.date, str]:
    """
    This function parses an ISO 8601 date string and returns a UTC date object or the string itself if the parsing fails.
    Input-Output Arguments
    :param s: str. The ISO 8601-formatted date string to be parsed.
    :return: Union[datetime.date, str]. The parsed UTC date object or the original string if parsing fails.
    """
    try:
        # Handle common ISO 8601 forms, including a trailing "Z"
        dt = datetime.datetime.fromisoformat(s.replace("Z", "+00:00"))
        return dt.date()
    except (ValueError, TypeError):
        try:
            # Fallback for date-only strings like "2024-01-31"
            return datetime.date.fromisoformat(s)
        except (ValueError, TypeError):
            return s

class SimpleXMLElement:
    def add_child(self, name, text=None, ns=True):
        """
        This function adds a child tag to an XML node. It takes the name of the child tag (name), an optional text content (text), and a namespace indicator (ns). Depending on the namespace information provided, it creates a new XML element with the specified name and namespace and appends it as a child to the current node. If text content is provided, it is added as either a CDATA section or a text node to the new child element. The function then returns a new SimpleXMLElement representing the added child element along with the updated XML document and namespace information.
        Input-Output Arguments
        :param self: SimpleXMLElement. An instance of the SimpleXMLElement class.
        :param name: String. The name of the child tag to be added.
        :param text: String or CDATASection. The text content of the child tag. It can be a regular string or a CDATASection object.
        :param ns: Bool or String. Whether to add a namespace to the child tag. If True, the namespace is added based on the instance's namespace. If False or the instance has no namespace, the child tag is added without a namespace. If a string is provided, it is used as the namespace for the child tag.
        :return: SimpleXMLElement. A new SimpleXMLElement instance representing the added child tag.
        """
        # Determine namespace URI to use
        namespace = None
        if isinstance(ns, str):
            namespace = ns
        elif ns and getattr(self, "namespace", None):
            namespace = self.namespace

        # Create the child element
        if namespace:
            child = self.doc.createElementNS(namespace, name)
        else:
            child = self.doc.createElement(name)

        # Append text if provided
        if text is not None:
            if hasattr(text, "nodeType") and text.nodeType == text.CDATA_SECTION_NODE:
                child.appendChild(self.doc.createCDATASection(text.data))
            else:
                child.appendChild(self.doc.createTextNode(str(text)))

        # Append child to current node
        self.node.appendChild(child)

        # Return a new SimpleXMLElement for the child
        return SimpleXMLElement(child, self.doc, namespace)

from datetime import date, datetime

def iso8601_date(d):
    """
    This function takes a date object and returns a string representation of the date in the format "YYYY-MM-DD". If the input is not a string, datetime, or date object, it returns None.
    Input-Output Arguments
    :param d: The date object to be converted to a string representation.
    :return: str or None. The string representation of the date in the format "YYYY-MM-DD", or None if the input is not a string, datetime, or date object.
    """
    if isinstance(d, datetime):
        return d.date().isoformat()
    if isinstance(d, date):
        return d.isoformat()
    if isinstance(d, str):
        try:
            return datetime.fromisoformat(d).date().isoformat()
        except ValueError:
            try:
                return date.fromisoformat(d).isoformat()
            except ValueError:
                return None
    return None

from datetime import datetime, date

def iso8601_datetime(d):
    """
    This function takes a date object and returns a string representation of the date in the format "%Y-%m-%dT%H:%M:%SZ" that is compatible with the Twilio API. If the input is not a string, datetime, or date object, it returns None.
    Input-Output Arguments
    :param d: The date object to be converted to a string representation.
    :return: String. The string representation of the date in the format "YYYY-MM-DD" or None if the input is not a valid date object.
    """
    if isinstance(d, datetime):
        return d.strftime("%Y-%m-%dT%H:%M:%SZ")
    elif isinstance(d, date):
        return datetime(d.year, d.month, d.day).strftime("%Y-%m-%dT%H:%M:%SZ")
    else:
        return None

from html import escape
from typing import Iterable

def unparse(text: str, entities: Iterable[TypeMessageEntity]) -> str:
    """
    This function takes a normal text and a list of MessageEntity objects and converts them into HTML representation.
    """
    if not text:
        return ""

    entities = list(entities or [])
    if not entities:
        return escape(text)

    # Telegram-style entities use UTF-16 offsets/lengths; Python uses Unicode code points.
    # This helper maps UTF-16 indices to Python string indices.
    def utf16_index_map(s: str):
        mapping = []
        i = 0
        for ch in s:
            mapping.append(i)
            i += 2 if ord(ch) > 0xFFFF else 1
        mapping.append(i)
        return mapping

    utf16_map = utf16_index_map(text)

    def to_py_index(utf16_pos: int) -> int:
        # Find the largest Python index whose UTF-16 offset is <= utf16_pos
        lo, hi = 0, len(utf16_map) - 1
        while lo <= hi:
            mid = (lo + hi) // 2
            if utf16_map[mid] <= utf16_pos:
                lo = mid + 1
            else:
                hi = mid - 1
        return hi

    # Sort entities by start asc, end desc so outer entities open first.
    entities = sorted(
        entities,
        key=lambda e: (getattr(e, "offset", 0), -(getattr(e, "offset", 0) + getattr(e, "length", 0)))
    )

    # Build opening/closing tags at Python indices.
    opens = {}
    closes = {}

    def add_tag(d, idx, tag, prepend=False):
        if idx not in d:
            d[idx] = []
        if prepend:
            d[idx].insert(0, tag)
        else:
            d[idx].append(tag)

    for e in entities:
        start_u16 = getattr(e, "offset", 0)
        end_u16 = start_u16 + getattr(e, "length", 0)

        start = to_py_index(start_u16)
        end = to_py_index(end_u16)

        tag_open = tag_close = None

        # Common Telegram entity types
        if e.__class__.__name__ == "MessageEntityBold":
            tag_open, tag_close = "<strong>", "</strong>"
        elif e.__class__.__name__ == "MessageEntityItalic":
            tag_open, tag_close = "<em>", "</em>"
        elif e.__class__.__name__ == "MessageEntityCode":
            tag_open, tag_close = "<code>", "</code>"
        elif e.__class__.__name__ == "MessageEntityPre":
            language = getattr(e, "language", None)
            if language:
                tag_open = f'<pre><code class="language-{escape(language)}">'
                tag_close = "</code></pre>"
            else:
                tag_open, tag_close = "<pre>", "</pre>"
        elif e.__class__.__name__ == "MessageEntityTextUrl":
            url = escape(getattr(e, "url", ""), quote=True)
            tag_open, tag_close = f'<a href="{url}">', "</a>"
        elif e.__class__.__name__ == "MessageEntityUrl":
            # Leave as plain text; URLs are already in text.
            continue
        elif e.__class__.__name__ == "MessageEntityMention":
            continue
        elif e.__class__.__name__ == "MessageEntityHashtag":
            continue
        elif e.__class__.__name__ == "MessageEntityBotCommand":
            continue
        elif e.__class__.__name__ == "MessageEntityEmail":
            continue
        elif e.__class__.__name__ == "MessageEntityPhone":
            continue
        elif e.__class__.__name__ == "MessageEntityUnderline":
            tag_open, tag_close = "<u>", "</u>"
        elif e.__class__.__name__ == "MessageEntityStrikethrough":
            tag_open, tag_close = "<s>", "</s>"
        elif e.__class__.__name__ == "MessageEntitySpoiler":
            tag_open, tag_close = '<span class="tg-spoiler">', "</span>"
        elif e.__class__.__name__ == "MessageEntityBlockquote":
            tag_open, tag_close = "<blockquote>", "</blockquote>"
        elif e.__class__.__name__ == "MessageEntityCustomEmoji":
            # No direct HTML equivalent; preserve as a span with data attributes if possible.
            custom_id = getattr(e, "custom_emoji_id", "")
            tag_open, tag_close = f'<span data-custom-emoji-id="{escape(str(custom_id), quote=True)}">', "</span>"
        else:
            # Unknown entity type: ignore formatting, keep text escaped.
            continue

        add_tag(opens, start, tag_open)
        add_tag(closes, end, tag_close, prepend=True)

    out = []
    for i, ch in enumerate(text):
        if i in opens:
            out.extend(opens[i])
        out.append(escape(ch))
        if i + 1 in closes:
            out.extend(closes[i + 1])

    # Tags at the very end
    if len(text) in opens:
        out.extend(opens[len(text)])
    if len(text) in closes:
        out.extend(closes[len(text)])

    return "".join(out)

