class MessageLinkButton:
    @classmethod
    def _parse_narrow_link(cls, link: str) -> ParsedNarrowLink:
        """
        This function parses a given link and returns a dictionary with narrow parameters for supported links. If the link does not match any of the supported formats, an empty dictionary is returned.
        We expect the fragment to be one of the following types:
        a. narrow/stream/[{stream_id}-]{stream-name}
        b. narrow/stream/[{stream_id}-]{stream-name}/near/{message_id}
        c. narrow/stream/[{stream_id}-]{stream-name}/topic/{encoded.20topic.20name}
        d. narrow/stream/[{stream_id}-]{stream-name}/topic/{encoded.20topic.20name}/near/{message_id}
        Input-Output Arguments
        :param cls: MessageLinkButton. The MessageLinkButton class.
        :param link: String. The link to be parsed.
        :return: ParsedNarrowLink. A dictionary with narrow parameters for supported links.
        """
        from urllib.parse import unquote

        parsed: ParsedNarrowLink = {}

        if not link:
            return parsed

        # Remove leading URL parts and work with the fragment/path portion.
        fragment = link.split("#", 1)[-1] if "#" in link else link
        fragment = fragment.lstrip("/")

        parts = fragment.split("/")

        # Expected prefix: narrow/stream/...
        if len(parts) < 3 or parts[0] != "narrow" or parts[1] != "stream":
            return parsed

        stream_part = parts[2]
        stream_name = stream_part
        if "-" in stream_part:
            # Zulip-style links may prefix stream id, e.g. "123-general"
            stream_name = stream_part.split("-", 1)[1]

        parsed["stream"] = stream_name

        idx = 3
        while idx < len(parts):
            if parts[idx] == "topic" and idx + 1 < len(parts):
                parsed["topic"] = unquote(parts[idx + 1].replace(".20", " "))
                idx += 2
            elif parts[idx] == "near" and idx + 1 < len(parts):
                try:
                    parsed["near"] = int(parts[idx + 1])
                except ValueError:
                    return {}
                idx += 2
            else:
                return {}
        return parsed

class MessageLinkButton:
    def _validate_narrow_link(self, parsed_link: ParsedNarrowLink) -> str:
        """
        This function validates a narrow link and returns either an empty string if the validation is successful
        or an appropriate validation error message if the validation fails. It checks various conditions related
        to the parsed link and returns the corresponding error message if any condition is not met.

        Input-Output Arguments
        :param self: MessageLinkButton. An instance of the MessageLinkButton class.
        :param parsed_link: ParsedNarrowLink. The parsed narrow link to be validated.
        :return: str. Either an empty string for successful validation or an appropriate validation error message.
        """
        if parsed_link is None:
            return "Invalid narrow link."

        # Validate stream/topic requirements
        if getattr(parsed_link, "operator", None) == "stream":
            if not getattr(parsed_link, "operand", None):
                return "Invalid narrow link: stream name is missing."
        elif getattr(parsed_link, "operator", None) == "topic":
            if not getattr(parsed_link, "operand", None):
                return "Invalid narrow link: topic name is missing."
        elif getattr(parsed_link, "operator", None) == "sender":
            if not getattr(parsed_link, "operand", None):
                return "Invalid narrow link: sender name is missing."
        elif getattr(parsed_link, "operator", None) == "search":
            if not getattr(parsed_link, "operand", None):
                return "Invalid narrow link: search term is missing."
        else:
            return "Invalid narrow link: unsupported operator."

        # Validate negation / conjunction flags if present
        if hasattr(parsed_link, "negated") and not isinstance(parsed_link.negated, bool):
            return "Invalid narrow link: negation flag must be boolean."

        if hasattr(parsed_link, "and_operator") and not isinstance(parsed_link.and_operator, bool):
            return "Invalid narrow link: conjunction flag must be boolean."

        return ""

