def parse_themefile(
    theme_styles: Dict[Optional[str], Tuple[Any, Any]], color_depth: int
) -> "ThemeSpec":
    """
    This function takes a dictionary of theme styles and a color depth including 1, 16, 256 and 2^24 as input and returns a list of theme specifications in the urwid format. It iterates over the theme styles dictionary and converts the color codes and properties based on the specified color depth. The converted theme specifications are then added to the list.
    Input-Output Arguments
    :param theme_styles: Dict[Optional[str], Tuple[Any, Any]]. A dictionary containing the theme styles where the keys are style names and the values are tuples of foreground and background colors.
    :param color_depth: int. The color depth to be used for converting the color codes. It can be 1, 16, 256, or 2^24.
    :return: ThemeSpec. A list of theme specifications in the urwid format.
    """
    theme_spec = []

    def _convert_color(color: Any) -> Any:
        if color is None:
            return None

        # Keep already-structured values as-is
        if isinstance(color, (tuple, list)):
            return tuple(color)

        # Normalize strings
        if isinstance(color, str):
            c = color.strip()

            # Common urwid-style attributes / special values
            if c in {"default", "black", "dark red", "dark green", "brown", "dark blue",
                     "dark magenta", "dark cyan", "light gray", "dark gray", "light red",
                     "light green", "yellow", "light blue", "light magenta", "light cyan",
                     "white", "bold", "underline", "standout", "blink", "italics", "strikethrough"}:
                return c

            # Hex colors for truecolor
            if color_depth == 16777216 and c.startswith("#"):
                return c

            # For lower depths, leave named colors unchanged
            return c

        return color

    for style_name, style_value in theme_styles.items():
        if style_name is None:
            continue

        if isinstance(style_value, tuple) and len(style_value) == 2:
            fg, bg = style_value
            theme_spec.append((style_name, _convert_color(fg), _convert_color(bg)))
        else:
            # Fallback: preserve whatever was provided
            theme_spec.append((style_name, style_value))

    return theme_spec

