def check_value(value):
    if isinstance(value, str):
        # Split on common separators used in color specs
        parts = re.split(r"[\s,/]+", value.strip())
        # Rebuild known multi-word colors like "dark red"
        i = 0
        while i < len(parts):
            if i + 1 < len(parts):
                two_word = normalize_color(f"{parts[i]} {parts[i+1]}")
