            single = normalize_color(parts[i])
            if single and single not in valid_colors:
                invalid_colors.append(single)
            i += 1
    elif isinstance(value, (list, tuple, set)):
        for item in value:
            check_value(item)
    elif isinstance(value, dict):
        for item in value.values():
