import sqlparse
from collections import namedtuple
from sqlparse.sql import Identifier, IdentifierList, Parenthesis, TokenList
from sqlparse.tokens import Keyword, DML, Whitespace, Punctuation

TableReference = namedtuple("TableReference", ["schema", "table"])

def _is_subselect(parsed):
    if not parsed.is_group:
        return False
    for item in parsed.tokens:
        if item.ttype is DML and item.value.upper() == "SELECT":
            return True
    return False

def _extract_from_token(token):
    tables = []

    if isinstance(token, IdentifierList):
        for identifier in token.get_identifiers():
            tables.extend(_extract_from_token(identifier))
    elif isinstance(token, Identifier):
        # Handle schema.table or just table
        names = [n for n in token.value.split(".") if n and n != '"']
        if len(names) >= 2:
            schema = names[-2].strip('"`[]')
            table = names[-1].strip('"`[]')
            tables.append(TableReference(schema=schema, table=table))
        else:
            tables.append(TableReference(schema=None, table=token.get_real_name().strip('"`[]') if token.get_real_name() else token.value.strip('"`[]')))
    elif isinstance(token, Parenthesis):
        # Possible subquery
        if _is_subselect(token):
            tables.extend(_extract_tables_from_statement(token))
    elif isinstance(token, TokenList):
        tables.extend(_extract_tables_from_statement(token))

    return tables

def _extract_tables_from_statement(statement):
    tables = []
    from_seen = False
    join_seen = False

    for token in statement.tokens:
        if token.is_whitespace or token.ttype is Whitespace or token.ttype is Punctuation:
            continue

        if token.ttype is Keyword:
            val = token.value.upper()
            if val in ("FROM", "JOIN", "INNER JOIN", "LEFT JOIN", "RIGHT JOIN", "FULL JOIN", "CROSS JOIN", "OUTER JOIN"):
                from_seen = True
                join_seen = True
                continue
            elif val in ("WHERE", "GROUP", "ORDER", "HAVING", "LIMIT", "UNION", "EXCEPT", "INTERSECT"):
                from_seen = False
                join_seen = False
                continue

        if from_seen or join_seen:
            tables.extend(_extract_from_token(token))
            from_seen = False
            join_seen = False

    return tables

parsed = sqlparse.parse(sql)
all_tables = []
for statement in parsed:
    all_tables.extend(_extract_tables_from_statement(statement))

# Deduplicate while preserving order
seen = set()
result = []
for t in all_tables:
    key = (t.schema, t.table)
    if key not in seen:
        seen.add(key)
        result.append(t)

return tuple(result)

class BaseModel:
    def _build_query(self, params):
        """
        This function builds a query string by encoding the given query parameters into an HTTP URI query string. It first checks if there is an alternate parameter and adds it to the parameters dictionary. Then, it iterates through the key-value pairs in the parameters dictionary. If the value is a list, it iterates through the elements of the list, encodes them into UTF-8, and adds them to the list of tuples. If the value is a string and callable, it encodes it into UTF-8 and adds it to the list of tuples. Finally, it returns the query string with the encoded parameters.
        Input-Output Arguments
        :param self: BaseModel. An instance of the BaseModel class.
        :param params: dict. The query parameters as a dictionary.
        :return: str. The query parameters properly encoded into an HTTP URI query string.
        """
        from urllib.parse import urlencode

        if params is None:
            return ""

        # Support alternate parameter naming if present on the instance
        alt_param = getattr(self, "alternate_parameter", None)
        if alt_param is not None and alt_param not in params:
            params = dict(params)
            params[alt_param] = getattr(self, alt_param, None)

        query_items = []

        for key, value in params.items():
            if value is None:
                continue

            if isinstance(value, list):
                for item in value:
                    if item is None:
                        continue
                    if isinstance(item, str):
                        item = item.encode("utf-8")
                    query_items.append((key, item))
            else:
                if isinstance(value, str):
                    value = value.encode("utf-8")
                query_items.append((key, value))

        return urlencode(query_items)

class BaseModel:
    def response(self, resp, content):

        """
        This function is a method of the BaseModel class. It is used to convert the response from a HTTP request into a Python object. It also handles error cases and raises an http error if a non 2xx response is received.
        Input-Output Arguments
        :param self: BaseModel. An instance of the BaseModel class.
        :param resp: httplib2.Response. The HTTP response headers and status.
        :param content: string. The body of the HTTP response.
        :return: The body de-serialized as a Python object.
        """
        import json

        # Normalize content to text if needed
        if isinstance(content, bytes):
            content = content.decode("utf-8")

        status = int(getattr(resp, "status", 0))

        # Raise an error for non-2xx responses
        if status < 200 or status >= 300:
            raise Exception(f"HTTP Error {status}: {content}")

        # Empty response body
        if not content:
            return None

        # Try to deserialize JSON, otherwise return raw content
        try:
            return json.loads(content)
        except Exception:
            return content

