CHARSET = "qpzry9x8gf2tvdw0s3jn54khce6mua7l"

def bech32_polymod(values):
    generator = [0x3b6a57b2, 0x26508e6d, 0x1ea119fa, 0x3d4233dd, 0x2a1462b3]
    chk = 1
    for v in values:
        b = chk >> 25
        chk = (chk & 0x1ffffff) << 5 ^ v
        for i in range(5):
            chk ^= generator[i] if ((b >> i) & 1) else 0
    return chk

def bech32_hrp_expand(hrp):
    return [ord(x) >> 5 for x in hrp] + [0] + [ord(x) & 31 for x in hrp]

def verify_checksum(hrp, data):
    return bech32_polymod(bech32_hrp_expand(hrp) + data) == 1

def convertbits(data, frombits, tobits, pad=True):
    acc = 0
    bits = 0
    ret = []
    maxv = (1 << tobits) - 1
    for value in data:
        if value < 0 or (value >> frombits):
            return None
        acc = (acc << frombits) | value
        bits += frombits
        while bits >= tobits:
            bits -= tobits
            ret.append((acc >> bits) & maxv)
    if pad:
        if bits:
            ret.append((acc << (tobits - bits)) & maxv)
    elif bits >= frombits or ((acc << (tobits - bits)) & maxv):
        return None
    return ret

# Basic validation
if not isinstance(hrp, str) or not isinstance(addr, str):
    return (None, None)

# Bech32 addresses are case-insensitive but must not mix cases
if addr.lower() != addr and addr.upper() != addr:
    return (None, None)

addr = addr.lower()

# Must have separator
pos = addr.rfind('1')
if pos < 1 or pos + 7 > len(addr):  # need hrp + separator + 6-char checksum minimum
    return (None, None)

if hrp.lower() != addr[:pos]:
    return (None, None)

# Decode data part
data_part = addr[pos + 1:]
try:
    data = [CHARSET.index(c) for c in data_part]
except ValueError:
    return (None, None)

if not verify_checksum(hrp.lower(), data):
    return (None, None)

# Remove checksum
data = data[:-6]
if len(data) == 0:
    return (None, None)

version = data[0]
if version > 16:
    return (None, None)

decoded = convertbits(data[1:], 5, 8, False)
if decoded is None:
    return (None, None)

# Segwit v0 must be 20 or 32 bytes; other versions must be 2..40 bytes
if version == 0 and len(decoded) not in (20, 32):
    return (None, None)
if version != 0 and not (2 <= len(decoded) <= 40):
    return (None, None)

return (version, decoded)

