    if not os.path.isfile(arg):
        return False
    try:
        with open(arg, "rb") as f:
            data = f.read(len(magic))
    except OSError:
        return False

# If arg is a string and should be treated as data
elif isinstance(arg, str):
    data = arg.encode("utf-8", errors="ignore")[:len(magic)]

# If arg is bytes/bytearray
elif isinstance(arg, (bytes, bytearray)):
    data = bytes(arg)[:len(magic)]

# If arg is a file-like object
elif hasattr(arg, "read"):
    try:
        pos = None
        try:
            pos = arg.tell()
        except Exception:
            pos = None

        data = arg.read(len(magic))

        # Restore stream position if possible
        if pos is not None:
            try:
                arg.seek(pos)
            except Exception:
                pass
    except Exception:
        return False

# Unsupported input type
else:
    return False

return data.startswith(magic)

