class UnitRefBuilder:
    def _build_modifiers_repr(self):
        """
        This function builds the representation of modifiers. It first build the representation of modifiers, then it sets the argument value and variation name for the modifiers, and finally returns the modified modifiers.
        Input-Output Arguments
        :param self: UnitRefBuilder. An instance of the UnitRefBuilder class.
        :return: The modified modifiers.
        """
        modifiers = getattr(self, "modifiers", None)
        if not modifiers:
            return modifiers

        built_modifiers = []
        for modifier in modifiers:
            # Support both dict-like and object-like modifiers
            if isinstance(modifier, dict):
                mod = dict(modifier)
                if "argument_value" not in mod and "value" in mod:
                    mod["argument_value"] = mod["value"]
                if "variation_name" not in mod and "variation" in mod:
                    mod["variation_name"] = mod["variation"]
                built_modifiers.append(mod)
            else:
                if hasattr(modifier, "value") and not hasattr(modifier, "argument_value"):
                    setattr(modifier, "argument_value", getattr(modifier, "value"))
                if hasattr(modifier, "variation") and not hasattr(modifier, "variation_name"):
                    setattr(modifier, "variation_name", getattr(modifier, "variation"))
                built_modifiers.append(modifier)

        self.modifiers = built_modifiers
        return built_modifiers

class UnitDefBuilder:
    def _build_modifiers_repr(self):
        """
        This function builds the representation of modifiers for a UnitDefBuilder instance. It first gets the modifiers, then sets the argument name of the modifiers to the arg name of the UnitDefBuilder instance. Finally, it returns the modifiers.
        Input-Output Arguments
        :param self: UnitDefBuilder. An instance of the UnitDefBuilder class.
        :return: The representation of modifiers for the UnitDefBuilder instance.
        """
        modifiers = self.modifiers
        if modifiers is None:
            return None

        # If modifiers is a single modifier, normalize to a list for processing.
        if not isinstance(modifiers, (list, tuple)):
            modifiers = [modifiers]

        for modifier in modifiers:
            if hasattr(modifier, "arg_name"):
                modifier.arg_name = self.arg_name

        return modifiers

class UnitRefBuilder:
    def create_concrete(self):
        """
        Create a concrete UnitReference object based on the information stored in the UnitRefBuilder instance. It first checks if all the necessary information is available, and then uses that information to create the UnitReference object.
        Input-Output Arguments
        :param self: UnitRefBuilder. An instance of the UnitRefBuilder class.
        :return: UnitReference. The created UnitReference object.
        """
        # Ensure required information is present
        if not hasattr(self, "unit_ref") or self.unit_ref is None:
            raise ValueError("Cannot create UnitReference: 'unit_ref' is missing.")

        # If the stored reference is already concrete, return it directly
        if isinstance(self.unit_ref, UnitReference):
            return self.unit_ref

        # Otherwise, try to construct a concrete UnitReference from stored fields
        # Commonly expected fields: name, namespace, version, etc.
        kwargs = {}

        for attr in ("name", "namespace", "version", "path", "id"):
            if hasattr(self, attr):
                value = getattr(self, attr)
                if value is not None:
                    kwargs[attr] = value

        try:
            return UnitReference(**kwargs)
        except TypeError as e:
            raise ValueError(
                "Cannot create UnitReference: insufficient or incompatible builder data."
            ) from e

class UnhideCommand:
    def execute(self):
        """
        This function implements the command `unhide` which restores a unit definition that was hidden from the AST. It takes input arguments and performs certain actions based on the input. Initially, the function checks if the number of command tokens is less than three. It determines the unit type from the second command token and validate the type of unit. It tries to interpret the third command token as a regular expression and execute the restoration process on the unit with different regular expression conditions.
        Input-Output Arguments
        :param self: UnhideCommand. An instance of the UnhideCommand class.
        :return: No return values.
        """
        import re

        # Expect: unhide <unit_type> <pattern>
        if not hasattr(self, "tokens") or len(self.tokens) < 3:
            raise ValueError("Usage: unhide <unit_type> <pattern>")

        unit_type = self.tokens[1].lower()
        pattern = self.tokens[2]

        valid_types = {"function", "class", "variable", "module", "unit"}
        if unit_type not in valid_types:
            raise ValueError(f"Invalid unit type: {unit_type}")

        # Determine the hidden units collection
        hidden_units = getattr(self, "hidden_units", None)
        if hidden_units is None:
            raise AttributeError("Missing hidden_units storage")

        # Try to compile the pattern as regex; if invalid, treat it as a literal string
        try:
            regex = re.compile(pattern)
            is_regex = True
        except re.error:
            regex = None
            is_regex = False

        restored = []
        remaining = []

        for unit in hidden_units:
            # Support dict-like or object-like hidden unit entries
            utype = unit.get("type") if isinstance(unit, dict) else getattr(unit, "type", None)
            uname = unit.get("name") if isinstance(unit, dict) else getattr(unit, "name", None)

            match_type = (unit_type == "unit") or (utype == unit_type)
            if not match_type:
                remaining.append(unit)
                continue

            if is_regex:
                matched = bool(regex.search(uname or ""))
            else:
                matched = (uname == pattern)

            if matched:
                restored.append(unit)
            else:
                remaining.append(unit)

        # Update hidden storage
        self.hidden_units = remaining

        # Restore into AST if available
        ast = getattr(self, "ast", None)
        if ast is not None:
            for unit in restored:
                if isinstance(unit, dict):
                    node = unit.get("node", unit)
                else:
                    node = getattr(unit, "node", unit)

                # Try common AST container APIs
                if hasattr(ast, "append"):
                    ast.append(node)
                elif hasattr(ast, "add"):
                    ast.add(node)
                elif hasattr(ast, "insert"):
                    ast.insert(node)

        # Optional feedback
        if hasattr(self, "output"):
            self.output.write(f"Restored {len(restored)} hidden unit(s)\n")

class SlotDefBuilder:
    def create_concrete(self):
        """
        This function creates a concrete SlotDefinition object based on the given conditions. It first checks if the necessary information is provided. If a variation is specified, it retrieves the definitions from the AST and checks if the identifier exists. If it does, it returns the corresponding SlotDefinition object. Otherwise, it creates a new SlotDefinition object with the identifier and the modifiers representation.
        Input-Output Arguments
        :param self: SlotDefBuilder. An instance of the SlotDefBuilder class.
        :return: SlotDefinition. The created SlotDefinition object.
        """
        # Ensure required information is present
        if not hasattr(self, "identifier") or self.identifier is None:
            raise ValueError("SlotDefBuilder requires an identifier to create a concrete SlotDefinition.")

        # If a variation is specified, try to resolve it from the AST definitions
        variation = getattr(self, "variation", None)
        if variation is not None:
            ast = getattr(self, "ast", None)
            if ast is not None and hasattr(ast, "definitions"):
                definitions = ast.definitions
                if isinstance(definitions, dict) and variation in definitions:
                    return definitions[variation]
                if isinstance(definitions, (list, tuple)):
                    for definition in definitions:
                        if getattr(definition, "identifier", None) == variation:
                            return definition

        # Build modifiers representation if available
        modifiers = getattr(self, "modifiers", None)
        modifiers_repr = None
        if modifiers is not None:
            if hasattr(modifiers, "representation"):
                modifiers_repr = modifiers.representation
            else:
                modifiers_repr = str(modifiers)

        # Create and return a new SlotDefinition object
        return SlotDefinition(self.identifier, modifiers_repr)

class AliasDefBuilder:
    def create_concrete(self):
        """
        This function creates a concrete alias definition based on the given conditions. It first checks if the variation is not None and if the identifier exists in the definitions. If so, it returns the corresponding definition. Otherwise, it creates a new AliasDefinition instance with the identifier and the modifiers representation.
        Input-Output Arguments
        :param self: AliasDefBuilder. An instance of the AliasDefBuilder class.
        :return: AliasDefinition. The created AliasDefinition instance.
        """
        # If a variation is provided and the identifier already exists, return the existing definition.
        if getattr(self, "variation", None) is not None:
            definitions = getattr(self, "definitions", None)
            identifier = getattr(self, "identifier", None)
            if definitions is not None and identifier in definitions:
                return definitions[identifier]

        # Otherwise, create a new AliasDefinition using the identifier and modifiers representation.
        identifier = getattr(self, "identifier", None)
        modifiers = getattr(self, "modifiers", None)

        # Try to obtain a string representation of modifiers if available.
        if modifiers is not None and hasattr(modifiers, "representation"):
            modifiers_repr = modifiers.representation
        else:
            modifiers_repr = modifiers

        return AliasDefinition(identifier, modifiers_repr)

class IntentDefBuilder:
    def create_concrete(self):
        """
        This function creates a concrete instance of an IntentDefinition based on the given conditions. It first checks if all the necessary information is provided. If a variation is specified, it retrieves the definitions from the AST and checks if the identifier is already present. If it is, it returns the corresponding definition. Otherwise, it creates a new IntentDefinition instance with the provided identifier, modifiers representation, number of training examples, and number of testing examples.
        Input-Output Arguments
        :param self: IntentDefBuilder. An instance of the IntentDefBuilder class.
        :return: IntentDefinition. The created concrete instance of IntentDefinition.
        """
        # Ensure required fields are present
        if not hasattr(self, "identifier") or self.identifier is None:
            raise ValueError("Intent identifier is required.")
        if not hasattr(self, "modifiers_repr") or self.modifiers_repr is None:
            raise ValueError("Modifiers representation is required.")
        if not hasattr(self, "num_training_examples") or self.num_training_examples is None:
            raise ValueError("Number of training examples is required.")
        if not hasattr(self, "num_testing_examples") or self.num_testing_examples is None:
            raise ValueError("Number of testing examples is required.")

        # If a variation is specified, try to reuse an existing definition from the AST
        variation = getattr(self, "variation", None)
        ast = getattr(self, "ast", None)

        if variation is not None and ast is not None:
            definitions = getattr(ast, "definitions", None)
            if definitions is not None:
                for definition in definitions:
                    if getattr(definition, "identifier", None) == self.identifier:
                        return definition

        # Create a new concrete IntentDefinition
        return IntentDefinition(
            identifier=self.identifier,
            modifiers_repr=self.modifiers_repr,
            num_training_examples=self.num_training_examples,
            num_testing_examples=self.num_testing_examples,
        )

