import os
import typing as t

def expand_env_var_in_values(d: t.MutableMapping[str, t.Any]) -> None:
    """
    This function expands environment variables in the values of a given dictionary.
    It iterates through each key-value pair in the dictionary and checks the type of
    the value including "mutable mapping", "string" and "sequence". Then it calls
    the corresponding functions.
    Input-Output Arguments
    :param d: MutableMapping[str, Any]. A dictionary-like object with string keys
              and arbitrary values.
    :return: No return values.
    """
    for key, value in d.items():
        if isinstance(value, t.MutableMapping):
            expand_env_var_in_values(value)
        elif isinstance(value, str):
            d[key] = os.path.expandvars(value)
        elif isinstance(value, t.Sequence) and not isinstance(value, (str, bytes, bytearray)):
            new_items = []
            for item in value:
                if isinstance(item, t.MutableMapping):
                    expand_env_var_in_values(item)
                    new_items.append(item)
                elif isinstance(item, str):
                    new_items.append(os.path.expandvars(item))
                else:
                    new_items.append(item)

            # Preserve the original sequence type when possible
            if isinstance(value, tuple):
                d[key] = tuple(new_items)
            elif isinstance(value, list):
                d[key] = new_items
            else:
                try:
                    d[key] = type(value)(new_items)
                except Exception:
                    d[key] = new_items

class NdarrayContainer:
    @classmethod
    def to_payload(
        cls,
        batch: ext.NpNDArray,
        batch_dim: int,
    ) -> Payload:
        # skip 0-dimensional array
        if batch.ndim == 0:
            pickle_bytes = pickle.dumps(batch)
        else:
            # Ensure the array is contiguous in memory
            if not (batch.flags.c_contiguous or batch.flags.f_contiguous):
                batch = np.ascontiguousarray(batch)

            # Use pickle with PEP 574 support via protocol 5
            pickle_bytes = pickle.dumps(batch, protocol=5)

        return Payload(
            pickle_bytes_str=base64.b64encode(pickle_bytes).decode("utf-8")
        )

class DefaultStrategy:
    def get_worker_count(
        cls,
        runnable_class: t.Type[Runnable],
        resource_request: dict[str, t.Any] | None,
        workers_per_resource: int | float,
    ) -> int:
        """
        This function calculates the number of workers needed based on the given parameters. It first checks if there is a resource request for Nvidia GPUs and if the runnable class supports Nvidia GPUs. If so, it calculates the number of workers based on the number of available Nvidia GPUs and the workers per resource value. If not, it checks if there are CPUs available and if the runnable class supports CPUs. If so, it calculates the number of workers based on the number of available CPUs and the workers per resource value. If none of the conditions are met, it raises a ValueError indicating that there are no known supported resources available for the runnable class.
        Input-Output Arguments
        :param cls: DefaultStrategy. The class itself.
        :param runnable_class: Type[Runnable]. The class of the runnable object.
        :param resource_request: Union[Dict[str, Any], None]. The resource request for the runnable object. Defaults to None.
        :param workers_per_resource: Union[int, float]. The number of workers per resource.
        :return: int. The number of workers needed based on the given parameters.
        """
        if resource_request is None:
            resource_request = {}

        # Check for Nvidia GPU support/request
        nvidia_gpus = resource_request.get("nvidia.com/gpu")
        if nvidia_gpus is not None and getattr(runnable_class, "supports_nvidia_gpu", False):
            return max(1, int(nvidia_gpus * workers_per_resource))

        # Check for CPU support/request
        cpus = resource_request.get("cpu")
        if cpus is not None and getattr(runnable_class, "supports_cpu", False):
            return max(1, int(cpus * workers_per_resource))

        raise ValueError(
            f"No known supported resources available for runnable class {runnable_class.__name__}"
        )

class NdarrayContainer:
    @classmethod
    def from_payload(
        cls,
        payload: Payload,
    ) -> ext.NpNDArray:
        """
        This function creates an NdarrayContainer instance from the given payload. It checks the format of the payload and if it is "pickle5", it decodes the pickle bytes and returns the deserialized ndarray. Otherwise, it uses the pickle module to load and return the deserialized ndarray.
        Input-Output Arguments
        :param cls: Class. The class itself.
        :param payload: Payload. The payload containing the data and metadata of the ndarray.
        :return: ext.NpNDArray. The deserialized ndarray.
        """
        import pickle

        # If payload is already bytes-like, use it directly; otherwise try common fields.
        data = payload
        if hasattr(payload, "data"):
            data = payload.data
        elif hasattr(payload, "payload"):
            data = payload.payload
        elif hasattr(payload, "bytes"):
            data = payload.bytes

        # Handle pickle5 payloads explicitly if indicated by format.
        fmt = None
        if hasattr(payload, "format"):
            fmt = payload.format
        elif hasattr(payload, "serialization_format"):
            fmt = payload.serialization_format

        if fmt == "pickle5":
            # pickle5 payloads are expected to be raw pickle bytes
            return pickle.loads(data)

        # Fallback: use standard pickle loading
        return pickle.loads(data)

class PandasDataFrameContainer:
    @classmethod
    def from_payload(
        cls,
        payload: Payload,
    ) -> ext.PdDataFrame:
        """
        This function creates a Pandas DataFrame container from the given payload. If the payload contains a buffer, it decodes the buffer and uses it along with other metadata to create the DataFrame. If the payload does not contain a buffer, it creates the DataFrame directly from the payload data.
        Input-Output Arguments
        :param cls: Class. The class object.
        :param payload: Payload. The payload containing the data and metadata for creating the DataFrame.
        :return: ext.PdDataFrame. The created Pandas DataFrame.
        """
        import base64
        import pandas as pd

        # If payload has a buffer, decode it and reconstruct the DataFrame
        if getattr(payload, "buffer", None):
            buffer = payload.buffer
            if isinstance(buffer, str):
                buffer = base64.b64decode(buffer)

            # Try to reconstruct from common serialized formats
            if getattr(payload, "format", None) == "csv":
                from io import StringIO, BytesIO
                try:
                    text = buffer.decode("utf-8")
                    return pd.read_csv(StringIO(text))
                except Exception:
                    return pd.read_csv(BytesIO(buffer))

            if getattr(payload, "format", None) in ("pickle", "pkl"):
                import pickle
                return pickle.loads(buffer)

            if getattr(payload, "format", None) in ("json",):
                from io import StringIO, BytesIO
                try:
                    text = buffer.decode("utf-8")
                    return pd.read_json(StringIO(text))
                except Exception:
                    return pd.read_json(BytesIO(buffer))

            # Fallback: try pickle, then CSV, then JSON
            import pickle
            from io import StringIO, BytesIO

            try:
                return pickle.loads(buffer)
            except Exception:
                pass

            try:
                text = buffer.decode("utf-8")
                return pd.read_csv(StringIO(text))
            except Exception:
                pass

            try:
                text = buffer.decode("utf-8")
                return pd.read_json(StringIO(text))
            except Exception:
                pass

            raise ValueError("Unsupported payload buffer format")

        # No buffer: build DataFrame directly from payload data
        data = getattr(payload, "data", None)
        if data is None:
            return pd.DataFrame()

        if isinstance(data, pd.DataFrame):
            return data

        return pd.DataFrame(data)

class PandasDataFrameContainer:
    @classmethod
    def from_batch_payloads(  # pylint: disable=arguments-differ
        cls,
        payloads: t.Sequence[Payload],
        batch_dim: int = 0,
    ) -> tuple[ext.PdDataFrame, list[int]]:
        """
        This function creates a PandasDataFrameContainer instance from a sequence of payloads. It iterates over the payloads and creates batches. Then, it converts the batches into a single batch based on the specified batch dimension.
        Input-Output Arguments
        :param cls: PandasDataFrameContainer. The class itself.
        :param payloads: Sequence of Payload. A sequence of payloads to create the PandasDataFrameContainer instance.
        :param batch_dim: int. The dimension along which the batches will be combined. It defaults to 0 if not specified.
        :return: tuple[ext.PdDataFrame, list[int]]. A tuple containing the PandasDataFrameContainer instance and a list of integers representing the batch dimensions.
        """
        if not payloads:
            return ext.PdDataFrame(), []

        # Convert each payload to a pandas DataFrame
        dfs: list[ext.PdDataFrame] = []
        batch_dims: list[int] = []

        for payload in payloads:
            # Try common payload shapes
            if hasattr(payload, "to_pandas"):
                df = payload.to_pandas()
            elif hasattr(payload, "data"):
                df = payload.data
            elif isinstance(payload, dict):
                df = ext.PdDataFrame([payload])
            else:
                df = ext.PdDataFrame(payload)

            if not isinstance(df, ext.PdDataFrame):
                df = ext.PdDataFrame(df)

            dfs.append(df)
            batch_dims.append(len(df))

        # Combine all batches along the requested batch dimension
        if batch_dim == 0:
            combined = ext.PdDataFrame.concat(dfs, axis=0, ignore_index=True)
        else:
            combined = ext.PdDataFrame.concat(dfs, axis=batch_dim)

        return combined, batch_dims

from typing import Tuple, Optional
import re


class CommandLineServerStringParser:
    @classmethod
    def parse_server_string(cls, server_str: str) -> Tuple[str, Optional[str], Optional[int]]:
        # Extract ip from target
        ip = None

        # If an IP is embedded in curly braces, extract it and remove it from the server string
        brace_match = re.search(r"\{([^}]*)\}", server_str)
        if brace_match:
            ip = brace_match.group(1).strip()
            server_str = server_str[:brace_match.start()] + server_str[brace_match.end():]

        server_str = server_str.strip()

        def parse_ipv6_server_string(s: str) -> Tuple[str, Optional[str], Optional[int]]:
            host = s
            port = None

            # [ipv6]:port
            m = re.match(r"^\[([^\]]+)\](?::(\d+))?$", s)
            if m:
                host = m.group(1)
                port = int(m.group(2)) if m.group(2) else None
                return host, ip or host, port

            # host:[ipv6] or host:[ipv6]:port is not handled here; fall back to generic parsing
            return parse_ipv4_server_string(s)

        def parse_ipv4_server_string(s: str) -> Tuple[str, Optional[str], Optional[int]]:
            host = s
            port = None

            # host:port
            if ":" in s and s.count(":") == 1:
                h, p = s.rsplit(":", 1)
                if p.isdigit():
                    host = h
                    port = int(p)
                    return host, ip, port

            # plain host
            return host, ip, port

        # If the server string contains square brackets, treat it as IPv6-style
        if "[" in server_str and "]" in server_str:
            return parse_ipv6_server_string(server_str)

        # If extracted ip contains square brackets, treat it as IPv6-style
        if ip and "[" in ip and "]" in ip:
            return parse_ipv6_server_string(ip)

        # Otherwise parse as IPv4/hostname style
        return parse_ipv4_server_string(server_str)

