class _SessionRenegotiationCliConnector:
    def result_to_console_output(cls, result: SessionRenegotiationScanResult) -> List[str]:
        """
        This function takes a SessionRenegotiationScanResult object as input and converts the result into a list of strings that represent the output to be displayed on the console. It formats the different fields of the result and appends them to the result_txt list.
        Input-Output Arguments
        :param cls: The class object of _SessionRenegotiationCliConnector.
        :param result: SessionRenegotiationScanResult. The result of a session renegotiation scan.
        :return: List of strings. The formatted output to be displayed on the console.
        """
        result_txt = []

        # Basic status / summary
        if hasattr(result, "is_vulnerable"):
            result_txt.append(f"Vulnerable: {'yes' if result.is_vulnerable else 'no'}")

        if hasattr(result, "severity"):
            result_txt.append(f"Severity: {result.severity}")

        if hasattr(result, "score"):
            result_txt.append(f"Score: {result.score}")

        # Details about the scan target
        if hasattr(result, "host"):
            result_txt.append(f"Host: {result.host}")

        if hasattr(result, "port"):
            result_txt.append(f"Port: {result.port}")

        if hasattr(result, "protocol"):
            result_txt.append(f"Protocol: {result.protocol}")

        # Findings / evidence
        if hasattr(result, "details") and result.details:
            result_txt.append("Details:")
            if isinstance(result.details, (list, tuple)):
                for item in result.details:
                    result_txt.append(f"  - {item}")
            else:
                result_txt.append(f"  - {result.details}")

        if hasattr(result, "recommendation") and result.recommendation:
            result_txt.append(f"Recommendation: {result.recommendation}")

        return result_txt

